fn find_first_file_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    pattern_ptr: u32,
    find_data_ptr: u32,
) -> u32 {
    let Some(pattern) = read_guest_wide_arg(memory, pattern_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return u32::MAX;
    };
    tracing::debug!(
        target: "ce.file",
        pattern = %pattern,
        find_data_ptr = format_args!("0x{find_data_ptr:08x}"),
        "FindFirstFileW"
    );
    let (handle, find_data) = match kernel.find_first_file_w(&pattern) {
        Ok(result) => {
            tracing::debug!(
                target: "ce.file",
                pattern = %pattern,
                handle = format_args!("0x{:08x}", result.0),
                file_name = %result.1.file_name,
                attributes = format_args!("0x{:08x}", result.1.attributes),
                "FindFirstFileW matched"
            );
            result
        }
        Err(_) => {
            tracing::debug!(
                target: "ce.file",
                pattern = %pattern,
                "FindFirstFileW failed"
            );
            kernel
                .threads
                .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
            return u32::MAX;
        }
    };
    if find_data_ptr == 0
        || !write_win32_find_data_w(kernel, memory, thread_id, find_data_ptr, &find_data)
    {
        let _ = kernel.find_close(handle);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return u32::MAX;
    }
    kernel.threads.set_last_error(thread_id, 0);
    handle
}

fn find_first_change_notification_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    path_ptr: u32,
    recursive: u32,
    notify_filter: u32,
) -> u32 {
    let Some(path) = read_guest_wide_arg(memory, path_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return u32::MAX;
    };
    let Ok(data) = kernel.file_attributes_w(&path) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_PATH_NOT_FOUND);
        return u32::MAX;
    };
    if data.attributes & FILE_ATTRIBUTE_DIRECTORY == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_PATH_NOT_FOUND);
        return u32::MAX;
    }
    match kernel.find_first_change_notification_w(&path, recursive != 0, notify_filter) {
        Ok(handle) => {
            kernel.threads.set_last_error(thread_id, 0);
            handle
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            u32::MAX
        }
    }
}

fn find_next_change_notification_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> bool {
    match kernel.find_next_change_notification(handle) {
        Ok(ok) => {
            kernel.threads.set_last_error(thread_id, 0);
            ok
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn find_close_change_notification_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> bool {
    match kernel.find_close_change_notification(handle) {
        Ok(ok) => {
            kernel.threads.set_last_error(thread_id, 0);
            ok
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn ce_get_file_notification_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let buffer = raw_arg(args, 2);
    let buffer_len = raw_arg(args, 3) as usize;
    let returned_ptr = raw_arg(args, 4);
    let available_ptr = raw_arg(args, 5);
    let records = match kernel.file_change_notification_records(handle) {
        Ok(records) => records,
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return false;
        }
    };
    let required = encoded_file_notification_len(&records) as u32;
    if records.is_empty() {
        let wrote_counts = write_optional_count(kernel, memory, thread_id, returned_ptr, 0)
            && write_optional_count(kernel, memory, thread_id, available_ptr, 0);
        if !wrote_counts {
            return false;
        }
        let _ = kernel.clear_file_change_notification(handle);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NO_MORE_ITEMS);
        return false;
    }

    let (fit_count, returned) = file_notification_prefix_fit(&records, buffer, buffer_len);
    if fit_count == 0 {
        let _ = write_optional_count(kernel, memory, thread_id, returned_ptr, 0);
        if !write_optional_count(kernel, memory, thread_id, available_ptr, required) {
            return false;
        }
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INSUFFICIENT_BUFFER);
        return false;
    }
    let encoded = encode_file_notification_records(&records[..fit_count]);
    let available = encoded_file_notification_len(&records[fit_count..]) as u32;
    if !write_guest_bytes(kernel, memory, thread_id, buffer, &encoded)
        || !write_optional_count(kernel, memory, thread_id, returned_ptr, returned as u32)
        || !write_optional_count(kernel, memory, thread_id, available_ptr, available)
    {
        return false;
    }
    match kernel.drain_file_change_notification_records(handle, fit_count) {
        Ok(_) => {
            let error = if available == 0 { 0 } else { ERROR_MORE_DATA };
            kernel.threads.set_last_error(thread_id, error);
            true
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn file_notification_prefix_fit(
    records: &[crate::ce::object::FileChangeRecord],
    buffer: u32,
    buffer_len: usize,
) -> (usize, usize) {
    if buffer == 0 {
        return (0, 0);
    }
    let mut fit_count = 0usize;
    let mut returned = 0usize;
    for record in records {
        let record_len = encoded_file_notification_record_len(record);
        if returned
            .checked_add(record_len)
            .is_none_or(|needed| needed > buffer_len)
        {
            break;
        }
        returned += record_len;
        fit_count += 1;
    }
    (fit_count, returned)
}

fn encoded_file_notification_len(records: &[crate::ce::object::FileChangeRecord]) -> usize {
    records
        .iter()
        .map(encoded_file_notification_record_len)
        .sum()
}

fn encoded_file_notification_record_len(record: &crate::ce::object::FileChangeRecord) -> usize {
    let name_len = record.path.encode_utf16().count() * 2;
    align_usize_to_u32(12usize + name_len)
}

fn encode_file_notification_records(records: &[crate::ce::object::FileChangeRecord]) -> Vec<u8> {
    let mut encoded_records = Vec::with_capacity(records.len());
    let mut total_len = 0usize;
    for record in records {
        let mut name = Vec::new();
        for unit in record.path.encode_utf16() {
            name.extend_from_slice(&unit.to_le_bytes());
        }
        let aligned_len = encoded_file_notification_record_len(record);
        let record_len = 12usize + name.len();
        total_len += aligned_len;
        encoded_records.push((record.action, name, record_len, aligned_len));
    }
    let mut out = Vec::with_capacity(total_len);
    for (index, (action, name, record_len, aligned_len)) in encoded_records.iter().enumerate() {
        let next_offset = if index + 1 == encoded_records.len() {
            0
        } else {
            *aligned_len as u32
        };
        out.extend_from_slice(&next_offset.to_le_bytes());
        out.extend_from_slice(&action.to_le_bytes());
        out.extend_from_slice(&(name.len() as u32).to_le_bytes());
        out.extend_from_slice(name);
        out.resize(out.len() + aligned_len.saturating_sub(*record_len), 0);
    }
    out
}

fn align_usize_to_u32(value: usize) -> usize {
    (value + 3) & !3
}

fn message_box_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let state = match message_box_w_prepare(kernel, memory, framebuffer, thread_id, args) {
        Err(result) => return result,
        Ok(state) => state,
    };
    let result = state
        .try_queued_result(kernel, thread_id)
        .unwrap_or_else(|| state.default_result());
    state.teardown(kernel, thread_id, result);
    kernel.threads.set_last_error(thread_id, 0);
    result
}

/// Validate args, disable owner, create the dialog window, and optionally render.
/// Returns `Err(result)` on invalid args (caller should set V0 and return immediately).
/// Returns `Ok(state)` with the live dialog ready for the modal loop.
pub(crate) fn message_box_w_prepare<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> std::result::Result<MessageBoxModalState, u32> {
    let owner_hwnd = raw_arg(args, 0);
    if owner_hwnd != 0 && !kernel.gwe.is_window(owner_hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return Err(0);
    }
    let text_ptr = raw_arg(args, 1);
    let caption_ptr = raw_arg(args, 2);
    let Some(text) = read_message_box_string(memory, text_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let Some(caption) = read_message_box_string(memory, caption_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let style = raw_arg(args, 3);
    let Some(selection) = message_box_selection(style) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let owner_was_enabled = if owner_hwnd == 0 {
        None
    } else {
        Some(kernel.gwe.is_window_enabled(owner_hwnd))
    };
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{:08x}", owner_hwnd),
        text = %text,
        caption = %caption,
        style = format_args!("0x{:08x}", style),
        result = selection.result,
        "MessageBoxW"
    );
    if owner_was_enabled.is_some() {
        let _ = kernel.enable_window(owner_hwnd, false);
    }
    let window_state =
        create_message_box_window(kernel, thread_id, owner_hwnd, &caption, &text, &selection);
    let rendered = if let Some(framebuffer) = framebuffer {
        render_message_box_framebuffer(framebuffer, &caption, &text, &selection);
        true
    } else {
        false
    };
    Ok(MessageBoxModalState {
        window_state,
        selection,
        owner_hwnd,
        owner_was_enabled,
        text,
        caption,
        style,
        rendered,
    })
}

/// Carries live dialog state during a modal `MessageBoxW` wait.
#[derive(Debug, Clone)]
#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) struct MessageBoxModalState {
    window_state: MessageBoxWindowState,
    selection: MessageBoxSelection,
    owner_hwnd: u32,
    owner_was_enabled: Option<bool>,
    text: String,
    caption: String,
    style: u32,
    rendered: bool,
}

#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
impl MessageBoxModalState {
    pub(crate) fn dialog_hwnd(&self) -> u32 {
        self.window_state.dialog_hwnd
    }

    pub(crate) fn default_result(&self) -> u32 {
        self.selection.result
    }

    /// Drain any already-queued modal messages; returns `Some(result)` if the dialog
    /// was dismissed, `None` if more input is still needed.
    pub(crate) fn try_queued_result(&self, kernel: &mut CeKernel, thread_id: u32) -> Option<u32> {
        message_box_modal_input_result(kernel, thread_id, &self.window_state, &self.selection)
    }

    /// End the dialog, destroy its window, re-enable the owner, and record to shell.
    pub(crate) fn teardown(self, kernel: &mut CeKernel, thread_id: u32, result: u32) {
        let _ = kernel.end_dialog(thread_id, self.window_state.dialog_hwnd, result);
        let _ = kernel.destroy_window_with_reason(self.window_state.dialog_hwnd, "MessageBoxW");
        if let Some(was_enabled) = self.owner_was_enabled {
            let _ = kernel.enable_window(self.owner_hwnd, was_enabled);
        }
        kernel.shell.record_message_box(MessageBoxRecord {
            thread_id,
            owner_hwnd: self.owner_hwnd,
            dialog_hwnd: self.window_state.dialog_hwnd,
            text_hwnd: self.window_state.text_hwnd,
            text: self.text,
            caption: self.caption,
            style: self.style,
            buttons: self.selection.buttons,
            button_hwnds: self.window_state.button_hwnds,
            button_layout: self.selection.button_layout,
            default_button_index: self.selection.default_button_index,
            icon: self.selection.icon,
            result,
            owner_was_enabled: self.owner_was_enabled,
            rendered: self.rendered,
        });
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct MessageBoxWindowState {
    pub(crate) dialog_hwnd: u32,
    pub(crate) text_hwnd: u32,
    pub(crate) button_hwnds: Vec<u32>,
}

fn create_message_box_window(
    kernel: &mut CeKernel,
    thread_id: u32,
    owner_hwnd: u32,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
) -> MessageBoxWindowState {
    let owner = (owner_hwnd != 0).then_some(owner_hwnd);
    let dialog = kernel.create_window_ex_w_with_parent_owner_and_rect(
        thread_id,
        "Dialog",
        caption,
        None,
        owner,
        0,
        WS_POPUP | WS_VISIBLE,
        0,
        Rect::from_origin_size(24, 24, 220, 96),
    );
    let text_hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "Static",
        text,
        Some(dialog),
        0,
        WS_CHILD | WS_VISIBLE,
        0,
        Rect::from_origin_size(12, 12, 196, 34),
    );
    let button_width = 58;
    let button_height = 18;
    let button_y = 62;
    let button_hwnds = selection
        .button_layout
        .iter()
        .enumerate()
        .map(|(index, button)| {
            let button_style = if index == selection.default_button_index {
                BS_DEFPUSHBUTTON
            } else {
                BS_PUSHBUTTON
            };
            let style = WS_CHILD | WS_VISIBLE | WS_TABSTOP | button_style;
            kernel.create_window_ex_w_with_rect(
                thread_id,
                "Button",
                message_box_button_title(button.label),
                Some(dialog),
                button.id,
                style,
                0,
                Rect::from_origin_size(
                    message_box_button_x(button.slot, button_width),
                    button_y,
                    button_width,
                    button_height,
                ),
            )
        })
        .collect();
    MessageBoxWindowState {
        dialog_hwnd: dialog,
        text_hwnd,
        button_hwnds,
    }
}

fn message_box_modal_input_result(
    kernel: &mut CeKernel,
    thread_id: u32,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> Option<u32> {
    let modal_message_min = crate::ce::gwe::WM_PAINT;
    while let Some(message) = kernel.gwe.peek_message_filtered(
        thread_id,
        None,
        modal_message_min,
        crate::ce::gwe::WM_LBUTTONUP,
        PeekFlags::REMOVE,
    ) {
        if message_box_message_targets_window(window_state, message.hwnd) {
            if let Some(result) =
                message_box_message_result(kernel, window_state, selection, &message)
            {
                return Some(result);
            }
            if message.msg == crate::ce::gwe::WM_PAINT {
                kernel.dispatch_message_w_for_thread(thread_id, message);
            }
        } else {
            kernel.dispatch_message_w_for_thread(thread_id, message);
        }
    }
    None
}

fn message_box_message_targets_window(window_state: &MessageBoxWindowState, hwnd: u32) -> bool {
    hwnd == window_state.dialog_hwnd
        || hwnd == window_state.text_hwnd
        || window_state.button_hwnds.contains(&hwnd)
}

fn message_box_message_result(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    message: &Message,
) -> Option<u32> {
    const VK_RETURN: u32 = 0x0d;
    const VK_ESCAPE: u32 = 0x1b;

    match message.msg {
        crate::ce::gwe::WM_COMMAND => {
            let command = message.wparam & 0xffff;
            selection.buttons.contains(&command).then_some(command)
        }
        crate::ce::gwe::WM_CLOSE => Some(message_box_cancel_or_default_result(
            kernel,
            window_state,
            selection,
        )),
        crate::ce::gwe::WM_SYSCOMMAND if (message.wparam & 0xfff0) == crate::ce::gwe::SC_CLOSE => {
            Some(message_box_cancel_or_default_result(
                kernel,
                window_state,
                selection,
            ))
        }
        crate::ce::gwe::WM_KEYDOWN if message.wparam == VK_RETURN => {
            let (command, _) = kernel.gwe.dialog_return_command(
                window_state.dialog_hwnd,
                message.hwnd,
                selection.result,
            );
            Some(command)
        }
        crate::ce::gwe::WM_CHAR if message.wparam == VK_RETURN => {
            let (command, _) = kernel.gwe.dialog_return_command(
                window_state.dialog_hwnd,
                message.hwnd,
                selection.result,
            );
            Some(command)
        }
        crate::ce::gwe::WM_KEYDOWN if message.wparam == VK_ESCAPE => Some(
            message_box_cancel_or_default_result(kernel, window_state, selection),
        ),
        crate::ce::gwe::WM_CHAR if message.wparam == VK_ESCAPE => Some(
            message_box_cancel_or_default_result(kernel, window_state, selection),
        ),
        crate::ce::gwe::WM_LBUTTONDOWN => None,
        crate::ce::gwe::WM_LBUTTONUP => {
            if let Some(command) =
                message_box_direct_button_command(kernel, window_state, selection, message.hwnd)
            {
                return Some(command);
            }
            if message.hwnd == window_state.dialog_hwnd {
                return message_box_dialog_click_command(
                    kernel,
                    window_state,
                    selection,
                    message.lparam,
                );
            }
            None
        }
        _ => None,
    }
}

fn message_box_direct_button_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    hwnd: u32,
) -> Option<u32> {
    window_state
        .button_hwnds
        .contains(&hwnd)
        .then(|| kernel.gwe.get_dlg_ctrl_id(hwnd))
        .flatten()
        .filter(|id| selection.buttons.contains(id))
}

fn message_box_dialog_click_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    lparam: u32,
) -> Option<u32> {
    let point = message_box_lparam_point(lparam);
    let screen_point = kernel
        .gwe
        .client_to_screen(window_state.dialog_hwnd, point)?;
    window_state
        .button_hwnds
        .iter()
        .copied()
        .find(|hwnd| {
            kernel
                .gwe
                .get_window_rect(*hwnd)
                .is_some_and(|rect| rect.contains_point(screen_point))
        })
        .and_then(|hwnd| message_box_direct_button_command(kernel, window_state, selection, hwnd))
}

fn message_box_lparam_point(lparam: u32) -> Point {
    Point {
        x: (lparam & 0xffff) as i16 as i32,
        y: ((lparam >> 16) & 0xffff) as i16 as i32,
    }
}

fn message_box_cancel_or_default_result(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> u32 {
    const IDCANCEL: u32 = 2;
    if selection.buttons.contains(&IDCANCEL) {
        let (command, _) = kernel
            .gwe
            .dialog_cancel_command(window_state.dialog_hwnd, IDCANCEL);
        command
    } else {
        selection.result
    }
}

fn render_message_box_framebuffer(
    framebuffer: &mut dyn Framebuffer,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
) {
    const DIALOG_LEFT: i32 = 24;
    const DIALOG_TOP: i32 = 24;
    const DIALOG_WIDTH: i32 = 220;
    const DIALOG_HEIGHT: i32 = 96;

    let dialog = Rect::from_origin_size(DIALOG_LEFT, DIALOG_TOP, DIALOG_WIDTH, DIALOG_HEIGHT);
    let caption_rect =
        Rect::from_origin_size(DIALOG_LEFT + 2, DIALOG_TOP + 2, DIALOG_WIDTH - 4, 14);
    fill_framebuffer_screen_rect(framebuffer, dialog, rgb(0x00, 0x00, 0x00));
    fill_framebuffer_screen_rect(
        framebuffer,
        Rect::from_origin_size(
            DIALOG_LEFT + 1,
            DIALOG_TOP + 1,
            DIALOG_WIDTH - 2,
            DIALOG_HEIGHT - 2,
        ),
        rgb(0xc0, 0xc0, 0xc0),
    );
    fill_framebuffer_screen_rect(framebuffer, caption_rect, rgb(0x00, 0x00, 0x80));
    render_framebuffer_text_marks(
        framebuffer,
        Rect::from_origin_size(DIALOG_LEFT + 8, DIALOG_TOP + 5, 150, 7),
        caption,
        rgb(0xff, 0xff, 0xff),
    );

    if let Some(icon) = selection.icon {
        let color = match icon {
            MessageBoxIcon::Hand => rgb(0xc0, 0x00, 0x00),
            MessageBoxIcon::Question => rgb(0x00, 0x40, 0xff),
            MessageBoxIcon::Exclamation => rgb(0xff, 0xc0, 0x00),
            MessageBoxIcon::Asterisk => rgb(0x00, 0x80, 0x40),
        };
        fill_framebuffer_screen_rect(
            framebuffer,
            Rect::from_origin_size(DIALOG_LEFT + 12, DIALOG_TOP + 28, 18, 18),
            rgb(0xff, 0xff, 0xff),
        );
        fill_framebuffer_screen_rect(
            framebuffer,
            Rect::from_origin_size(DIALOG_LEFT + 15, DIALOG_TOP + 31, 12, 12),
            color,
        );
    }

    fill_framebuffer_screen_rect(
        framebuffer,
        Rect::from_origin_size(DIALOG_LEFT + 38, DIALOG_TOP + 25, 168, 24),
        rgb(0xff, 0xff, 0xff),
    );
    render_framebuffer_text_marks(
        framebuffer,
        Rect::from_origin_size(DIALOG_LEFT + 42, DIALOG_TOP + 30, 156, 12),
        text,
        rgb(0x00, 0x00, 0x00),
    );

    for (index, button) in selection.button_layout.iter().enumerate() {
        let button_rect = Rect::from_origin_size(
            DIALOG_LEFT + message_box_button_x(button.slot, 58),
            DIALOG_TOP + 62,
            58,
            18,
        );
        fill_framebuffer_screen_rect(framebuffer, button_rect, rgb(0x00, 0x00, 0x00));
        fill_framebuffer_screen_rect(
            framebuffer,
            Rect::from_origin_size(
                button_rect.left + 1,
                button_rect.top + 1,
                button_rect.width() - 2,
                button_rect.height() - 2,
            ),
            rgb(0xd8, 0xd8, 0xd8),
        );
        if index == selection.default_button_index {
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(
                    button_rect.left + 3,
                    button_rect.top + 3,
                    button_rect.width() - 6,
                    1,
                ),
                rgb(0x00, 0x00, 0x00),
            );
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(
                    button_rect.left + 3,
                    button_rect.bottom - 4,
                    button_rect.width() - 6,
                    1,
                ),
                rgb(0x00, 0x00, 0x00),
            );
        }
        render_framebuffer_text_marks(
            framebuffer,
            Rect::from_origin_size(button_rect.left + 7, button_rect.top + 7, 44, 6),
            message_box_button_title(button.label),
            rgb(0x00, 0x00, 0x00),
        );
    }
}

fn render_framebuffer_text_marks(
    framebuffer: &mut dyn Framebuffer,
    rect: Rect,
    text: &str,
    color: u32,
) {
    let mut x = rect.left;
    let mut y = rect.top;
    let max_right = rect.right;
    let max_bottom = rect.bottom;
    for ch in text.chars().take(96) {
        if ch == '\r' {
            continue;
        }
        if ch == '\n' || x + 4 > max_right {
            x = rect.left;
            y += 6;
            if ch == '\n' {
                continue;
            }
        }
        if y + 5 > max_bottom {
            break;
        }
        if !ch.is_whitespace() {
            fill_framebuffer_screen_rect(framebuffer, Rect::from_origin_size(x, y, 3, 5), color);
        }
        x += 4;
    }
}

fn message_box_button_x(slot: MessageBoxButtonSlot, button_width: i32) -> i32 {
    match slot {
        MessageBoxButtonSlot::Left => 26,
        MessageBoxButtonSlot::Center => 110 - button_width / 2,
        MessageBoxButtonSlot::Right => 220 - 26 - button_width,
    }
}

fn message_box_button_title(label: MessageBoxButtonLabel) -> &'static str {
    match label {
        MessageBoxButtonLabel::Ok => "OK",
        MessageBoxButtonLabel::Cancel => "Cancel",
        MessageBoxButtonLabel::Abort => "Abort",
        MessageBoxButtonLabel::Retry => "Retry",
        MessageBoxButtonLabel::Ignore => "Ignore",
        MessageBoxButtonLabel::Yes => "Yes",
        MessageBoxButtonLabel::No => "No",
        MessageBoxButtonLabel::YesAll => "Yes to All",
    }
}

fn read_message_box_string<M: CoredllGuestMemory>(memory: &M, ptr: u32) -> Option<String> {
    if ptr == 0 {
        Some(String::new())
    } else {
        read_guest_wide_arg(memory, ptr)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct MessageBoxSelection {
    pub(crate) buttons: Vec<u32>,
    pub(crate) button_layout: Vec<MessageBoxButton>,
    pub(crate) default_button_index: usize,
    pub(crate) icon: Option<MessageBoxIcon>,
    pub(crate) result: u32,
}

fn message_box_selection(style: u32) -> Option<MessageBoxSelection> {
    const MB_TYPEMASK: u32 = 0x0000_000f;
    const MB_DEFMASK: u32 = 0x0000_0300;
    const MB_ICONMASK: u32 = 0x0000_00f0;
    const MB_OK: u32 = 0x0000_0000;
    const MB_OKCANCEL: u32 = 0x0000_0001;
    const MB_ABORTRETRYIGNORE: u32 = 0x0000_0002;
    const MB_YESNOCANCEL: u32 = 0x0000_0003;
    const MB_YESNO: u32 = 0x0000_0004;
    const MB_RETRYCANCEL: u32 = 0x0000_0005;
    const MB_YESALL: u32 = 0x0000_0006;
    const MB_CANCEL: u32 = 0x0000_0007;
    const MB_DEFBUTTON1: u32 = 0x0000_0000;
    const MB_DEFBUTTON2: u32 = 0x0000_0100;
    const MB_DEFBUTTON3: u32 = 0x0000_0200;
    const MB_DEFBUTTON4: u32 = 0x0000_0300;
    const MB_ICONHAND: u32 = 0x0000_0010;
    const MB_ICONQUESTION: u32 = 0x0000_0020;
    const MB_ICONEXCLAMATION: u32 = 0x0000_0030;
    const MB_ICONASTERISK: u32 = 0x0000_0040;
    const IDOK: u32 = 1;
    const IDCANCEL: u32 = 2;
    const IDABORT: u32 = 3;
    const IDRETRY: u32 = 4;
    const IDIGNORE: u32 = 5;
    const IDYES: u32 = 6;
    const IDNO: u32 = 7;

    let button_layout: Vec<MessageBoxButton> = match style & MB_TYPEMASK {
        MB_OK => vec![message_box_button(
            IDOK,
            MessageBoxButtonLabel::Ok,
            MessageBoxButtonSlot::Center,
        )],
        MB_OKCANCEL => vec![
            message_box_button(IDOK, MessageBoxButtonLabel::Ok, MessageBoxButtonSlot::Left),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_ABORTRETRYIGNORE => vec![
            message_box_button(
                IDABORT,
                MessageBoxButtonLabel::Abort,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDRETRY,
                MessageBoxButtonLabel::Retry,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDIGNORE,
                MessageBoxButtonLabel::Ignore,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESNOCANCEL => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDNO,
                MessageBoxButtonLabel::No,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESNO => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(IDNO, MessageBoxButtonLabel::No, MessageBoxButtonSlot::Right),
        ],
        MB_RETRYCANCEL => vec![
            message_box_button(
                IDRETRY,
                MessageBoxButtonLabel::Retry,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESALL => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDNO,
                MessageBoxButtonLabel::No,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::YesAll,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_CANCEL => vec![message_box_button(
            IDCANCEL,
            MessageBoxButtonLabel::Cancel,
            MessageBoxButtonSlot::Center,
        )],
        _ => return None,
    };
    let buttons: Vec<u32> = button_layout.iter().map(|button| button.id).collect();
    let requested_index = match style & MB_DEFMASK {
        MB_DEFBUTTON1 => 0,
        MB_DEFBUTTON2 => 1,
        MB_DEFBUTTON3 => 2,
        MB_DEFBUTTON4 => 3,
        _ => 0,
    };
    let default_button_index = if requested_index < button_layout.len() {
        requested_index
    } else {
        0
    };
    let icon = match style & MB_ICONMASK {
        0 => None,
        MB_ICONHAND => Some(MessageBoxIcon::Hand),
        MB_ICONQUESTION => Some(MessageBoxIcon::Question),
        MB_ICONEXCLAMATION => Some(MessageBoxIcon::Exclamation),
        MB_ICONASTERISK => Some(MessageBoxIcon::Asterisk),
        _ => None,
    };
    let result = buttons[default_button_index];
    Some(MessageBoxSelection {
        buttons,
        button_layout,
        default_button_index,
        icon,
        result,
    })
}

fn message_box_button(
    id: u32,
    label: MessageBoxButtonLabel,
    slot: MessageBoxButtonSlot,
) -> MessageBoxButton {
    MessageBoxButton { id, label, slot }
}

fn create_caret_raw(
    kernel: &mut CeKernel,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let old_rect = visible_caret_dirty_rect(kernel);
    let hwnd = raw_arg(args, 0);
    if hwnd == 0 || !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    if kernel.gwe.create_caret(
        hwnd,
        raw_arg(args, 1),
        raw_i32_arg(args, 2),
        raw_i32_arg(args, 3),
    ) {
        dirty_caret_rects(kernel, framebuffer, old_rect);
        kernel.threads.set_last_error(thread_id, 0);
        true
    } else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        false
    }
}

