fn get_string_type_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    const CT_CTYPE1: u32 = 0x0001;
    const CT_CTYPE2: u32 = 0x0002;
    const CT_CTYPE3: u32 = 0x0004;

    // GetStringTypeExW has locale as arg0, type at arg1; GetStringTypeW has type at arg0
    let (info_type, src_ptr, cch_src, out_ptr) = if args.len() >= 5 {
        (raw_arg(args, 1), raw_arg(args, 2), raw_arg(args, 3) as i32, raw_arg(args, 4))
    } else {
        (raw_arg(args, 0), raw_arg(args, 1), raw_arg(args, 2) as i32, raw_arg(args, 3))
    };

    if src_ptr == 0 || out_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if !matches!(info_type, CT_CTYPE1 | CT_CTYPE2 | CT_CTYPE3) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }

    let Some(units) = read_conversion_wide(kernel, memory, thread_id, src_ptr, cch_src) else {
        return false;
    };
    let count = if cch_src < 0 {
        // null-terminated: strip the null terminator
        units.iter().position(|&u| u == 0).unwrap_or(units.len())
    } else {
        units.len()
    };

    for (i, &u) in units.iter().take(count).enumerate() {
        let char_type: u16 = match info_type {
            CT_CTYPE1 => unicode_ctype1(u),
            CT_CTYPE2 => unicode_ctype2(u),
            CT_CTYPE3 => unicode_ctype3(u),
            _ => 0,
        };
        if !write_guest_u16(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add((i as u32) * 2),
            char_type,
        ) {
            return false;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn unicode_ctype1(u: u16) -> u16 {
    const C1_UPPER: u16 = 0x0001;
    const C1_LOWER: u16 = 0x0002;
    const C1_DIGIT: u16 = 0x0004;
    const C1_SPACE: u16 = 0x0008;
    const C1_PUNCT: u16 = 0x0010;
    const C1_CNTRL: u16 = 0x0020;
    const C1_BLANK: u16 = 0x0040;
    const C1_XDIGIT: u16 = 0x0080;
    const C1_ALPHA: u16 = 0x0100;
    const C1_DEFINED: u16 = 0x0200;

    match u {
        0x0000..=0x0008 | 0x000E..=0x001F | 0x007F => C1_CNTRL | C1_DEFINED,
        0x0009 => C1_SPACE | C1_CNTRL | C1_DEFINED,
        0x000A..=0x000D => C1_SPACE | C1_CNTRL | C1_DEFINED,
        0x0020 => C1_SPACE | C1_BLANK | C1_DEFINED,
        0x0021..=0x002F | 0x003A..=0x0040 | 0x005B..=0x0060 | 0x007B..=0x007E => {
            C1_PUNCT | C1_DEFINED
        }
        0x0030..=0x0039 => C1_DIGIT | C1_XDIGIT | C1_DEFINED,
        0x0041..=0x0046 => C1_UPPER | C1_ALPHA | C1_XDIGIT | C1_DEFINED,
        0x0047..=0x005A => C1_UPPER | C1_ALPHA | C1_DEFINED,
        0x0061..=0x0066 => C1_LOWER | C1_ALPHA | C1_XDIGIT | C1_DEFINED,
        0x0067..=0x007A => C1_LOWER | C1_ALPHA | C1_DEFINED,
        0x00C0..=0x00D6 | 0x00D8..=0x00DE => C1_UPPER | C1_ALPHA | C1_DEFINED,
        0x00DF..=0x00F6 | 0x00F8..=0x00FF => C1_LOWER | C1_ALPHA | C1_DEFINED,
        0x0100..=0x017E => {
            if u % 2 == 0 {
                C1_UPPER | C1_ALPHA | C1_DEFINED
            } else {
                C1_LOWER | C1_ALPHA | C1_DEFINED
            }
        }
        0x0391..=0x03A9 => C1_UPPER | C1_ALPHA | C1_DEFINED,
        0x03B1..=0x03C9 => C1_LOWER | C1_ALPHA | C1_DEFINED,
        0x0410..=0x042F => C1_UPPER | C1_ALPHA | C1_DEFINED,
        0x0430..=0x044F => C1_LOWER | C1_ALPHA | C1_DEFINED,
        0x1100..=0x11FF => C1_ALPHA | C1_DEFINED,
        0x3040..=0x309F => C1_ALPHA | C1_DEFINED,
        0x30A0..=0x30FF => C1_ALPHA | C1_DEFINED,
        0x3400..=0x4DBF | 0x4E00..=0x9FFF | 0xF900..=0xFAFF => C1_ALPHA | C1_DEFINED,
        0xAC00..=0xD7A3 => C1_ALPHA | C1_DEFINED,
        0xD7B0..=0xD7FF => C1_ALPHA | C1_DEFINED,
        0xFF10..=0xFF19 => C1_DIGIT | C1_DEFINED,
        0xFF21..=0xFF26 | 0xFF41..=0xFF46 => C1_ALPHA | C1_XDIGIT | C1_DEFINED,
        0xFF27..=0xFF3A | 0xFF47..=0xFF5A => C1_ALPHA | C1_DEFINED,
        0x00A0..=0x00BF | 0x2000..=0x206F => C1_PUNCT | C1_DEFINED,
        _ => {
            if u >= 0x0080 { C1_DEFINED } else { 0 }
        }
    }
}

fn unicode_ctype2(u: u16) -> u16 {
    const C2_LEFTTORIGHT: u16 = 0x0001;
    const C2_RIGHTTOLEFT: u16 = 0x0002;
    const C2_EUROPENUMBER: u16 = 0x0003;
    const C2_EUROPESEPARATOR: u16 = 0x0004;
    const C2_EUROPETERMINATOR: u16 = 0x0005;
    const C2_ARABICNUMBER: u16 = 0x0006;
    const C2_COMMONSEPARATOR: u16 = 0x0007;
    const C2_BLOCKSEPARATOR: u16 = 0x0008;
    const C2_SEGMENTSEPARATOR: u16 = 0x0009;
    const C2_WHITESPACE: u16 = 0x000A;
    const C2_OTHERNEUTRAL: u16 = 0x000B;
    const C2_NOTAPPLICABLE: u16 = 0x0000;

    match u {
        0x0000..=0x0008 | 0x000E..=0x001B | 0x007F | 0x0080..=0x0084 | 0x0086..=0x009F => {
            C2_NOTAPPLICABLE
        }
        0x0009 | 0x000B | 0x001F => C2_SEGMENTSEPARATOR,
        0x000A | 0x000C | 0x001C..=0x001E => C2_BLOCKSEPARATOR,
        0x000D | 0x001D => C2_BLOCKSEPARATOR,
        0x0020 | 0x00A0 => C2_WHITESPACE,
        0x0021..=0x0022 | 0x0026..=0x002A | 0x003B..=0x0040 | 0x005B..=0x0060
        | 0x007B..=0x007E => C2_OTHERNEUTRAL,
        0x0023..=0x0025 | 0x002B..=0x002C | 0x002D => C2_EUROPETERMINATOR,
        0x002E..=0x002F => C2_EUROPESEPARATOR,
        0x0030..=0x0039 => C2_EUROPENUMBER,
        0x003A => C2_COMMONSEPARATOR,
        0x0041..=0x005A | 0x0061..=0x007A | 0x00C0..=0x00D6 | 0x00D8..=0x00F6
        | 0x00F8..=0x02B8 => C2_LEFTTORIGHT,
        0x0300..=0x036F => C2_NOTAPPLICABLE,
        0x0400..=0x04FF => C2_LEFTTORIGHT,
        0x0591..=0x05FF | 0x0610..=0x061A | 0x064B..=0x065E | 0x0670 | 0x06D6..=0x06E4
        | 0x06E7..=0x06E8 | 0x06EA..=0x06ED => C2_RIGHTTOLEFT,
        0x0600..=0x06FF | 0x0750..=0x077F => C2_RIGHTTOLEFT,
        0xFF10..=0xFF19 => C2_EUROPENUMBER,
        0x1100..=0x11FF | 0x3040..=0x30FF | 0x4E00..=0x9FFF | 0xAC00..=0xD7A3 => {
            C2_LEFTTORIGHT
        }
        _ => {
            if u > 0x007E { C2_LEFTTORIGHT } else { C2_OTHERNEUTRAL }
        }
    }
}

fn unicode_ctype3(u: u16) -> u16 {
    const C3_NONSPACING: u16 = 0x0001;
    const C3_DIACRITIC: u16 = 0x0002;
    const C3_VOWELMARK: u16 = 0x0004;
    const C3_SYMBOL: u16 = 0x0008;
    const C3_KATAKANA: u16 = 0x0010;
    const C3_HIRAGANA: u16 = 0x0020;
    const C3_HALFWIDTH: u16 = 0x0040;
    const C3_FULLWIDTH: u16 = 0x0080;
    const C3_IDEOGRAPH: u16 = 0x0100;
    const C3_ALPHA: u16 = 0x8000;
    const C3_NOTAPPLICABLE: u16 = 0x0000;

    match u {
        0x0000..=0x007E => C3_HALFWIDTH,
        0x0300..=0x036F => C3_NONSPACING | C3_DIACRITIC,
        0x064B..=0x0652 => C3_NONSPACING | C3_DIACRITIC | C3_VOWELMARK,
        0x1100..=0x11FF => C3_ALPHA,
        0x3040..=0x309F => C3_HIRAGANA | C3_FULLWIDTH | C3_ALPHA,
        0x30A0..=0x30FF => C3_KATAKANA | C3_FULLWIDTH | C3_ALPHA,
        0x3400..=0x4DBF | 0x4E00..=0x9FFF | 0xF900..=0xFAFF => C3_IDEOGRAPH | C3_FULLWIDTH,
        0xAC00..=0xD7A3 | 0xD7B0..=0xD7FF => C3_ALPHA | C3_FULLWIDTH,
        0xFF01..=0xFF0F | 0xFF1A..=0xFF20 | 0xFF3B..=0xFF40 | 0xFF5B..=0xFF60 => {
            C3_SYMBOL | C3_FULLWIDTH
        }
        0xFF10..=0xFF19 => C3_FULLWIDTH,
        0xFF21..=0xFF3A | 0xFF41..=0xFF5A => C3_FULLWIDTH | C3_ALPHA,
        0xFF61..=0xFF9F => C3_HALFWIDTH | C3_KATAKANA,
        0xFFA0..=0xFFEE => C3_HALFWIDTH,
        0x00A1..=0x00FF | 0x2000..=0x206F => C3_SYMBOL | C3_FULLWIDTH,
        _ => C3_NOTAPPLICABLE,
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct SystemTimeFields {
    year: u16,
    month: u16,
    day_of_week: u16,
    day: u16,
    hour: u16,
    minute: u16,
    second: u16,
    milliseconds: u16,
}

fn write_current_system_time<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    system_time_ptr: u32,
) {
    if system_time_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return;
    }
    let fields = system_time_fields_from_ticks(current_filetime_ticks(kernel));
    let ok = write_guest_u16(kernel, memory, thread_id, system_time_ptr, fields.year)
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(2),
            fields.month,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(4),
            fields.day_of_week,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(6),
            fields.day,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(8),
            fields.hour,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(10),
            fields.minute,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(12),
            fields.second,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(14),
            fields.milliseconds,
        );
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
    }
}

fn write_current_file_time<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    file_time_ptr: u32,
) {
    if file_time_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return;
    }
    let ticks = current_filetime_ticks(kernel);
    if write_guest_u32(kernel, memory, thread_id, file_time_ptr, ticks as u32)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            file_time_ptr.wrapping_add(4),
            (ticks >> 32) as u32,
        )
    {
        kernel.threads.set_last_error(thread_id, 0);
    }
}

fn write_time_zone_information<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    time_zone_information_ptr: u32,
) -> u32 {
    if time_zone_information_ptr == 0
        || !write_guest_bytes(
            kernel,
            memory,
            thread_id,
            time_zone_information_ptr,
            &[0; TIME_ZONE_INFORMATION_SIZE],
        )
        || !write_guest_i32(kernel, memory, thread_id, time_zone_information_ptr, 0)
        || !write_guest_wide_fixed(
            kernel,
            memory,
            thread_id,
            time_zone_information_ptr.wrapping_add(4),
            "UTC",
            32,
        )
        || !write_guest_i32(
            kernel,
            memory,
            thread_id,
            time_zone_information_ptr.wrapping_add(84),
            0,
        )
        || !write_guest_i32(
            kernel,
            memory,
            thread_id,
            time_zone_information_ptr.wrapping_add(168),
            0,
        )
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return TIME_ZONE_ID_INVALID;
    }
    kernel.threads.set_last_error(thread_id, 0);
    TIME_ZONE_ID_UNKNOWN
}

fn current_filetime_ticks(kernel: &CeKernel) -> u64 {
    let base_days = days_before_year(SYSTEM_TIME_BASE_YEAR)
        + days_before_month(SYSTEM_TIME_BASE_YEAR, SYSTEM_TIME_BASE_MONTH)
        + i64::from(SYSTEM_TIME_BASE_DAY - 1);
    (base_days as u64)
        .saturating_mul(86_400)
        .saturating_mul(FILETIME_TICKS_PER_SECOND)
        .saturating_add(
            u64::from(kernel.timers.tick_count()).saturating_mul(FILETIME_TICKS_PER_MILLISECOND),
        )
}

fn system_time_fields_from_ticks(ticks: u64) -> SystemTimeFields {
    let total_ms = ticks / FILETIME_TICKS_PER_MILLISECOND;
    let total_seconds = total_ms / 1_000;
    let mut days = (total_seconds / 86_400) as i64;
    let seconds_of_day = total_seconds % 86_400;
    let milliseconds = (total_ms % 1_000) as u16;

    let mut year = 1601;
    loop {
        let days_in_year = if is_leap_year(year) { 366 } else { 365 };
        if days < days_in_year {
            break;
        }
        days -= days_in_year;
        year += 1;
    }

    let mut month = 1;
    loop {
        let days_in_month = days_in_month(year, month);
        if days < i64::from(days_in_month) {
            break;
        }
        days -= i64::from(days_in_month);
        month += 1;
    }

    let days_since_epoch = total_seconds / 86_400;
    SystemTimeFields {
        year: year as u16,
        month: month as u16,
        day_of_week: ((days_since_epoch + 1) % 7) as u16,
        day: (days + 1) as u16,
        hour: (seconds_of_day / 3_600) as u16,
        minute: ((seconds_of_day % 3_600) / 60) as u16,
        second: (seconds_of_day % 60) as u16,
        milliseconds,
    }
}

fn read_system_time_fields<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    ptr: u32,
) -> Option<SystemTimeFields> {
    Some(SystemTimeFields {
        year: read_guest_u16(kernel, memory, thread_id, ptr)?,
        month: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(2))?,
        day_of_week: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(4))?,
        day: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(6))?,
        hour: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(8))?,
        minute: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(10))?,
        second: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(12))?,
        milliseconds: read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(14))?,
    })
}

fn system_time_to_file_time_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    system_time_ptr: u32,
    file_time_ptr: u32,
) -> bool {
    if system_time_ptr == 0 || file_time_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(year) = read_guest_u16(kernel, memory, thread_id, system_time_ptr) else {
        return false;
    };
    let Some(month) = read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(2))
    else {
        return false;
    };
    let Some(day) = read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(6))
    else {
        return false;
    };
    let Some(hour) = read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(8))
    else {
        return false;
    };
    let Some(minute) = read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(10))
    else {
        return false;
    };
    let Some(second) = read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(12))
    else {
        return false;
    };
    let Some(milliseconds) =
        read_guest_u16(kernel, memory, thread_id, system_time_ptr.wrapping_add(14))
    else {
        return false;
    };
    if year < 1601
        || month == 0
        || month > 12
        || day == 0
        || day > days_in_month(year as i32, month as i32) as u16
        || hour > 23
        || minute > 59
        || second > 59
        || milliseconds > 999
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let days = days_before_year(year as i32)
        + days_before_month(year as i32, month as i32)
        + i64::from(day - 1);
    let seconds =
        days * 86_400 + i64::from(hour) * 3_600 + i64::from(minute) * 60 + i64::from(second);
    let ticks = (seconds as u64)
        .saturating_mul(FILETIME_TICKS_PER_SECOND)
        .saturating_add(u64::from(milliseconds).saturating_mul(FILETIME_TICKS_PER_MILLISECOND));
    if !write_guest_u32(kernel, memory, thread_id, file_time_ptr, ticks as u32)
        || !write_guest_u32(
            kernel,
            memory,
            thread_id,
            file_time_ptr.wrapping_add(4),
            (ticks >> 32) as u32,
        )
    {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn file_time_to_system_time_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    file_time_ptr: u32,
    system_time_ptr: u32,
) -> bool {
    if file_time_ptr == 0 || system_time_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(low) = read_guest_u32(kernel, memory, thread_id, file_time_ptr) else {
        return false;
    };
    let Some(high) = read_guest_u32(kernel, memory, thread_id, file_time_ptr.wrapping_add(4))
    else {
        return false;
    };
    let fields = system_time_fields_from_ticks((u64::from(high) << 32) | u64::from(low));
    let ok = write_guest_u16(kernel, memory, thread_id, system_time_ptr, fields.year)
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(2),
            fields.month,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(4),
            fields.day_of_week,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(6),
            fields.day,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(8),
            fields.hour,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(10),
            fields.minute,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(12),
            fields.second,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            system_time_ptr.wrapping_add(14),
            fields.milliseconds,
        );
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
    }
    ok
}

fn days_before_year(year: i32) -> i64 {
    let y = year - 1601;
    let leap_days_before = |year: i32| year / 4 - year / 100 + year / 400;
    i64::from(y * 365 + leap_days_before(year - 1) - leap_days_before(1600))
}

fn days_before_month(year: i32, month: i32) -> i64 {
    const MONTH_DAYS: [i32; 12] = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    let mut days = 0;
    for m in 1..month {
        days += MONTH_DAYS[(m - 1) as usize];
        if m == 2 && is_leap_year(year) {
            days += 1;
        }
    }
    i64::from(days)
}

fn days_in_month(year: i32, month: i32) -> i32 {
    const MONTH_DAYS: [i32; 12] = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    let mut days = MONTH_DAYS[(month - 1) as usize];
    if month == 2 && is_leap_year(year) {
        days += 1;
    }
    days
}

fn is_leap_year(year: i32) -> bool {
    (year % 4 == 0 && year % 100 != 0) || year % 400 == 0
}

fn reg_create_key_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(subkey) = read_optional_guest_wide_arg(memory, raw_arg(args, 1)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    let result = kernel
        .registry
        .reg_create_key_exw(raw_arg(args, 0), subkey.as_deref());
    if result.status == crate::ce::registry::ERROR_SUCCESS {
        if let Some(hkey) = result.hkey {
            if !write_optional_u32(kernel, memory, thread_id, raw_arg(args, 7), hkey) {
                return crate::ce::registry::ERROR_INVALID_PARAMETER;
            }
        }
        if !write_optional_u32(
            kernel,
            memory,
            thread_id,
            raw_arg(args, 8),
            result.disposition,
        ) {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        }
    }
    result.status
}

fn reg_open_key_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(subkey) = read_optional_guest_wide_arg(memory, raw_arg(args, 1)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    let result = kernel.registry.reg_open_key_exw(
        raw_arg(args, 0),
        subkey.as_deref(),
        raw_arg(args, 2),
        raw_arg(args, 3),
    );
    if result.status == crate::ce::registry::ERROR_SUCCESS {
        if let Some(hkey) = result.hkey {
            if !write_optional_u32(kernel, memory, thread_id, raw_arg(args, 4), hkey) {
                return crate::ce::registry::ERROR_INVALID_PARAMETER;
            }
        }
    }
    result.status
}

fn reg_delete_key_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(subkey) = read_optional_guest_wide_arg(memory, raw_arg(args, 1)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    kernel
        .registry
        .reg_delete_key_w(raw_arg(args, 0), subkey.as_deref())
}

fn reg_set_value_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(value_name) = read_optional_guest_wide_arg(memory, raw_arg(args, 1)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    let Some(data) = read_guest_bytes(
        kernel,
        memory,
        thread_id,
        raw_arg(args, 4),
        raw_arg(args, 5),
    ) else {
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    kernel.registry.reg_set_value_exw(
        raw_arg(args, 0),
        value_name.as_deref(),
        raw_arg(args, 3),
        &data,
    )
}

fn reg_query_value_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(value_name) = read_optional_guest_wide_arg(memory, raw_arg(args, 1)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    };
    let data_len_ptr = raw_arg(args, 5);
    let data_capacity = if data_len_ptr == 0 {
        None
    } else {
        let Some(capacity) = read_guest_u32(kernel, memory, thread_id, data_len_ptr) else {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        };
        Some(capacity as usize)
    };
    let result =
        kernel
            .registry
            .reg_query_value_exw(raw_arg(args, 0), value_name.as_deref(), data_capacity);
    if let Some(value_type) = result.value_type {
        if !write_optional_u32(kernel, memory, thread_id, raw_arg(args, 3), value_type) {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        }
    }
    if !write_optional_u32(kernel, memory, thread_id, data_len_ptr, result.required_len) {
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    }
    if result.status == crate::ce::registry::ERROR_SUCCESS {
        if let Some(data) = result.data {
            if raw_arg(args, 4) != 0
                && !write_guest_bytes(kernel, memory, thread_id, raw_arg(args, 4), &data)
            {
                return crate::ce::registry::ERROR_INVALID_PARAMETER;
            }
        }
    }
    result.status
}

fn reg_query_info_key_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let result = kernel.registry.reg_query_info_key_w(raw_arg(args, 0));
    if result.status != crate::ce::registry::ERROR_SUCCESS {
        return result.status;
    }
    for (arg_index, value) in [
        (4, result.subkeys),
        (5, result.max_subkey_chars),
        (7, result.values),
        (8, result.max_value_name_chars),
        (9, result.max_value_data_len),
    ] {
        if !write_optional_u32(kernel, memory, thread_id, raw_arg(args, arg_index), value) {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        }
    }
    result.status
}

fn reg_enum_value_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let name_len_ptr = raw_arg(args, 3);
    let name_capacity = if name_len_ptr == 0 {
        None
    } else {
        let Some(capacity) = read_guest_u32(kernel, memory, thread_id, name_len_ptr) else {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        };
        Some(capacity as usize)
    };
    let data_len_ptr = raw_arg(args, 7);
    let data_capacity = if data_len_ptr == 0 {
        None
    } else {
        let Some(capacity) = read_guest_u32(kernel, memory, thread_id, data_len_ptr) else {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        };
        Some(capacity as usize)
    };
    let result = kernel.registry.reg_enum_value_w(
        raw_arg(args, 0),
        raw_arg(args, 1),
        name_capacity,
        data_capacity,
    );
    if let Some(value_type) = result.value_type {
        if !write_optional_u32(kernel, memory, thread_id, raw_arg(args, 5), value_type) {
            return crate::ce::registry::ERROR_INVALID_PARAMETER;
        }
    }
    if !write_optional_u32(
        kernel,
        memory,
        thread_id,
        name_len_ptr,
        result.required_name_chars,
    ) || !write_optional_u32(
        kernel,
        memory,
        thread_id,
        data_len_ptr,
        result.required_data_len,
    ) {
        return crate::ce::registry::ERROR_INVALID_PARAMETER;
    }
    if result.status == crate::ce::registry::ERROR_SUCCESS {
        if let Some(name) = result.name {
            if raw_arg(args, 2) != 0
                && write_wide_result(
                    kernel,
                    memory,
                    thread_id,
                    raw_arg(args, 2),
                    name_capacity.unwrap_or(0),
                    &name,
                ) == 0
            {
                return crate::ce::registry::ERROR_INVALID_PARAMETER;
            }
        }
        if let Some(data) = result.data {
            if raw_arg(args, 6) != 0
                && !write_guest_bytes(kernel, memory, thread_id, raw_arg(args, 6), &data)
            {
                return crate::ce::registry::ERROR_INVALID_PARAMETER;
            }
        }
    }
    result.status
}

