const PAGE_READWRITE: u32 = 0x04;
const MEM_COMMIT_FLAG: u32 = 0x0000_1000;
const MEM_FREE_FLAG: u32 = 0x0001_0000;
const PAGE_NOACCESS: u32 = 0x01;

fn virtual_query_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    // For VirtualQuery: (lpAddress, lpBuffer, dwLength)
    // For VirtualQueryEx: (hProcess, lpAddress, lpBuffer, dwLength)
    let (addr, buf_ptr, buf_len) = if args.len() >= 4 {
        (raw_arg(args, 1), raw_arg(args, 2), raw_arg(args, 3))
    } else {
        (raw_arg(args, 0), raw_arg(args, 1), raw_arg(args, 2))
    };
    // MEMORY_BASIC_INFORMATION is 28 bytes:
    //   BaseAddress(4), AllocationBase(4), AllocationProtect(4),
    //   RegionSize(4), State(4), Protect(4), Type(4)
    const MBI_SIZE: u32 = 28;
    if buf_ptr == 0 || buf_len < MBI_SIZE {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    // Determine region state based on whether addr falls within a known virtual allocation.
    let (state, protect, region_size) = kernel
        .memory
        .virtual_allocations()
        .find(|a| addr >= a.base && addr < a.base.saturating_add(a.size))
        .map(|a| (MEM_COMMIT_FLAG, a.protect, a.size))
        .unwrap_or((MEM_FREE_FLAG, PAGE_NOACCESS, 0x1000));
    let page_base = addr & !0xfff;
    let writes = [
        (buf_ptr, page_base),             // BaseAddress
        (buf_ptr + 4, page_base),         // AllocationBase
        (buf_ptr + 8, protect),           // AllocationProtect
        (buf_ptr + 12, region_size),      // RegionSize
        (buf_ptr + 16, state),            // State
        (buf_ptr + 20, protect),          // Protect
        (buf_ptr + 24, 0x20000u32),       // Type = MEM_PRIVATE
    ];
    for (offset, value) in writes {
        if !write_guest_u32(kernel, memory, thread_id, offset, value) {
            return 0;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    MBI_SIZE
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PointerProbe {
    Read,
    Write,
}

fn is_bad_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    ptr: u32,
    bytes: u32,
    probe: PointerProbe,
) -> bool {
    if bytes == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    if ptr == 0 || ptr.checked_add(bytes).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return true;
    }
    if let Some(valid) = kernel.memory.heap_range_status(ptr, bytes) {
        kernel
            .threads
            .set_last_error(thread_id, if valid { 0 } else { ERROR_INVALID_PARAMETER });
        return !valid;
    }
    if kernel.memory.contains_allocated_range(ptr, bytes) {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    if probe_guest_range(memory, ptr, bytes, probe) {
        kernel.threads.set_last_error(thread_id, 0);
        false
    } else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        true
    }
}

fn probe_guest_range<M: CoredllGuestMemory>(
    memory: &mut M,
    ptr: u32,
    bytes: u32,
    probe: PointerProbe,
) -> bool {
    let end = ptr + bytes - 1;
    let mut addr = ptr;
    loop {
        if !probe_guest_byte(memory, addr, probe) {
            return false;
        }
        if addr == end {
            return true;
        }
        let next_page = (addr & !0xfff).saturating_add(0x1000);
        let next = next_page.min(end);
        if next == addr {
            return true;
        }
        addr = next;
    }
}

fn probe_guest_byte<M: CoredllGuestMemory>(memory: &mut M, addr: u32, probe: PointerProbe) -> bool {
    let Ok(value) = memory.read_u8(addr) else {
        return false;
    };
    match probe {
        PointerProbe::Read => true,
        PointerProbe::Write => memory.write_u8(addr, value).is_ok(),
    }
}

fn create_file_mapping_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    const INVALID_HANDLE_VALUE: u32 = 0xffff_ffff;

    let file_handle = raw_arg(args, 0);
    let protect = raw_arg(args, 2);
    let size_high = raw_arg(args, 3);
    let size_low = raw_arg(args, 4);
    if size_high != 0 || size_low == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let name = read_optional_guest_wide_arg(memory, raw_arg(args, 5)).and_then(|name| name);
    let file_id = if file_handle == 0 || file_handle == INVALID_HANDLE_VALUE {
        None
    } else {
        let Ok(KernelObject::File(file)) = kernel.handles.get(file_handle) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        Some(file.file_id)
    };
    let handle = kernel
        .handles
        .create_file_mapping(name, size_low.max(1), protect, file_id);
    kernel.threads.set_last_error(thread_id, 0);
    handle
}

fn map_view_of_file_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    mapping_handle: u32,
    offset_high: u32,
    offset_low: u32,
    bytes_to_map: u32,
) -> u32 {
    const MEM_COMMIT: u32 = 0x0000_1000;
    const MEM_RESERVE: u32 = 0x0000_2000;
    const PAGE_READWRITE: u32 = 0x04;

    if offset_high != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(mapping) = kernel.handles.file_mapping(mapping_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    if offset_low >= mapping.size {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let remaining = mapping.size - offset_low;
    let size = if bytes_to_map == 0 {
        remaining
    } else {
        bytes_to_map.min(remaining)
    };
    if size == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let file_id = mapping.file_id;
    let mut initial_bytes = if let Some(file_id) = file_id {
        match kernel.read_file_at(file_id, offset_low as usize, size as usize) {
            Ok(mut bytes) => {
                bytes.resize(size as usize, 0);
                bytes
            }
            Err(_) => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            }
        }
    } else {
        let start = offset_low as usize;
        let end = start.saturating_add(size as usize).min(mapping.data.len());
        let mut bytes = if start < mapping.data.len() {
            mapping.data[start..end].to_vec()
        } else {
            Vec::new()
        };
        bytes.resize(size as usize, 0);
        bytes
    };
    let mapping_bytes = initial_bytes.clone();
    let Some(base) = kernel
        .memory
        .virtual_alloc(0, size, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    kernel
        .memory
        .set_virtual_initial_bytes(base, std::mem::take(&mut initial_bytes));
    try_seed_guest_bytes(memory, base, &mapping_bytes);
    let Ok(mapping) = kernel.handles.file_mapping_mut(mapping_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let start = offset_low as usize;
    let end = start.saturating_add(mapping_bytes.len());
    if end > mapping.data.len() {
        mapping.data.resize(end, 0);
    }
    mapping.data[start..end].copy_from_slice(&mapping_bytes);
    mapping.views.push(FileMappingView {
        base,
        size,
        offset: offset_low,
    });
    kernel.threads.set_last_error(thread_id, 0);
    base
}

fn try_seed_guest_bytes<M: CoredllGuestMemory>(memory: &mut M, base: u32, bytes: &[u8]) {
    for (offset, byte) in bytes.iter().copied().enumerate() {
        if memory
            .write_u8(base.wrapping_add(offset as u32), byte)
            .is_err()
        {
            break;
        }
    }
}

fn flush_view_of_file_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    base: u32,
    bytes_to_flush: u32,
) -> bool {
    let Some((mapping, view)) = kernel
        .handles
        .file_mapping_view(base)
        .map(|(mapping, view)| (mapping.clone(), view))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    let count = if bytes_to_flush == 0 {
        view.size
    } else {
        bytes_to_flush.min(view.size)
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, base, count) else {
        return false;
    };
    let (views, data) = if let Some((mapping, view)) = kernel.handles.file_mapping_by_view_mut(base)
    {
        let start = view.offset as usize;
        let end = start.saturating_add(bytes.len());
        if end > mapping.data.len() {
            mapping.data.resize(end, 0);
        }
        mapping.data[start..end].copy_from_slice(&bytes);
        (mapping.views.clone(), mapping.data.clone())
    } else {
        (Vec::new(), Vec::new())
    };
    sync_file_mapping_views_to_guest(memory, base, &views, &data);
    let Some(file_id) = mapping.file_id else {
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    };
    match kernel.write_file_at(file_id, view.offset as usize, &bytes) {
        Ok(result) if result.success && result.bytes_transferred == count => {
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn sync_file_mapping_views_to_guest<M: CoredllGuestMemory>(
    memory: &mut M,
    source_base: u32,
    views: &[FileMappingView],
    data: &[u8],
) {
    for view in views
        .iter()
        .copied()
        .filter(|view| view.base != source_base)
    {
        let start = view.offset as usize;
        let end = start.saturating_add(view.size as usize).min(data.len());
        if start >= end {
            continue;
        }
        try_seed_guest_bytes(memory, view.base, &data[start..end]);
    }
}

fn unmap_view_of_file_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    base: u32,
) -> bool {
    let Some((mapping, view)) = kernel
        .handles
        .file_mapping_view(base)
        .map(|(mapping, view)| (mapping.clone(), view))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, base, view.size) else {
        return false;
    };
    let (views, data) = if let Some((mapping, view)) = kernel.handles.file_mapping_by_view_mut(base)
    {
        let start = view.offset as usize;
        let end = start.saturating_add(bytes.len());
        if end > mapping.data.len() {
            mapping.data.resize(end, 0);
        }
        mapping.data[start..end].copy_from_slice(&bytes);
        (mapping.views.clone(), mapping.data.clone())
    } else {
        (Vec::new(), Vec::new())
    };
    sync_file_mapping_views_to_guest(memory, base, &views, &data);
    if let Some(file_id) = mapping.file_id {
        let _ = kernel.write_file_at(file_id, view.offset as usize, &bytes);
    }
    if kernel.handles.remove_file_mapping_view(base).is_some() {
        let _ = kernel.memory.virtual_free(base, 0, MEM_RELEASE);
        kernel.threads.set_last_error(thread_id, 0);
        true
    } else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        false
    }
}

fn create_mutex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let name_ptr = raw_arg(args, 2);
    let name = if name_ptr == 0 {
        None
    } else {
        let Some(name) = read_guest_wide_arg(memory, name_ptr) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        Some(name)
    };
    let owner = (raw_arg(args, 1) != 0).then_some(thread_id);
    let (handle, existed) = kernel.create_mutex_w_with_status(name, owner);
    kernel
        .threads
        .set_last_error(thread_id, if existed { ERROR_ALREADY_EXISTS } else { 0 });
    handle
}

