fn set_window_long_w_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> u32 {
    let hwnd = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let value = raw_arg(args, 2);
    set_window_long_traced(kernel, thread_id, hwnd, index, value)
}

fn set_window_long_traced(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    index: i32,
    value: u32,
) -> u32 {
    let class_name = kernel
        .gwe
        .window(hwnd)
        .map(|window| window.class_name.clone());
    let previous = kernel.gwe.set_window_long(hwnd, index, value).unwrap_or(0);
    if index == GWL_STYLE {
        kernel.record_window_lifecycle_trace(
            "set_window_long_style",
            thread_id,
            Some(hwnd),
            Some(previous),
            Some(format!(
                "previous=0x{previous:08x}/value=0x{value:08x}/prev_visible={}/new_visible={}",
                previous & WS_VISIBLE != 0,
                value & WS_VISIBLE != 0
            )),
        );
    }
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{hwnd:08x}"),
        index,
        index_name = window_long_index_name(index),
        value = format_args!("0x{value:08x}"),
        previous = format_args!("0x{previous:08x}"),
        class = class_name.as_deref().unwrap_or("<invalid>"),
        "SetWindowLongW"
    );
    previous
}

fn get_window_long_w_raw(kernel: &mut CeKernel, args: &[u32]) -> u32 {
    let hwnd = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let class_name = kernel
        .gwe
        .window(hwnd)
        .map(|window| window.class_name.clone());
    let value = kernel.gwe.get_window_long(hwnd, index).unwrap_or(0);
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{hwnd:08x}"),
        index,
        index_name = window_long_index_name(index),
        value = format_args!("0x{value:08x}"),
        class = class_name.as_deref().unwrap_or("<invalid>"),
        "GetWindowLongW"
    );
    value
}

// Maps a GCL_* index to a byte offset in our 40-byte WNDCLASSW storage.
// Layout (see register_class_w_raw): style[0], wndproc[4], cbClsExtra[8],
// cbWndExtra[12], hInstance[16], hIcon[20], hCursor[24], hbrBackground[28],
// menuname[32], classname[36].
fn gcl_to_byte_offset(index: i32) -> Option<usize> {
    match index {
        -26 => Some(0),  // GCL_STYLE
        -24 => Some(4),  // GCL_WNDPROC
        -20 => Some(8),  // GCL_CBCLSEXTRA
        -18 => Some(12), // GCL_CBWNDEXTRA
        -16 => Some(16), // GCL_HMODULE
        -14 => Some(20), // GCL_HICON
        -12 => Some(24), // GCL_HCURSOR
        -10 => Some(28), // GCL_HBRBACKGROUND
        -8 => Some(32),  // GCL_MENUNAME
        _ => None,
    }
}

fn get_class_long_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, index: i32) -> u32 {
    let Some(class_name) = kernel.gwe.window(hwnd).map(|w| w.class_name.clone()) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(class) = kernel.gwe.registered_class(&class_name) else {
        kernel.threads.set_last_error(thread_id, ERROR_CLASS_DOES_NOT_EXIST);
        return 0;
    };
    let Some(byte_off) = gcl_to_byte_offset(index) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_INDEX);
        return 0;
    };
    let bytes = &class.bytes;
    kernel.threads.set_last_error(thread_id, 0);
    u32::from_le_bytes([bytes[byte_off], bytes[byte_off + 1], bytes[byte_off + 2], bytes[byte_off + 3]])
}

fn set_class_long_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    index: i32,
    value: u32,
) -> u32 {
    let Some(class_name) = kernel.gwe.window(hwnd).map(|w| w.class_name.clone()) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(byte_off) = gcl_to_byte_offset(index) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_INDEX);
        return 0;
    };
    let Some(class) = kernel.gwe.registered_class_mut(&class_name) else {
        kernel.threads.set_last_error(thread_id, ERROR_CLASS_DOES_NOT_EXIST);
        return 0;
    };
    let bytes = &mut class.bytes;
    let old = u32::from_le_bytes([bytes[byte_off], bytes[byte_off + 1], bytes[byte_off + 2], bytes[byte_off + 3]]);
    let new_bytes = value.to_le_bytes();
    bytes[byte_off..byte_off + 4].copy_from_slice(&new_bytes);
    kernel.threads.set_last_error(thread_id, 0);
    old
}

fn window_long_index_name(index: i32) -> &'static str {
    match index {
        crate::ce::gwe::GWL_WNDPROC => "GWL_WNDPROC",
        crate::ce::gwe::GWL_ID => "GWL_ID",
        crate::ce::gwe::GWL_STYLE => "GWL_STYLE",
        crate::ce::gwe::GWL_EXSTYLE => "GWL_EXSTYLE",
        crate::ce::gwe::GWL_USERDATA => "GWL_USERDATA",
        crate::ce::gwe::DWL_MSGRESULT => "DWL_MSGRESULT",
        crate::ce::gwe::DWL_DLGPROC => "DWL_DLGPROC",
        crate::ce::gwe::DWL_USER => "DWL_USER",
        _ => "<unknown>",
    }
}

fn create_dialog_indirect_param_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let template_ptr = raw_arg(args, 1);
    let parent = (raw_arg(args, 2) != 0).then_some(raw_arg(args, 2));
    let dlgproc = raw_arg(args, 3);
    if template_ptr == 0 || dlgproc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(template) = read_dialog_template(kernel, memory, thread_id, template_ptr) else {
        return 0;
    };
    let hwnd = kernel.gwe.create_window_ex_with_process_and_rect(
        thread_id,
        kernel.current_process_id(),
        "Dialog",
        &template.title,
        parent,
        0,
        template.style,
        template.ex_style,
        Rect::from_origin_size(template.x, template.y, template.cx, template.cy),
    );
    kernel
        .gwe
        .set_window_long(hwnd, crate::ce::gwe::GWL_WNDPROC, dlgproc);
    for control in template.controls {
        let control_hwnd = kernel.gwe.create_window_ex_with_process_and_rect(
            thread_id,
            kernel.current_process_id(),
            &control.class_name,
            &control.title,
            Some(hwnd),
            control.id,
            control.style,
            control.ex_style,
            Rect::from_origin_size(control.x, control.y, control.cx, control.cy),
        );
        if control.class_name.eq_ignore_ascii_case("button") && control.title.is_empty() {
            kernel.gwe.set_window_text(control_hwnd, "Button");
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    hwnd
}

fn end_dialog_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, result: u32) -> bool {
    if !kernel.end_dialog(thread_id, hwnd, result) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

