fn track_popup_menu_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let menu = raw_arg(args, 0);
    if kernel.resources.menu(menu).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let hwnd = raw_arg(args, 4);
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    let lptpm = raw_arg(args, 5);
    let exclude_rect = if lptpm == 0 {
        None
    } else {
        let Some(cb_size) = read_guest_u32(kernel, memory, thread_id, lptpm) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        if cb_size < TPMPARAMS_SIZE {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
        let Some(rect) = read_guest_rect(kernel, memory, thread_id, lptpm.wrapping_add(4)) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        Some([rect.left, rect.top, rect.right, rect.bottom])
    };
    let flags = raw_arg(args, 1);
    let tracking = PopupMenuTracking {
        menu,
        flags,
        x: raw_i32_arg(args, 2),
        y: raw_i32_arg(args, 3),
        hwnd,
        exclude_rect,
    };
    if !kernel.resources.track_popup_menu(tracking) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let initial_hilite = popup_menu_initial_key_index(&kernel.resources, menu);
    let _ = kernel.resources.set_menu_hilite_index(menu, initial_hilite);
    let mut framebuffer = framebuffer;
    if let Some(framebuffer) = framebuffer.as_mut() {
        render_popup_menu_framebuffer(
            *framebuffer,
            &kernel.resources,
            menu,
            raw_i32_arg(args, 2),
            raw_i32_arg(args, 3),
        );
    }
    kernel.threads.set_last_error(thread_id, 0);
    let cursor = kernel.gwe.get_cursor_pos();
    let modal_input = popup_menu_modal_input_selection(
        kernel,
        thread_id,
        hwnd,
        menu,
        flags,
        raw_i32_arg(args, 2),
        raw_i32_arg(args, 3),
        &mut framebuffer,
    );
    let cancelled = matches!(modal_input, Some(PopupMenuModalInput::Cancelled));
    let selection = match modal_input {
        Some(PopupMenuModalInput::Selected(selection)) => Some(selection),
        Some(PopupMenuModalInput::Cancelled) => None,
        None => popup_menu_pointer_selection(
            &kernel.resources,
            menu,
            raw_i32_arg(args, 2),
            raw_i32_arg(args, 3),
            cursor,
        )
        .or_else(|| kernel.resources.popup_menu_command_selection(menu)),
    };
    let command = selection
        .as_ref()
        .map(|selection| selection.command)
        .unwrap_or(0);
    let submenus = selection
        .as_ref()
        .map(|selection| selection.submenus.as_slice())
        .unwrap_or(&[]);
    notify_popup_menu_owner(kernel, hwnd, menu, flags, submenus);
    if cancelled {
        return 0;
    }
    if flags & TPM_RETURNCMD != 0 {
        command
    } else {
        notify_popup_menu_command(kernel, hwnd, flags, command);
        1
    }
}

fn notify_popup_menu_owner(
    kernel: &mut CeKernel,
    hwnd: u32,
    menu: u32,
    flags: u32,
    submenus: &[u32],
) {
    if hwnd == 0 || flags & TPM_NONOTIFY != 0 {
        return;
    }
    let mut notifications = vec![
        (crate::ce::gwe::WM_ENTERMENULOOP, 1, 0),
        (crate::ce::gwe::WM_INITMENUPOPUP, menu, 0),
    ];
    notifications.extend(
        submenus
            .iter()
            .copied()
            .enumerate()
            .map(|(index, submenu)| {
                (
                    crate::ce::gwe::WM_INITMENUPOPUP,
                    submenu,
                    index.saturating_add(1) as u32,
                )
            }),
    );
    notifications.push((crate::ce::gwe::WM_EXITMENULOOP, 1, 0));
    for (msg, wparam, lparam) in notifications {
        kernel
            .resources
            .record_popup_notification(PopupMenuNotification {
                hwnd,
                msg,
                wparam,
                lparam,
            });
        let _ = kernel.send_message_w(hwnd, msg, wparam, lparam);
    }
}

fn notify_popup_menu_command(kernel: &mut CeKernel, hwnd: u32, flags: u32, command: u32) {
    if hwnd == 0 || command == 0 || flags & TPM_NONOTIFY != 0 {
        return;
    }
    kernel
        .resources
        .record_popup_notification(PopupMenuNotification {
            hwnd,
            msg: crate::ce::gwe::WM_COMMAND,
            wparam: command,
            lparam: 0,
        });
    let _ = kernel.send_message_w(hwnd, crate::ce::gwe::WM_COMMAND, command, 0);
}

#[derive(Debug, Clone)]
enum PopupMenuModalInput {
    Selected(PopupMenuCommandSelection),
    Cancelled,
}

#[derive(Debug, Clone)]
struct PopupMenuModalMenuState {
    menu: u32,
    popup_x: i32,
    popup_y: i32,
    current: Option<usize>,
}

#[derive(Debug, Clone)]
#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) struct PopupMenuModalState {
    hwnd: u32,
    menu: u32,
    flags: u32,
    popup_x: i32,
    popup_y: i32,
    pub(crate) mouse_message_max: u32,
    cursor: Point,
    stack: Vec<PopupMenuModalMenuState>,
}

#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) fn track_popup_menu_ex_prepare<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> std::result::Result<PopupMenuModalState, u32> {
    let menu = raw_arg(args, 0);
    if kernel.resources.menu(menu).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return Err(0);
    }
    let hwnd = raw_arg(args, 4);
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return Err(0);
    }
    let lptpm = raw_arg(args, 5);
    let exclude_rect = if lptpm == 0 {
        None
    } else {
        let Some(cb_size) = read_guest_u32(kernel, memory, thread_id, lptpm) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return Err(0);
        };
        if cb_size < TPMPARAMS_SIZE {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return Err(0);
        }
        let Some(rect) = read_guest_rect(kernel, memory, thread_id, lptpm.wrapping_add(4)) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return Err(0);
        };
        Some([rect.left, rect.top, rect.right, rect.bottom])
    };
    let flags = raw_arg(args, 1);
    let popup_x = raw_i32_arg(args, 2);
    let popup_y = raw_i32_arg(args, 3);
    let tracking = PopupMenuTracking {
        menu,
        flags,
        x: popup_x,
        y: popup_y,
        hwnd,
        exclude_rect,
    };
    if !kernel.resources.track_popup_menu(tracking) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return Err(0);
    }
    let initial_hilite = popup_menu_initial_key_index(&kernel.resources, menu);
    let _ = kernel.resources.set_menu_hilite_index(menu, initial_hilite);
    let mut framebuffer = framebuffer;
    if let Some(framebuffer) = framebuffer.as_mut() {
        render_popup_menu_framebuffer(*framebuffer, &kernel.resources, menu, popup_x, popup_y);
    }
    kernel.threads.set_last_error(thread_id, 0);
    let cursor = kernel.gwe.get_cursor_pos();
    let mouse_message_max = if flags & TPM_RIGHTBUTTON != 0 {
        crate::ce::gwe::WM_RBUTTONUP
    } else {
        crate::ce::gwe::WM_LBUTTONUP
    };
    if hwnd == 0 {
        let selection = popup_menu_pointer_selection(
            &kernel.resources,
            menu,
            popup_x,
            popup_y,
            cursor,
        )
        .or_else(|| kernel.resources.popup_menu_command_selection(menu));
        let command = selection.as_ref().map(|s| s.command).unwrap_or(0);
        let submenus = selection
            .as_ref()
            .map(|s| s.submenus.as_slice())
            .unwrap_or(&[]);
        notify_popup_menu_owner(kernel, hwnd, menu, flags, submenus);
        let result = if flags & TPM_RETURNCMD != 0 {
            command
        } else {
            notify_popup_menu_command(kernel, hwnd, flags, command);
            1
        };
        return Err(result);
    }
    let mut stack = vec![PopupMenuModalMenuState {
        menu,
        popup_x,
        popup_y,
        current: popup_menu_initial_key_index(&kernel.resources, menu),
    }];
    let initial_current = stack[0].current;
    popup_menu_set_current_index(
        kernel,
        menu,
        &mut stack[0].current,
        initial_current,
        &mut framebuffer,
        popup_x,
        popup_y,
    );
    Ok(PopupMenuModalState {
        hwnd,
        menu,
        flags,
        popup_x,
        popup_y,
        mouse_message_max,
        cursor,
        stack,
    })
}

#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
impl PopupMenuModalState {
    pub(crate) fn owner_hwnd(&self) -> u32 {
        self.hwnd
    }

    pub(crate) fn poll_once(
        mut self,
        kernel: &mut CeKernel,
        thread_id: u32,
        framebuffer: &mut Option<&mut dyn Framebuffer>,
    ) -> std::result::Result<u32, Self> {
        match popup_menu_modal_input_loop(
            kernel,
            thread_id,
            self.hwnd,
            self.menu,
            self.popup_x,
            self.popup_y,
            self.mouse_message_max,
            framebuffer,
            &mut self.stack,
        ) {
            Some(input) => Ok(self.finalize(kernel, input)),
            None => Err(self),
        }
    }

    fn finalize(self, kernel: &mut CeKernel, input: PopupMenuModalInput) -> u32 {
        let cancelled = matches!(input, PopupMenuModalInput::Cancelled);
        let selection = match input {
            PopupMenuModalInput::Selected(sel) => Some(sel),
            PopupMenuModalInput::Cancelled => None,
        };
        let command = selection.as_ref().map(|s| s.command).unwrap_or(0);
        let submenus = selection
            .as_ref()
            .map(|s| s.submenus.as_slice())
            .unwrap_or(&[]);
        notify_popup_menu_owner(kernel, self.hwnd, self.menu, self.flags, submenus);
        if cancelled {
            return 0;
        }
        if self.flags & TPM_RETURNCMD != 0 {
            command
        } else {
            notify_popup_menu_command(kernel, self.hwnd, self.flags, command);
            1
        }
    }
}

const POPUP_MENU_ITEM_HEIGHT: i32 = 18;
const POPUP_MENU_BORDER: i32 = 2;
const POPUP_MENU_VERTICAL_PADDING: i32 = POPUP_MENU_BORDER * 2;

fn popup_menu_modal_input_loop(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    menu: u32,
    popup_x: i32,
    popup_y: i32,
    mouse_message_max: u32,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
    mut stack: &mut Vec<PopupMenuModalMenuState>,
) -> Option<PopupMenuModalInput> {
    const VK_RETURN: u32 = 0x0d;
    const VK_ESCAPE: u32 = 0x1b;
    const VK_LEFT: u32 = 0x25;
    const VK_UP: u32 = 0x26;
    const VK_RIGHT: u32 = 0x27;
    const VK_DOWN: u32 = 0x28;

    let modal_message_min = crate::ce::gwe::WM_PAINT;
    loop {
        let Some(message) = kernel.gwe.peek_message_filtered(
            thread_id,
            None,
            modal_message_min,
            mouse_message_max,
            PeekFlags::NO_REMOVE,
        ) else {
            return None;
        };
        if message.hwnd != hwnd {
            let Some(message) = kernel.gwe.peek_message_filtered(
                thread_id,
                None,
                modal_message_min,
                mouse_message_max,
                PeekFlags::REMOVE,
            ) else {
                continue;
            };
            kernel.dispatch_message_w_for_thread(thread_id, message);
            continue;
        }
        match message.msg {
            crate::ce::gwe::WM_CANCELMODE => {
                let _ = kernel.gwe.peek_message_filtered(
                    thread_id,
                    None,
                    modal_message_min,
                    mouse_message_max,
                    PeekFlags::REMOVE,
                );
            }
            crate::ce::gwe::WM_KEYDOWN
                if matches!(
                    message.wparam,
                    VK_LEFT | VK_UP | VK_RIGHT | VK_DOWN | VK_RETURN | VK_ESCAPE
                ) =>
            {
                let _ = kernel.gwe.peek_message_filtered(
                    thread_id,
                    None,
                    modal_message_min,
                    mouse_message_max,
                    PeekFlags::REMOVE,
                );
            }
            crate::ce::gwe::WM_CHAR => {
                let _ = kernel.gwe.peek_message_filtered(
                    thread_id,
                    None,
                    modal_message_min,
                    mouse_message_max,
                    PeekFlags::REMOVE,
                );
            }
            crate::ce::gwe::WM_LBUTTONDOWN
            | crate::ce::gwe::WM_LBUTTONUP
            | crate::ce::gwe::WM_MOUSEMOVE
            | crate::ce::gwe::WM_RBUTTONDOWN
            | crate::ce::gwe::WM_RBUTTONUP => {
                let _ = kernel.gwe.peek_message_filtered(
                    thread_id,
                    None,
                    modal_message_min,
                    mouse_message_max,
                    PeekFlags::REMOVE,
                );
            }
            _ => {
                let Some(message) = kernel.gwe.peek_message_filtered(
                    thread_id,
                    None,
                    modal_message_min,
                    mouse_message_max,
                    PeekFlags::REMOVE,
                ) else {
                    continue;
                };
                kernel.dispatch_message_w_for_thread(thread_id, message);
                continue;
            }
        }
        match (message.msg, message.wparam) {
            (crate::ce::gwe::WM_CANCELMODE, _) => return Some(PopupMenuModalInput::Cancelled),
            (crate::ce::gwe::WM_MOUSEMOVE, _) => {
                let point = popup_menu_lparam_point(message.lparam);
                if let Some((level_index, item_index)) =
                    popup_menu_modal_pointer_index(&kernel.resources, &stack, point)
                {
                    popup_menu_modal_truncate_stack(
                        kernel,
                        &mut stack,
                        level_index + 1,
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                    let active = stack.last_mut().unwrap();
                    popup_menu_set_current_index(
                        kernel,
                        active.menu,
                        &mut active.current,
                        Some(item_index),
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                }
            }
            (crate::ce::gwe::WM_LBUTTONDOWN | crate::ce::gwe::WM_RBUTTONDOWN, _) => {
                let point = popup_menu_lparam_point(message.lparam);
                if let Some((level_index, item_index)) =
                    popup_menu_modal_pointer_index(&kernel.resources, &stack, point)
                {
                    popup_menu_modal_truncate_stack(
                        kernel,
                        &mut stack,
                        level_index + 1,
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                    let active = stack.last_mut().unwrap();
                    popup_menu_set_current_index(
                        kernel,
                        active.menu,
                        &mut active.current,
                        Some(item_index),
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                }
            }
            (crate::ce::gwe::WM_LBUTTONUP | crate::ce::gwe::WM_RBUTTONUP, _) => {
                let point = popup_menu_lparam_point(message.lparam);
                if let Some((level_index, item_index)) =
                    popup_menu_modal_pointer_index(&kernel.resources, &stack, point)
                {
                    popup_menu_modal_truncate_stack(
                        kernel,
                        &mut stack,
                        level_index + 1,
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                    let active = stack.last_mut().unwrap();
                    popup_menu_set_current_index(
                        kernel,
                        active.menu,
                        &mut active.current,
                        Some(item_index),
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                }
                if let Some(selection) =
                    popup_menu_pointer_selection(&kernel.resources, menu, popup_x, popup_y, point)
                {
                    return Some(PopupMenuModalInput::Selected(selection));
                }
                return Some(PopupMenuModalInput::Cancelled);
            }
            (crate::ce::gwe::WM_CHAR, VK_RETURN) => {
                let active = stack.last().unwrap();
                if let Some(index) = active.current {
                    if let Some(selection) =
                        popup_menu_modal_key_index_selection(&kernel.resources, &stack, index)
                    {
                        return Some(PopupMenuModalInput::Selected(selection));
                    }
                }
                return None;
            }
            (crate::ce::gwe::WM_CHAR, VK_ESCAPE) => {
                if popup_menu_modal_close_submenu(kernel, &mut stack, framebuffer, popup_x, popup_y)
                {
                    continue;
                }
                return Some(PopupMenuModalInput::Cancelled);
            }
            (crate::ce::gwe::WM_CHAR, ch) => {
                let active_menu = stack.last().unwrap().menu;
                if let Some(index) = popup_menu_mnemonic_index(&kernel.resources, active_menu, ch) {
                    let active = stack.last_mut().unwrap();
                    popup_menu_set_current_index(
                        kernel,
                        active.menu,
                        &mut active.current,
                        Some(index),
                        framebuffer,
                        popup_x,
                        popup_y,
                    );
                    if let Some(selection) =
                        popup_menu_modal_key_index_selection(&kernel.resources, &stack, index)
                    {
                        return Some(PopupMenuModalInput::Selected(selection));
                    }
                }
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_UP) => {
                let active = stack.last_mut().unwrap();
                let next = popup_menu_relative_key_index(
                    &kernel.resources,
                    active.menu,
                    active.current,
                    -1,
                )
                .or(active.current);
                popup_menu_set_current_index(
                    kernel,
                    active.menu,
                    &mut active.current,
                    next,
                    framebuffer,
                    popup_x,
                    popup_y,
                );
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_DOWN) => {
                let active = stack.last_mut().unwrap();
                let next = popup_menu_relative_key_index(
                    &kernel.resources,
                    active.menu,
                    active.current,
                    1,
                )
                .or(active.current);
                popup_menu_set_current_index(
                    kernel,
                    active.menu,
                    &mut active.current,
                    next,
                    framebuffer,
                    popup_x,
                    popup_y,
                );
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_RIGHT) => {
                if popup_menu_modal_open_submenu(kernel, &mut stack, framebuffer, popup_x, popup_y)
                {
                    continue;
                }
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_LEFT) => {
                popup_menu_modal_close_submenu(kernel, &mut stack, framebuffer, popup_x, popup_y);
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_RETURN) => {
                let active = stack.last().unwrap();
                if let Some(index) = active.current {
                    if let Some(selection) =
                        popup_menu_modal_key_index_selection(&kernel.resources, &stack, index)
                    {
                        return Some(PopupMenuModalInput::Selected(selection));
                    }
                }
                return None;
            }
            (crate::ce::gwe::WM_KEYDOWN, VK_ESCAPE) => {
                if popup_menu_modal_close_submenu(kernel, &mut stack, framebuffer, popup_x, popup_y)
                {
                    continue;
                }
                return Some(PopupMenuModalInput::Cancelled);
            }
            _ => unreachable!(),
        }
    }
}

fn popup_menu_modal_input_selection(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    menu: u32,
    flags: u32,
    popup_x: i32,
    popup_y: i32,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
) -> Option<PopupMenuModalInput> {
    if hwnd == 0 {
        return None;
    }
    let mut stack = vec![PopupMenuModalMenuState {
        menu,
        popup_x,
        popup_y,
        current: popup_menu_initial_key_index(&kernel.resources, menu),
    }];
    let initial_current = stack[0].current;
    popup_menu_set_current_index(
        kernel,
        menu,
        &mut stack[0].current,
        initial_current,
        framebuffer,
        popup_x,
        popup_y,
    );
    let mouse_message_max = if flags & TPM_RIGHTBUTTON != 0 {
        crate::ce::gwe::WM_RBUTTONUP
    } else {
        crate::ce::gwe::WM_LBUTTONUP
    };
    popup_menu_modal_input_loop(
        kernel,
        thread_id,
        hwnd,
        menu,
        popup_x,
        popup_y,
        mouse_message_max,
        framebuffer,
        &mut stack,
    )
}

fn popup_menu_modal_pointer_index(
    resources: &ResourceSystem,
    stack: &[PopupMenuModalMenuState],
    point: Point,
) -> Option<(usize, usize)> {
    for (level_index, level) in stack.iter().enumerate().rev() {
        if let Some(item_index) =
            popup_menu_pointer_index(resources, level.menu, level.popup_x, level.popup_y, point)
        {
            return Some((level_index, item_index));
        }
    }
    None
}

fn popup_menu_modal_key_index_selection(
    resources: &ResourceSystem,
    stack: &[PopupMenuModalMenuState],
    index: usize,
) -> Option<PopupMenuCommandSelection> {
    let active = stack.last()?;
    let mut selection = popup_menu_key_index_selection(resources, active.menu, index)?;
    for level in stack.iter().skip(1).rev() {
        selection.submenus.insert(0, level.menu);
    }
    Some(selection)
}

fn popup_menu_modal_open_submenu(
    kernel: &mut CeKernel,
    stack: &mut Vec<PopupMenuModalMenuState>,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
    root_x: i32,
    root_y: i32,
) -> bool {
    let Some(active) = stack.last() else {
        return false;
    };
    let Some(index) = active.current else {
        return false;
    };
    let Some(menu_object) = kernel.resources.menu(active.menu) else {
        return false;
    };
    let Some(item) = menu_object.items.get(index) else {
        return false;
    };
    if !popup_menu_pointer_item_is_enabled(item) || item.submenu == 0 {
        return false;
    }
    let submenu = item.submenu;
    let child_x = active.popup_x + menu_popup_width(menu_object) - POPUP_MENU_BORDER;
    let child_y = active.popup_y + POPUP_MENU_BORDER + (index as i32) * POPUP_MENU_ITEM_HEIGHT;
    let child_current = popup_menu_initial_key_index(&kernel.resources, submenu);
    stack.push(PopupMenuModalMenuState {
        menu: submenu,
        popup_x: child_x,
        popup_y: child_y,
        current: child_current,
    });
    let child = stack.last_mut().unwrap();
    popup_menu_set_current_index(
        kernel,
        child.menu,
        &mut child.current,
        child_current,
        framebuffer,
        root_x,
        root_y,
    );
    true
}

fn popup_menu_modal_truncate_stack(
    kernel: &mut CeKernel,
    stack: &mut Vec<PopupMenuModalMenuState>,
    keep_len: usize,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
    root_x: i32,
    root_y: i32,
) {
    let keep_len = keep_len.max(1).min(stack.len());
    if keep_len == stack.len() {
        return;
    }
    for closed in stack.drain(keep_len..) {
        let _ = kernel.resources.set_menu_hilite_index(closed.menu, None);
    }
    if let Some(framebuffer) = framebuffer.as_mut() {
        render_popup_menu_framebuffer(
            *framebuffer,
            &kernel.resources,
            stack[0].menu,
            root_x,
            root_y,
        );
    }
}

fn popup_menu_modal_close_submenu(
    kernel: &mut CeKernel,
    stack: &mut Vec<PopupMenuModalMenuState>,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
    root_x: i32,
    root_y: i32,
) -> bool {
    if stack.len() <= 1 {
        return false;
    }
    popup_menu_modal_truncate_stack(kernel, stack, stack.len() - 1, framebuffer, root_x, root_y);
    true
}

fn popup_menu_set_current_index(
    kernel: &mut CeKernel,
    menu: u32,
    current: &mut Option<usize>,
    next: Option<usize>,
    framebuffer: &mut Option<&mut dyn Framebuffer>,
    popup_x: i32,
    popup_y: i32,
) {
    *current = next;
    if kernel.resources.set_menu_hilite_index(menu, *current) {
        if let Some(framebuffer) = framebuffer.as_mut() {
            render_popup_menu_framebuffer(*framebuffer, &kernel.resources, menu, popup_x, popup_y);
        }
    }
}

fn popup_menu_lparam_point(lparam: u32) -> Point {
    Point {
        x: (lparam & 0xffff) as i16 as i32,
        y: ((lparam >> 16) & 0xffff) as i16 as i32,
    }
}

fn popup_menu_initial_key_index(resources: &ResourceSystem, menu: u32) -> Option<usize> {
    let menu_object = resources.menu(menu)?;
    menu_object
        .items
        .iter()
        .position(|item| {
            popup_menu_pointer_item_is_enabled(item)
                && item.state & crate::ce::resource::MFS_DEFAULT != 0
        })
        .or_else(|| {
            menu_object
                .items
                .iter()
                .position(popup_menu_pointer_item_is_enabled)
        })
}

fn popup_menu_relative_key_index(
    resources: &ResourceSystem,
    menu: u32,
    current: Option<usize>,
    direction: i32,
) -> Option<usize> {
    let menu_object = resources.menu(menu)?;
    let len = menu_object.items.len();
    if len == 0 {
        return None;
    }
    let start = current.unwrap_or_else(|| if direction < 0 { 0 } else { len - 1 });
    for offset in 1..=len {
        let index = if direction < 0 {
            (start + len - offset) % len
        } else {
            (start + offset) % len
        };
        if menu_object
            .items
            .get(index)
            .is_some_and(popup_menu_pointer_item_is_enabled)
        {
            return Some(index);
        }
    }
    None
}

fn popup_menu_key_index_selection(
    resources: &ResourceSystem,
    menu: u32,
    index: usize,
) -> Option<PopupMenuCommandSelection> {
    let item = resources.menu(menu)?.items.get(index)?;
    if !popup_menu_pointer_item_is_enabled(item) {
        return None;
    }
    if popup_menu_pointer_item_is_command(item) {
        return Some(PopupMenuCommandSelection {
            command: item.id,
            submenus: Vec::new(),
        });
    }
    if item.submenu != 0 {
        let mut selection = resources.popup_menu_command_selection(item.submenu)?;
        selection.submenus.insert(0, item.submenu);
        return Some(selection);
    }
    None
}

fn popup_menu_mnemonic_index(resources: &ResourceSystem, menu: u32, ch: u32) -> Option<usize> {
    let needle = popup_menu_fold_ascii_char(ch)?;
    resources
        .menu(menu)?
        .items
        .iter()
        .enumerate()
        .find(|(_, item)| {
            popup_menu_pointer_item_is_enabled(item)
                && item.text.as_deref().and_then(popup_menu_text_mnemonic) == Some(needle)
        })
        .map(|(index, _)| index)
        .or_else(|| {
            resources
                .menu(menu)?
                .items
                .iter()
                .enumerate()
                .find_map(|(index, item)| {
                    if !popup_menu_pointer_item_is_enabled(item) {
                        return None;
                    }
                    let first = item
                        .text
                        .as_deref()?
                        .chars()
                        .filter(|ch| *ch != '&')
                        .find_map(|ch| popup_menu_fold_ascii_char(ch as u32))?;
                    (first == needle).then_some(index)
                })
        })
}

fn popup_menu_text_mnemonic(text: &str) -> Option<char> {
    let mut chars = text.chars().peekable();
    while let Some(ch) = chars.next() {
        if ch != '&' {
            continue;
        }
        match chars.peek().copied() {
            Some('&') => {
                let _ = chars.next();
            }
            Some(next) => return popup_menu_fold_ascii_char(next as u32),
            None => return None,
        }
    }
    None
}

fn popup_menu_fold_ascii_char(ch: u32) -> Option<char> {
    let byte = u8::try_from(ch).ok()?;
    if !byte.is_ascii_alphanumeric() {
        return None;
    }
    Some(byte.to_ascii_lowercase() as char)
}

fn popup_menu_pointer_index(
    resources: &ResourceSystem,
    menu: u32,
    popup_x: i32,
    popup_y: i32,
    cursor: Point,
) -> Option<usize> {
    let menu_object = resources.menu(menu)?;
    if menu_object.items.is_empty() {
        return None;
    }
    let width = menu_popup_width(menu_object);
    let row_left = popup_x + POPUP_MENU_BORDER;
    let row_top = popup_y + POPUP_MENU_BORDER;
    let row_right = popup_x + width - POPUP_MENU_BORDER;
    let row_bottom =
        row_top + (menu_object.items.len() as i32).saturating_mul(POPUP_MENU_ITEM_HEIGHT);
    if cursor.x < row_left || cursor.x >= row_right || cursor.y < row_top || cursor.y >= row_bottom
    {
        return None;
    }
    let index = ((cursor.y - row_top) / POPUP_MENU_ITEM_HEIGHT) as usize;
    menu_object
        .items
        .get(index)
        .is_some_and(popup_menu_pointer_item_is_enabled)
        .then_some(index)
}

fn popup_menu_pointer_selection(
    resources: &ResourceSystem,
    menu: u32,
    popup_x: i32,
    popup_y: i32,
    cursor: Point,
) -> Option<PopupMenuCommandSelection> {
    let mut visited = BTreeSet::new();
    popup_menu_pointer_selection_inner(resources, menu, popup_x, popup_y, cursor, &mut visited)
}

fn popup_menu_pointer_selection_inner(
    resources: &ResourceSystem,
    menu: u32,
    popup_x: i32,
    popup_y: i32,
    cursor: Point,
    visited: &mut BTreeSet<u32>,
) -> Option<PopupMenuCommandSelection> {
    if !visited.insert(menu) {
        return None;
    }
    if let Some(index) = popup_menu_pointer_index(resources, menu, popup_x, popup_y, cursor) {
        return popup_menu_key_index_selection(resources, menu, index);
    }
    let (submenu, submenu_x, submenu_y) =
        popup_menu_highlighted_submenu_popup(resources, menu, popup_x, popup_y)?;
    let mut selection = popup_menu_pointer_selection_inner(
        resources, submenu, submenu_x, submenu_y, cursor, visited,
    )?;
    selection.submenus.insert(0, submenu);
    Some(selection)
}

fn popup_menu_highlighted_submenu_popup(
    resources: &ResourceSystem,
    menu: u32,
    popup_x: i32,
    popup_y: i32,
) -> Option<(u32, i32, i32)> {
    let menu_object = resources.menu(menu)?;
    let width = menu_popup_width(menu_object);
    menu_object
        .items
        .iter()
        .enumerate()
        .find_map(|(index, item)| {
            let highlighted = item.state & crate::ce::resource::MF_HILITE != 0;
            let enabled = popup_menu_pointer_item_is_enabled(item);
            (highlighted && enabled && item.submenu != 0).then_some((
                item.submenu,
                popup_x + width - POPUP_MENU_BORDER,
                popup_y + POPUP_MENU_BORDER + (index as i32) * POPUP_MENU_ITEM_HEIGHT,
            ))
        })
}

fn popup_menu_pointer_item_is_enabled(item: &MenuItem) -> bool {
    item.item_type & crate::ce::resource::MF_SEPARATOR == 0
        && item.state & (crate::ce::resource::MF_DISABLED | crate::ce::resource::MF_GRAYED) == 0
}

fn popup_menu_pointer_item_is_command(item: &MenuItem) -> bool {
    item.submenu == 0 && item.id != u32::MAX
}

fn render_popup_menu_framebuffer(
    framebuffer: &mut dyn Framebuffer,
    resources: &ResourceSystem,
    menu: u32,
    x: i32,
    y: i32,
) {
    let mut visited = BTreeSet::new();
    render_popup_menu_framebuffer_inner(framebuffer, resources, menu, x, y, &mut visited);
}

fn render_popup_menu_framebuffer_inner(
    framebuffer: &mut dyn Framebuffer,
    resources: &ResourceSystem,
    menu: u32,
    x: i32,
    y: i32,
    visited: &mut BTreeSet<u32>,
) {
    if !visited.insert(menu) {
        return;
    }
    let Some(menu) = resources.menu(menu) else {
        return;
    };
    let item_count = menu.items.len().max(1) as i32;
    let width = menu_popup_width(menu);
    let height = item_count * POPUP_MENU_ITEM_HEIGHT + POPUP_MENU_VERTICAL_PADDING;
    let outer = Rect::from_origin_size(x, y, width, height);
    fill_framebuffer_screen_rect(framebuffer, outer, rgb(0x00, 0x00, 0x00));
    fill_framebuffer_screen_rect(
        framebuffer,
        Rect::from_origin_size(x + 1, y + 1, width - 2, height - 2),
        rgb(0xf0, 0xf0, 0xf0),
    );
    for (index, item) in menu.items.iter().enumerate() {
        let item_top = y + POPUP_MENU_BORDER + (index as i32) * POPUP_MENU_ITEM_HEIGHT;
        let item_rect = Rect::from_origin_size(
            x + POPUP_MENU_BORDER,
            item_top,
            width - POPUP_MENU_VERTICAL_PADDING,
            POPUP_MENU_ITEM_HEIGHT,
        );
        let disabled =
            item.state & (crate::ce::resource::MF_DISABLED | crate::ce::resource::MF_GRAYED) != 0;
        let default = item.state & crate::ce::resource::MFS_DEFAULT != 0;
        let highlighted = item.state & crate::ce::resource::MF_HILITE != 0 && !disabled;
        let separator = item.item_type & crate::ce::resource::MF_SEPARATOR != 0;
        let checked = item.state & crate::ce::resource::MF_CHECKED != 0;
        let has_submenu = item.submenu != 0;
        if highlighted {
            fill_framebuffer_screen_rect(framebuffer, item_rect, rgb(0x33, 0x99, 0xff));
        } else if default {
            fill_framebuffer_screen_rect(framebuffer, item_rect, rgb(0xd8, 0xe8, 0xff));
        }
        if separator {
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(x + 8, item_top + POPUP_MENU_ITEM_HEIGHT / 2, width - 16, 1),
                rgb(0x80, 0x80, 0x80),
            );
            continue;
        }
        if checked {
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(x + 7, item_top + 5, 8, 8),
                rgb(0x00, 0x80, 0x00),
            );
        }
        let text_color = if disabled {
            rgb(0x80, 0x80, 0x80)
        } else if highlighted {
            rgb(0xff, 0xff, 0xff)
        } else {
            rgb(0x00, 0x00, 0x00)
        };
        render_framebuffer_text_marks(
            framebuffer,
            Rect::from_origin_size(x + 22, item_top + 6, width - 42, 7),
            item.text.as_deref().unwrap_or_default(),
            text_color,
        );
        if has_submenu {
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(x + width - 15, item_top + 6, 7, 2),
                text_color,
            );
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(x + width - 12, item_top + 8, 4, 2),
                text_color,
            );
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(x + width - 10, item_top + 10, 2, 2),
                text_color,
            );
            if highlighted {
                render_popup_menu_framebuffer_inner(
                    framebuffer,
                    resources,
                    item.submenu,
                    x + width - POPUP_MENU_BORDER,
                    item_top,
                    visited,
                );
            }
        }
    }
}

fn menu_popup_width(menu: &crate::ce::resource::MenuObject) -> i32 {
    let text_chars = menu
        .items
        .iter()
        .filter_map(|item| item.text.as_deref())
        .map(|text| text.chars().count() as i32)
        .max()
        .unwrap_or(6);
    (text_chars.saturating_mul(4) + 58).clamp(90, 220)
}

fn get_sub_menu_raw(kernel: &mut CeKernel, thread_id: u32, menu: u32, position: u32) -> u32 {
    let submenu = kernel.resources.get_sub_menu(menu, position).unwrap_or(0);
    kernel.threads.set_last_error(
        thread_id,
        if submenu == 0 {
            ERROR_INVALID_PARAMETER
        } else {
            0
        },
    );
    submenu
}

fn get_menu_item_info_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let menu = raw_arg(args, 0);
    let item_or_pos = raw_arg(args, 1);
    let by_position = raw_arg(args, 2) != 0;
    let info_ptr = raw_arg(args, 3);
    let Some(cb_size) = read_guest_u32(kernel, memory, thread_id, info_ptr) else {
        return false;
    };
    if cb_size < MENUITEMINFOW_SIZE {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(mask) = read_guest_u32(kernel, memory, thread_id, info_ptr + 4) else {
        return false;
    };
    let Some(item) = kernel
        .resources
        .get_menu_item(menu, item_or_pos, by_position)
        .cloned()
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    if !write_menu_item_info(kernel, memory, thread_id, info_ptr, mask, &item) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn set_menu_item_info_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let menu = raw_arg(args, 0);
    let item_or_pos = raw_arg(args, 1);
    let by_position = raw_arg(args, 2) != 0;
    let info_ptr = raw_arg(args, 3);
    let Some((mask, patch)) = read_menu_item_info(kernel, memory, thread_id, info_ptr) else {
        return false;
    };
    let Some(mut item) = kernel
        .resources
        .get_menu_item(menu, item_or_pos, by_position)
        .cloned()
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    apply_menu_item_info_mask(&mut item, mask, patch);
    if !kernel
        .resources
        .set_menu_item(menu, item_or_pos, by_position, item)
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn menu_item_from_insert_args<M: CoredllGuestMemory>(
    memory: &M,
    flags: u32,
    id_or_submenu: u32,
    text_ptr: u32,
) -> MenuItem {
    let text = if flags & crate::ce::resource::MF_SEPARATOR != 0 || text_ptr == 0 {
        None
    } else {
        read_guest_wide_arg(memory, text_ptr)
    };
    MenuItem::from_insert_flags(flags, id_or_submenu, text)
}

fn read_menu_item_info<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    info_ptr: u32,
) -> Option<(u32, MenuItem)> {
    let cb_size = read_guest_u32(kernel, memory, thread_id, info_ptr)?;
    if cb_size < MENUITEMINFOW_SIZE {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let mask = read_guest_u32(kernel, memory, thread_id, info_ptr + 4)?;
    let text_ptr = read_guest_u32(kernel, memory, thread_id, info_ptr + 36).unwrap_or(0);
    let text = if menu_info_wants_text(mask) && text_ptr != 0 {
        read_guest_wide_arg(memory, text_ptr)
    } else {
        None
    };
    Some((
        mask,
        MenuItem {
            id: read_guest_u32(kernel, memory, thread_id, info_ptr + 16).unwrap_or(0),
            item_type: read_guest_u32(kernel, memory, thread_id, info_ptr + 8).unwrap_or(0),
            state: read_guest_u32(kernel, memory, thread_id, info_ptr + 12).unwrap_or(0),
            submenu: read_guest_u32(kernel, memory, thread_id, info_ptr + 20).unwrap_or(0),
            checked_bitmap: read_guest_u32(kernel, memory, thread_id, info_ptr + 24).unwrap_or(0),
            unchecked_bitmap: read_guest_u32(kernel, memory, thread_id, info_ptr + 28).unwrap_or(0),
            data: read_guest_u32(kernel, memory, thread_id, info_ptr + 32).unwrap_or(0),
            text,
        },
    ))
}

fn apply_menu_item_info_mask(item: &mut MenuItem, mask: u32, patch: MenuItem) {
    if mask & MIIM_TYPE != 0 {
        item.item_type = patch.item_type;
    }
    if mask & MIIM_STATE != 0 {
        item.state = patch.state;
    }
    if mask & MIIM_ID != 0 {
        item.id = patch.id;
    }
    if mask & MIIM_SUBMENU != 0 {
        item.submenu = patch.submenu;
        if patch.submenu != 0 && item.id == 0 {
            item.id = u32::MAX;
        }
    }
    if mask & MIIM_CHECKMARKS != 0 {
        item.checked_bitmap = patch.checked_bitmap;
        item.unchecked_bitmap = patch.unchecked_bitmap;
    }
    if mask & MIIM_DATA != 0 {
        item.data = patch.data;
    }
    if menu_info_wants_text(mask) {
        item.text = patch.text;
    }
}

fn write_menu_item_info<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    info_ptr: u32,
    mask: u32,
    item: &MenuItem,
) -> bool {
    if mask & MIIM_TYPE != 0
        && !write_guest_u32(kernel, memory, thread_id, info_ptr + 8, item.item_type)
    {
        return false;
    }
    if mask & MIIM_STATE != 0
        && !write_guest_u32(kernel, memory, thread_id, info_ptr + 12, item.state)
    {
        return false;
    }
    if mask & MIIM_ID != 0 && !write_guest_u32(kernel, memory, thread_id, info_ptr + 16, item.id) {
        return false;
    }
    if mask & MIIM_SUBMENU != 0
        && !write_guest_u32(kernel, memory, thread_id, info_ptr + 20, item.submenu)
    {
        return false;
    }
    if mask & MIIM_CHECKMARKS != 0 {
        if !write_guest_u32(
            kernel,
            memory,
            thread_id,
            info_ptr + 24,
            item.checked_bitmap,
        ) || !write_guest_u32(
            kernel,
            memory,
            thread_id,
            info_ptr + 28,
            item.unchecked_bitmap,
        ) {
            return false;
        }
    }
    if mask & MIIM_DATA != 0
        && !write_guest_u32(kernel, memory, thread_id, info_ptr + 32, item.data)
    {
        return false;
    }
    if menu_info_wants_text(mask) {
        let text = item.text.as_deref().unwrap_or("");
        let full_len = text.encode_utf16().count() as u32;
        let buffer = read_guest_u32(kernel, memory, thread_id, info_ptr + 36).unwrap_or(0);
        let capacity = read_guest_u32(kernel, memory, thread_id, info_ptr + 40).unwrap_or(0);
        if buffer != 0
            && capacity != 0
            && write_wide_result(kernel, memory, thread_id, buffer, capacity as usize, text) == 0
            && !text.is_empty()
        {
            return false;
        }
        if !write_guest_u32(kernel, memory, thread_id, info_ptr + 40, full_len) {
            return false;
        }
    }
    true
}

fn menu_info_wants_text(mask: u32) -> bool {
    mask & (MIIM_TYPE | MIIM_STRING) != 0
}

