fn image_list_get_drag_image_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(drag) = kernel.resources.image_list_drag() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let point_ptr = raw_arg(args, 0);
    let hotspot_ptr = raw_arg(args, 1);
    if point_ptr != 0
        && !write_guest_point(
            kernel,
            memory,
            thread_id,
            point_ptr,
            Point {
                x: drag.x,
                y: drag.y,
            },
        )
    {
        return 0;
    }
    if hotspot_ptr != 0
        && !write_guest_point(
            kernel,
            memory,
            thread_id,
            hotspot_ptr,
            Point {
                x: drag.hotspot_x,
                y: drag.hotspot_y,
            },
        )
    {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    drag.image_list
}

