fn record_image_list_draw(kernel: &mut CeKernel, thread_id: u32, draw: ImageListDraw) -> bool {
    if draw.hdc == 0 || draw.index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if draw.image_list == SHELL_SYSTEM_IMAGE_LIST_HANDLE {
        if draw.index as u32 >= SHELL_SYSTEM_IMAGE_LIST_COUNT {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }
    match kernel.resources.record_image_list_draw(draw) {
        Some(true) => {
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn shell_system_image_bitmap_handle(index: i32) -> u32 {
    0x000b_d000 | ((index as u32) & 0x0fff)
}

fn load_stock_or_resource_image(
    kernel: &mut CeKernel,
    thread_id: u32,
    module: u32,
    name: u32,
    resource_kind: u16,
    stock_base: u32,
) -> u32 {
    if module == 0 && name <= u16::MAX as u32 {
        kernel.threads.set_last_error(thread_id, 0);
        return stock_base | name;
    }

    let module = normalized_module(kernel, module);
    let name = ResourceId::from_guest_arg(name);
    let Some(resource_handle) =
        kernel
            .resources
            .find_resource(module, name, ResourceId::Integer(resource_kind))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    resource_handle
}

fn load_bitmap_resource<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    module: u32,
    name: u32,
) -> u32 {
    let module = if module == 0 {
        kernel.process_module_base()
    } else {
        module
    };
    let Some(resource_handle) = kernel.resources.find_resource(
        module,
        ResourceId::from_guest_arg(name),
        ResourceId::Integer(RT_BITMAP as u16),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };
    let Some(data_ptr) = kernel.resources.load_resource(resource_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(size) = kernel.resources.sizeof_resource(resource_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, data_ptr, size) else {
        return 0;
    };
    create_bitmap_from_dib_bytes(kernel, memory, thread_id, &bytes)
}

fn load_bitmap_file<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    name_ptr: u32,
) -> u32 {
    let Some(path) = read_guest_wide_arg(memory, name_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Ok(bytes) = kernel.read_guest_file(&path) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
        return 0;
    };
    create_bitmap_from_file_bytes(kernel, memory, thread_id, &bytes)
}

fn create_bitmap_from_file_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
) -> u32 {
    if bytes.len() < 14 || &bytes[0..2] != b"BM" {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_offset) = read_le_u32(bytes, 10) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if bytes.len() <= 14 || bits_offset < 14 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let dib = &bytes[14..];
    let Some(header) = parse_dib_header(dib) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let bits_offset = bits_offset as usize;
    let byte_count_usize = byte_count as usize;
    if bits_offset
        .checked_add(byte_count_usize)
        .map_or(true, |end| end > bytes.len())
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if !write_guest_bytes(
        kernel,
        memory,
        thread_id,
        bits_ptr,
        &bytes[bits_offset..bits_offset + byte_count_usize],
    ) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_owned_bitmap(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
    )
}

fn create_bitmap_from_dib_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
) -> u32 {
    let Some(header) = parse_dib_header(bytes) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header_size) = read_le_u32(bytes, 0) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let compression = if header_size >= 40 {
        let Some(compression) = read_le_u32(bytes, 16) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        compression
    } else {
        BI_RGB
    };
    let Some(rgb_masks) =
        dib_rgb_masks_from_bytes(bytes, header_size, compression, header.bits_pixel)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let color_table =
        read_dib_color_table_from_bytes(bytes, header_size, compression, header.bits_pixel);
    let Some(bits_offset) = dib_bits_offset(bytes, header_size, compression, header.bits_pixel)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let byte_count_usize = byte_count as usize;
    if bits_offset
        .checked_add(byte_count_usize)
        .map_or(true, |end| end > bytes.len())
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if !write_guest_bytes(
        kernel,
        memory,
        thread_id,
        bits_ptr,
        &bytes[bits_offset..bits_offset + byte_count_usize],
    ) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    let bitmap = kernel.resources.create_owned_bitmap_with_masks(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
        rgb_masks,
    );
    if !color_table.is_empty()
        && let Some(object) = kernel.resources.bitmap_mut(bitmap)
    {
        object.color_table = color_table;
    }
    bitmap
}

fn create_bitmap_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    width: i32,
    height: i32,
    planes: u16,
    bits_pixel: u16,
    bits_ptr: u32,
) -> u32 {
    if width <= 0 || height == 0 || planes == 0 || bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .create_bitmap(width, height, planes, bits_pixel, bits_ptr)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DibHeader {
    width: i32,
    height: i32,
    planes: u16,
    bits_pixel: u16,
}

fn parse_dib_header(bytes: &[u8]) -> Option<DibHeader> {
    let header_size = read_le_u32(bytes, 0)?;
    match header_size {
        12 => Some(DibHeader {
            width: read_le_u16(bytes, 4)? as i32,
            height: read_le_u16(bytes, 6)? as i32,
            planes: read_le_u16(bytes, 8)?,
            bits_pixel: read_le_u16(bytes, 10)?,
        }),
        40..=124 => Some(DibHeader {
            width: read_le_i32(bytes, 4)?,
            height: read_le_i32(bytes, 8)?,
            planes: read_le_u16(bytes, 12)?,
            bits_pixel: read_le_u16(bytes, 14)?,
        }),
        _ => None,
    }
}

fn bitmap_byte_count(width: i32, height: i32, bits_pixel: u16) -> Option<u32> {
    if width == 0 || height == 0 || bits_pixel == 0 {
        return None;
    }
    let width = u64::from(width.unsigned_abs());
    let height = u64::from(height.unsigned_abs());
    let bits_per_row = width.checked_mul(u64::from(bits_pixel))?;
    let row_bytes = bits_per_row
        .checked_add(31)?
        .checked_div(32)?
        .checked_mul(4)?;
    let bytes = row_bytes.checked_mul(height)?;
    (bytes <= u64::from(u32::MAX)).then_some(bytes as u32)
}

fn dib_bits_offset(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<usize> {
    let header_size = header_size as usize;
    if bytes.len() < header_size {
        return None;
    }
    let mask_bytes = if compression == BI_BITFIELDS && header_size == 40 {
        12usize
    } else {
        0
    };
    let color_entries = dib_color_entry_count(bytes, header_size as u32, bits_pixel)?;
    let color_entry_bytes = if header_size == 12 { 3usize } else { 4 };
    header_size
        .checked_add(mask_bytes)?
        .checked_add(color_entries.checked_mul(color_entry_bytes)?)
}

fn dib_color_entry_count(bytes: &[u8], header_size: u32, bits_pixel: u16) -> Option<usize> {
    if !matches!(bits_pixel, 1 | 4 | 8) {
        return Some(0);
    }
    let max_entries = 1usize.checked_shl(u32::from(bits_pixel))?;
    if header_size >= 40 {
        let used_entries = read_le_u32(bytes, 32)
            .and_then(|count| (count != 0).then_some(count as usize))
            .unwrap_or(max_entries)
            .min(max_entries);
        Some(used_entries)
    } else {
        Some(max_entries)
    }
}

fn dib_rgb_masks_from_bytes(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<[u32; 3]>> {
    match compression {
        BI_RGB => Some(None),
        BI_BITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_offset = if header_size >= 52 {
                40usize
            } else {
                header_size as usize
            };
            let mask_bytes = bytes.get(mask_offset..mask_offset.checked_add(12)?)?;
            Some(Some([
                read_le_u32(mask_bytes, 0)?,
                read_le_u32(mask_bytes, 4)?,
                read_le_u32(mask_bytes, 8)?,
            ]))
        }
        _ => None,
    }
}

fn read_dib_color_table_from_bytes(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Vec<[u8; 4]> {
    let Some(used_entries) = dib_color_entry_count(bytes, header_size, bits_pixel) else {
        return Vec::new();
    };
    if used_entries == 0 {
        return Vec::new();
    }
    let table_offset = if header_size == 12 {
        12usize
    } else if compression == BI_BITFIELDS && header_size == 40 {
        52usize
    } else {
        header_size as usize
    };
    let bytes_per_entry = if header_size == 12 { 3usize } else { 4 };
    let Some(table_bytes) = used_entries.checked_mul(bytes_per_entry) else {
        return default_indexed_color_table(bits_pixel);
    };
    let Some(table) = bytes.get(table_offset..table_offset.saturating_add(table_bytes)) else {
        return default_indexed_color_table(bits_pixel);
    };
    let mut entries = Vec::with_capacity(used_entries);
    for entry in table.chunks_exact(bytes_per_entry) {
        entries.push([
            entry[0],
            entry[1],
            entry[2],
            if bytes_per_entry == 4 { entry[3] } else { 0 },
        ]);
    }
    entries
}

fn dib_rgb_masks<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    info_ptr: u32,
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<[u32; 3]>> {
    match compression {
        BI_RGB => Some(None),
        BI_BITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_bytes = if header_size >= 52 {
                read_guest_bytes(kernel, memory, thread_id, info_ptr.wrapping_add(40), 12)?
            } else {
                read_guest_bytes(
                    kernel,
                    memory,
                    thread_id,
                    info_ptr.wrapping_add(header_size),
                    12,
                )?
            };
            Some(Some([
                read_le_u32(&mask_bytes, 0)?,
                read_le_u32(&mask_bytes, 4)?,
                read_le_u32(&mask_bytes, 8)?,
            ]))
        }
        _ => None,
    }
}

fn read_dib_color_table<M: CoredllGuestMemory>(
    memory: &M,
    info_ptr: u32,
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
    color_usage: u32,
) -> Vec<[u8; 4]> {
    if !matches!(bits_pixel, 1 | 4 | 8) {
        return Vec::new();
    }
    let max_entries = 1usize << bits_pixel;
    let used_entries = if header_size >= 40 {
        memory
            .read_u32(info_ptr.wrapping_add(32))
            .ok()
            .and_then(|count| (count != 0).then_some(count as usize))
            .unwrap_or(max_entries)
            .min(max_entries)
    } else {
        max_entries
    };
    if used_entries == 0 {
        return Vec::new();
    }
    if color_usage == DIB_PAL_COLORS {
        return read_dib_palette_index_table(memory, info_ptr, header_size, used_entries)
            .unwrap_or_else(|| default_indexed_color_table(bits_pixel));
    }
    let table_ptr = if header_size == 12 {
        info_ptr.wrapping_add(12)
    } else if compression == BI_BITFIELDS && header_size == 40 {
        info_ptr.wrapping_add(52)
    } else {
        info_ptr.wrapping_add(header_size)
    };
    let bytes_per_entry = if header_size == 12 { 3 } else { 4 };
    let mut table = Vec::with_capacity(used_entries);
    for index in 0..used_entries {
        let entry_ptr = table_ptr.wrapping_add((index * bytes_per_entry) as u32);
        let blue = match memory.read_u8(entry_ptr) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let green = match memory.read_u8(entry_ptr.wrapping_add(1)) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let red = match memory.read_u8(entry_ptr.wrapping_add(2)) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let reserved = if bytes_per_entry == 4 {
            match memory.read_u8(entry_ptr.wrapping_add(3)) {
                Ok(value) => value,
                Err(_) => return default_indexed_color_table(bits_pixel),
            }
        } else {
            0
        };
        table.push([blue, green, red, reserved]);
    }
    table
}

fn read_dib_palette_index_table<M: CoredllGuestMemory>(
    memory: &M,
    info_ptr: u32,
    header_size: u32,
    used_entries: usize,
) -> Option<Vec<[u8; 4]>> {
    let table_ptr = info_ptr.wrapping_add(header_size);
    let mut table = Vec::with_capacity(used_entries);
    for index in 0..used_entries {
        let entry_ptr = table_ptr.wrapping_add((index * 2) as u32);
        let palette_index = u16::from_le_bytes([
            memory.read_u8(entry_ptr).ok()?,
            memory.read_u8(entry_ptr.wrapping_add(1)).ok()?,
        ]);
        let value = palette_index.min(u16::from(u8::MAX)) as u8;
        table.push([value, value, value, 0]);
    }
    Some(table)
}

fn default_indexed_color_table(bits_pixel: u16) -> Vec<[u8; 4]> {
    let entries = 1usize << bits_pixel;
    if bits_pixel == 1 {
        return vec![[0, 0, 0, 0], [0xff, 0xff, 0xff, 0]];
    }
    let divisor = entries.saturating_sub(1).max(1) as u16;
    (0..entries)
        .map(|index| {
            let value = ((index as u16 * 255) / divisor) as u8;
            [value, value, value, 0]
        })
        .collect()
}

fn get_object_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
    byte_count: i32,
    out_ptr: u32,
) -> u32 {
    const BITMAP_SIZE: u32 = 24;
    if out_ptr == 0 || byte_count < BITMAP_SIZE as i32 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INSUFFICIENT_BUFFER);
        return 0;
    }
    let Some(bitmap) = kernel.resources.bitmap(handle).cloned() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let ok = write_guest_i32(kernel, memory, thread_id, out_ptr, 0)
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(4),
            bitmap.width,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(8),
            bitmap.height,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(12),
            bitmap.width_bytes,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(16),
            bitmap.planes,
        )
        && write_guest_u16(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(18),
            bitmap.bits_pixel,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            out_ptr.wrapping_add(20),
            bitmap.bits_ptr,
        );
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
        BITMAP_SIZE
    } else {
        0
    }
}

fn delete_object_raw(kernel: &mut CeKernel, handle: u32) -> bool {
    if handle == 0 {
        return false;
    }
    let bitmap = kernel.resources.bitmap(handle).cloned();
    let removed = kernel.resources.delete_gdi_object(handle);
    if removed
        && let Some(bitmap) = bitmap
        && bitmap.bits_owned
        && bitmap.bits_ptr != 0
    {
        let _ = kernel
            .memory
            .heap_free(PROCESS_HEAP_HANDLE, 0, bitmap.bits_ptr);
    }
    true
}

fn read_le_u16(bytes: &[u8], offset: usize) -> Option<u16> {
    Some(u16::from_le_bytes([
        *bytes.get(offset)?,
        *bytes.get(offset + 1)?,
    ]))
}

fn read_le_u32(bytes: &[u8], offset: usize) -> Option<u32> {
    Some(u32::from_le_bytes([
        *bytes.get(offset)?,
        *bytes.get(offset + 1)?,
        *bytes.get(offset + 2)?,
        *bytes.get(offset + 3)?,
    ]))
}

fn read_le_i32(bytes: &[u8], offset: usize) -> Option<i32> {
    read_le_u32(bytes, offset).map(|value| value as i32)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum WindowRectKind {
    Window,
    Client,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PointMapKind {
    ClientToScreen,
    ScreenToClient,
}

fn write_window_rect<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd: u32,
    rect_ptr: u32,
    kind: WindowRectKind,
) -> bool {
    let rect = match kind {
        WindowRectKind::Window => kernel.gwe.get_window_rect(hwnd),
        WindowRectKind::Client => kernel.gwe.get_client_rect(hwnd),
    };
    let Some(rect) = rect else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    write_guest_rect(kernel, memory, thread_id, rect_ptr, rect)
}

// Strsafe helpers.

// Read up to max_chars wide chars from guest memory (not including null terminator).
fn read_guest_wcs_bounded<M: CoredllGuestMemory>(memory: &M, ptr: u32, max_chars: u32) -> Vec<u16> {
    let mut v = Vec::new();
    for i in 0..max_chars {
        match memory.read_u16(ptr + i * 2) {
            Ok(0) => break,
            Ok(c) => v.push(c),
            Err(_) => break,
        }
    }
    v
}

// Read up to max_bytes bytes from guest memory (stops at NUL or limit).
fn read_guest_bytes_bounded<M: CoredllGuestMemory>(memory: &M, ptr: u32, max_bytes: u32) -> Vec<u8> {
    let mut v = Vec::new();
    for i in 0..max_bytes {
        match memory.read_u8(ptr + i) {
            Ok(0) => break,
            Ok(c) => v.push(c),
            Err(_) => break,
        }
    }
    v
}

// Write wide string to guest memory, NUL-terminate within cap_chars characters.
// Returns true if the whole string fit.
fn write_guest_wcs<M: CoredllGuestMemory>(
    kernel: &mut CeKernel, memory: &mut M, thread_id: u32,
    dst: u32, src: &[u16], cap_chars: u32,
) -> bool {
    if cap_chars == 0 { return false; }
    let copy = src.len().min((cap_chars - 1) as usize);
    for (i, &ch) in src[..copy].iter().enumerate() {
        if !write_guest_u16(kernel, memory, thread_id, dst + i as u32 * 2, ch) { return false; }
    }
    write_guest_u16(kernel, memory, thread_id, dst + copy as u32 * 2, 0);
    copy == src.len()
}

// Write ANSI string to guest memory, NUL-terminate within cap_bytes.
fn strsafe_write_bytes<M: CoredllGuestMemory>(
    _kernel: &mut CeKernel, memory: &mut M, _thread_id: u32,
    dst: u32, src: &[u8], cap_bytes: u32,
) -> bool {
    if cap_bytes == 0 { return false; }
    let copy = src.len().min((cap_bytes - 1) as usize);
    for (i, &b) in src[..copy].iter().enumerate() {
        if memory.write_u8(dst + i as u32, b).is_err() { return false; }
    }
    let _ = memory.write_u8(dst + copy as u32, 0);
    copy == src.len()
}

fn strsafe_copy_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel, memory: &mut M, thread_id: u32,
    args: &[u32], _is_cb: bool,
) -> u32 {
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1); // chars or bytes depending on Cch vs Cb
    let src_ptr = raw_arg(args, 2);
    if dst == 0 || cap == 0 { return STRSAFE_E_INVALID_PARAMETER; }
    let cap_chars = if _is_cb { cap / 2 } else { cap };
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    if write_guest_wcs(kernel, memory, thread_id, dst, &src, cap_chars) {
        0 // S_OK
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

fn strsafe_copy_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel, memory: &mut M, thread_id: u32,
    args: &[u32], _is_cb: bool,
) -> u32 {
    // StringCchCopyExW(pszDest, cchDest, pszSrc, ppszDestEnd, pcchRemaining, dwFlags)
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    let pp_end = raw_arg(args, 3);
    let p_rem = raw_arg(args, 4);
    // dwFlags at args[5] — ignored in emulation
    if dst == 0 || cap == 0 { return STRSAFE_E_INVALID_PARAMETER; }
    let cap_chars = if _is_cb { cap / 2 } else { cap };
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    let ok = write_guest_wcs(kernel, memory, thread_id, dst, &src, cap_chars);
    let written = src.len().min((cap_chars - 1) as usize);
    let end_ptr = dst + written as u32 * 2;
    let rem = cap_chars.saturating_sub(written as u32 + 1);
    if pp_end != 0 { write_guest_u32(kernel, memory, thread_id, pp_end, end_ptr); }
    if p_rem != 0 { write_guest_u32(kernel, memory, thread_id, p_rem, rem); }
    if ok { 0 } else { STRSAFE_E_INSUFFICIENT_BUFFER }
}

fn strsafe_copy_n_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel, memory: &mut M, thread_id: u32,
    args: &[u32], _ex: bool,
) -> u32 {
    // StringCchCopyNW(pszDest, cchDest, pszSrc, cchSrc) — copy at most cchSrc chars.
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    let src_limit = raw_arg(args, 3);
    if dst == 0 || cap == 0 { return STRSAFE_E_INVALID_PARAMETER; }
    let src = read_guest_wcs_bounded(memory, src_ptr, src_limit);
    if write_guest_wcs(kernel, memory, thread_id, dst, &src, cap) {
        0
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

fn strsafe_cat_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel, memory: &mut M, thread_id: u32,
    args: &[u32], _ex: bool,
) -> u32 {
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    if dst == 0 || cap == 0 { return STRSAFE_E_INVALID_PARAMETER; }
    // Find current length of dst.
    let dst_len = read_guest_wcs_bounded(memory, dst, cap).len() as u32;
    let rem_chars = cap.saturating_sub(dst_len);
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    if write_guest_wcs(kernel, memory, thread_id, dst + dst_len * 2, &src, rem_chars) {
        0
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

