// SCROLLINFO fMask flags
const SIF_RANGE: u32 = 0x0001;
const SIF_PAGE: u32 = 0x0002;
const SIF_POS: u32 = 0x0004;
const SIF_TRACKPOS: u32 = 0x0010;
const SB_HORZ: u32 = 0;
const SB_VERT: u32 = 1;
const SB_BOTH: u32 = 3;

fn get_scroll_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let lpsi = raw_arg(args, 2);
    if !kernel.gwe.is_window(hwnd) {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    if lpsi == 0 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    // cbSize must be 28
    let Some(cb_size) = read_guest_u32(kernel, memory, thread_id, lpsi) else {
        return false;
    };
    if cb_size < 28 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let fmask = read_guest_u32(kernel, memory, thread_id, lpsi + 4).unwrap_or(0);
    let bar = if n_bar == SB_BOTH { SB_VERT } else { n_bar };
    let state = match kernel.gwe.get_scroll_state(hwnd, bar).cloned() {
        Some(s) => s,
        None => {
            kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        }
    };
    let mut ok = true;
    if fmask & SIF_RANGE != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 8, state.min as u32);
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 12, state.max as u32);
    }
    if fmask & SIF_PAGE != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 16, state.page);
    }
    if fmask & SIF_POS != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 20, state.pos as u32);
    }
    if fmask & SIF_TRACKPOS != 0 {
        // tracking position same as current position
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 24, state.pos as u32);
    }
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
    }
    ok
}

fn set_scroll_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let lpsi = raw_arg(args, 2);
    // arg 3: bRedraw (ignored — we have no actual rendering to trigger)
    if !kernel.gwe.is_window(hwnd) || lpsi == 0 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    // Read all values from guest memory before touching the mutable borrow.
    let fmask = read_guest_u32(kernel, memory, thread_id, lpsi + 4).unwrap_or(0);
    let nmin = read_guest_u32(kernel, memory, thread_id, lpsi + 8).unwrap_or(0) as i32;
    let nmax = read_guest_u32(kernel, memory, thread_id, lpsi + 12).unwrap_or(0) as i32;
    let npage = read_guest_u32(kernel, memory, thread_id, lpsi + 16).unwrap_or(0);
    let npos = read_guest_u32(kernel, memory, thread_id, lpsi + 20).unwrap_or(0) as i32;
    let bars: &[u32] = match n_bar {
        SB_BOTH => &[SB_HORZ, SB_VERT],
        b => &[b],
    };
    let mut new_pos = 0i32;
    for &bar in bars {
        let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) else {
            continue;
        };
        if fmask & SIF_RANGE != 0 {
            state.min = nmin;
            state.max = nmax;
        }
        if fmask & SIF_PAGE != 0 {
            state.page = npage;
        }
        if fmask & SIF_POS != 0 {
            let page_size = state.page as i32;
            let max_pos = (state.max - page_size.max(0) + 1).max(state.min);
            state.pos = npos.clamp(state.min, max_pos);
            new_pos = state.pos;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    new_pos
}

fn set_scroll_pos_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> i32 {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let n_pos = raw_arg(args, 2) as i32;
    // arg 3: bRedraw (ignored)
    if !kernel.gwe.is_window(hwnd) {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let bar = if n_bar == SB_BOTH { SB_VERT } else { n_bar };
    let (prev_pos, new_pos) = {
        let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) else {
            kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        let prev = state.pos;
        let page_size = state.page as i32;
        let max_pos = (state.max - page_size.max(0) + 1).max(state.min);
        state.pos = n_pos.clamp(state.min, max_pos);
        (prev, state.pos)
    };
    let _ = new_pos;
    kernel.threads.set_last_error(thread_id, 0);
    prev_pos
}

fn set_scroll_range_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let n_min = raw_arg(args, 2) as i32;
    let n_max = raw_arg(args, 3) as i32;
    // arg 4: bRedraw (ignored)
    if !kernel.gwe.is_window(hwnd) {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let bars: &[u32] = match n_bar {
        SB_BOTH => &[SB_HORZ, SB_VERT],
        b => &[b],
    };
    for &bar in bars {
        if let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) {
            state.min = n_min;
            state.max = n_max;
            state.pos = state.pos.clamp(n_min, n_max);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn scroll_window_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let hwnd = raw_arg(args, 0);
    // dx, dy: scroll amounts; fuScroll: SW_* flags
    let fu_scroll = raw_arg(args, 7);
    const SW_INVALIDATE: u32 = 0x0002;
    if !kernel.gwe.is_window(hwnd) {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0; // ERROR
    }
    // Invalidate entire client area when SW_INVALIDATE is set.
    if fu_scroll & SW_INVALIDATE != 0 {
        kernel.gwe.invalidate_window(hwnd, None, true);
    }
    // Check if prcUpdate (arg 6) is requested and write a zero RECT.
    let prc_update = raw_arg(args, 6);
    if prc_update != 0 {
        // Write empty update rect (0,0,0,0)
        let _ = write_guest_bytes(kernel, memory, thread_id, prc_update, &[0u8; 16]);
    }
    kernel.threads.set_last_error(thread_id, 0);
    1 // NULLREGION
}

fn release_dc_raw(kernel: &CeKernel, hwnd: u32, hdc: u32) -> u32 {
    if hdc == 0 {
        return 0;
    }
    if hwnd == 0 || kernel.gwe.is_window(hwnd) {
        1
    } else {
        0
    }
}

fn get_device_caps_raw(kernel: &CeKernel, hdc: u32, index: u32) -> u32 {
    if hdc == 0 {
        return 0;
    }
    match index {
        HORZRES => kernel.gwe.system_metric(crate::ce::gwe::SM_CXSCREEN) as u32,
        VERTRES => kernel.gwe.system_metric(crate::ce::gwe::SM_CYSCREEN) as u32,
        BITSPIXEL => 16,
        PLANES => 1,
        LOGPIXELSX | LOGPIXELSY => 96,
        _ => 0,
    }
}

fn create_compatible_dc_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> u32 {
    let _ = hdc;
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_compatible_dc()
}

fn delete_dc_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> bool {
    if hdc == 0 || !kernel.resources.delete_dc(hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn create_compatible_bitmap_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hdc: u32,
    width: i32,
    height: i32,
) -> u32 {
    if hdc == 0 || width <= 0 || height <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(width, height, 32) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .create_owned_bitmap(width, height, 1, 32, bits_ptr)
}

fn create_dib_section_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let _hdc = raw_arg(args, 0);
    let info_ptr = raw_arg(args, 1);
    let color_usage = raw_arg(args, 2);
    let bits_out = raw_arg(args, 3);
    let section = raw_arg(args, 4);
    let offset = raw_arg(args, 5);
    if info_ptr == 0
        || bits_out == 0
        || !matches!(color_usage, DIB_RGB_COLORS | DIB_PAL_COLORS)
        || offset != 0
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if section != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
        return 0;
    }
    let Some(header_size) = read_guest_u32(kernel, memory, thread_id, info_ptr) else {
        return 0;
    };
    if !(40..=124).contains(&header_size) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header_bytes) = read_guest_bytes(kernel, memory, thread_id, info_ptr, header_size)
    else {
        return 0;
    };
    let Some(header) = parse_dib_header(&header_bytes) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(compression) = read_le_u32(&header_bytes, 16) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let rgb_masks = match dib_rgb_masks(
        kernel,
        memory,
        thread_id,
        info_ptr,
        header_size,
        compression,
        header.bits_pixel,
    ) {
        Some(masks) => masks,
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
    };
    let color_table = read_dib_color_table(
        memory,
        info_ptr,
        header_size,
        compression,
        header.bits_pixel,
        color_usage,
    );
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if !write_guest_u32(kernel, memory, thread_id, bits_out, bits_ptr) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    let bitmap = kernel.resources.create_owned_bitmap_with_masks(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
        rgb_masks,
    );
    if !color_table.is_empty() {
        if let Some(object) = kernel.resources.bitmap_mut(bitmap) {
            object.color_table = color_table;
        }
    }
    bitmap
}

fn create_font_indirect_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    logfont_ptr: u32,
) -> u32 {
    const LOGFONTW_SIZE: u32 = 92;
    const LF_FACESIZE: usize = 32;
    if logfont_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, logfont_ptr, LOGFONTW_SIZE)
    else {
        return 0;
    };
    let Some(height) = read_le_i32(&bytes, 0) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(width) = read_le_i32(&bytes, 4) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(weight) = read_le_i32(&bytes, 16) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let face_units = (0..LF_FACESIZE)
        .filter_map(|index| read_le_u16(&bytes, 28 + index * 2))
        .take_while(|unit| *unit != 0)
        .collect::<Vec<_>>();
    let face_name = String::from_utf16_lossy(&face_units);
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_font(
        logfont_ptr,
        height,
        width,
        weight,
        bytes.get(20).copied().unwrap_or(0) != 0,
        bytes.get(21).copied().unwrap_or(0) != 0,
        bytes.get(22).copied().unwrap_or(0) != 0,
        bytes.get(23).copied().unwrap_or(1),
        bytes.get(27).copied().unwrap_or(0),
        face_name,
    )
}

fn add_font_resource_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    path_ptr: u32,
) -> u32 {
    if path_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(path) = read_guest_wide_arg(memory, path_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    match kernel.read_guest_file(&path) {
        Ok(_) => {
            kernel.threads.set_last_error(thread_id, 0);
            kernel.send_notify_message_w(
                thread_id,
                crate::ce::gwe::HWND_BROADCAST,
                crate::ce::gwe::WM_FONTCHANGE,
                0,
                0,
            );
            1
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
            0
        }
    }
}

