fn get_dib_color_table_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    start: u32,
    entries: u32,
    colors_ptr: u32,
) -> u32 {
    if hdc == 0 || colors_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bitmap_handle) = kernel.resources.selected_bitmap(hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(bitmap) = kernel.resources.bitmap(bitmap_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Ok(start_index) = usize::try_from(start) else {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    if entries == 0 || start_index >= bitmap.color_table.len() {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let copy_count = usize::try_from(entries)
        .ok()
        .unwrap_or(usize::MAX)
        .min(bitmap.color_table.len() - start_index);
    let bytes: Vec<u8> = bitmap.color_table[start_index..start_index + copy_count]
        .iter()
        .flat_map(|entry| entry.iter().copied())
        .collect();
    if !write_guest_bytes(kernel, memory, thread_id, colors_ptr, &bytes) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    copy_count as u32
}

fn set_dib_color_table_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hdc: u32,
    start: u32,
    entries: u32,
    colors_ptr: u32,
) -> u32 {
    if hdc == 0 || colors_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bitmap_handle) = kernel.resources.selected_bitmap(hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    if entries == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let Some(byte_count) = entries.checked_mul(4) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, colors_ptr, byte_count) else {
        return 0;
    };
    let Ok(start_index) = usize::try_from(start) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let copy_count = bytes.len() / 4;
    let Some(bitmap) = kernel.resources.bitmap_mut(bitmap_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let required_len = start_index.saturating_add(copy_count);
    if bitmap.color_table.len() < required_len {
        bitmap.color_table.resize(required_len, [0, 0, 0, 0]);
    }
    for (index, entry) in bytes.chunks_exact(4).enumerate() {
        bitmap.color_table[start_index + index] = [entry[0], entry[1], entry[2], entry[3]];
    }
    kernel.threads.set_last_error(thread_id, 0);
    copy_count as u32
}

fn set_bitmap_bits_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
    byte_count: u32,
    bits_ptr: u32,
) -> u32 {
    if bitmap == 0 || bits_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(dest_ptr) = kernel
        .resources
        .bitmap(bitmap)
        .map(|bitmap| bitmap.bits_ptr)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    if dest_ptr != 0 {
        let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, bits_ptr, byte_count) else {
            return 0;
        };
        if !write_guest_bytes(kernel, memory, thread_id, dest_ptr, &bytes) {
            return 0;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    byte_count
}

fn get_pixel_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> u32 {
    if hdc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return CLR_INVALID;
    }
    kernel.threads.set_last_error(thread_id, 0);
    0
}

fn set_brush_org_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let x = raw_i32_arg(args, 1);
    let y = raw_i32_arg(args, 2);
    let out_ptr = raw_arg(args, 3);
    let Some(previous) = kernel.resources.set_brush_origin(hdc, Point { x, y }) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if out_ptr != 0 && !write_guest_point(kernel, memory, thread_id, out_ptr, previous) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct PenModel {
    colorref: u32,
    width: i32,
    rop2: i32,
    style: u32,
}

fn polyline_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    hdc: u32,
    points_ptr: u32,
    point_count: i32,
) -> bool {
    if hdc == 0 || points_ptr == 0 || point_count <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let mut points = Vec::new();
    for index in 0..point_count as u32 {
        let Some(point) = read_guest_point(
            kernel,
            memory,
            thread_id,
            points_ptr.wrapping_add(index * 8),
        ) else {
            return false;
        };
        points.push(point);
    }
    if let Some(pen) = selected_pen_model(kernel, hdc) {
        if !draw_polyline_to_bitmap_for_hdc(kernel, memory, hdc, &points, pen)
            && let Some(framebuffer) = framebuffer
        {
            draw_polyline_for_hdc(kernel, framebuffer, hdc, &points, pen);
        }
    }
    if let Some(last) = points.last().copied() {
        let _ = kernel.resources.move_to(hdc, last);
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn draw_polyline_to_bitmap_for_hdc<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    hdc: u32,
    points: &[Point],
    pen: PenModel,
) -> bool {
    if !kernel.resources.is_memory_dc(hdc) {
        return false;
    }
    let Some(bitmap) = selected_bitmap_object(kernel, hdc) else {
        return true;
    };
    let clips = hdc_clip_rects(
        kernel,
        hdc,
        Rect {
            left: 0,
            top: 0,
            right: bitmap.width,
            bottom: bitmap.height,
        },
        bitmap.width,
        bitmap.height,
    );
    if clips.is_empty() {
        return true;
    };
    for clip in clips {
        let mut style_state = 0usize;
        for segment in points.windows(2) {
            draw_bitmap_line(
                memory,
                &bitmap,
                segment[0],
                segment[1],
                clip,
                pen,
                &mut style_state,
            );
        }
    }
    true
}

fn polygon_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    hdc: u32,
    points_ptr: u32,
    point_count: i32,
) -> bool {
    if hdc == 0 || points_ptr == 0 || point_count <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let mut points = Vec::new();
    for index in 0..point_count as u32 {
        let Some(point) = read_guest_point(
            kernel,
            memory,
            thread_id,
            points_ptr.wrapping_add(index * 8),
        ) else {
            return false;
        };
        points.push(point);
    }
    if points.len() >= 2 {
        if kernel.resources.is_memory_dc(hdc) {
            if let Some(bitmap) = selected_bitmap_object(kernel, hdc) {
                let clips = hdc_clip_rects(
                    kernel,
                    hdc,
                    Rect {
                        left: 0,
                        top: 0,
                        right: bitmap.width,
                        bottom: bitmap.height,
                    },
                    bitmap.width,
                    bitmap.height,
                );
                if !clips.is_empty() {
                    let paint = selected_brush_paint(kernel, hdc);
                    let pen = selected_pen_model(kernel, hdc);
                    let (origin, fill_mode) = kernel
                        .resources
                        .dc_state(hdc)
                        .map(|state| (state.brush_origin, state.poly_fill_mode))
                        .unwrap_or((Point { x: 0, y: 0 }, crate::ce::resource::POLY_FILL_ALTERNATE));
                    for clip in clips {
                        if let Some(paint) = paint.clone() {
                            fill_bitmap_polygon(memory, &bitmap, &points, clip, paint, origin, fill_mode);
                        }
                        if let Some(pen) = pen {
                            draw_closed_bitmap_polyline(memory, &bitmap, &points, clip, pen);
                        }
                    }
                }
            }
        } else if let Some(framebuffer) = framebuffer {
            let fill_mode = kernel
                .resources
                .dc_state(hdc)
                .map(|state| state.poly_fill_mode)
                .unwrap_or(crate::ce::resource::POLY_FILL_ALTERNATE);
            if let Some(BrushPaint::Solid(color)) = selected_brush_paint(kernel, hdc) {
                fill_framebuffer_polygon_for_hdc(kernel, framebuffer, hdc, &points, color, fill_mode);
            }
            if let Some(pen) = selected_pen_model(kernel, hdc) {
                let mut closed = points.clone();
                if let Some(first) = points.first().copied() {
                    closed.push(first);
                }
                draw_polyline_for_hdc(kernel, framebuffer, hdc, &closed, pen);
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn rectangle_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    if hdc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let rect = Rect {
        left: raw_i32_arg(args, 1),
        top: raw_i32_arg(args, 2),
        right: raw_i32_arg(args, 3),
        bottom: raw_i32_arg(args, 4),
    };
    if let Some(paint) = selected_brush_paint(kernel, hdc)
        && !fill_bitmap_rect_for_hdc(kernel, memory, hdc, rect, paint.clone())
        && let BrushPaint::Solid(color) = paint
        && let Some(framebuffer) = framebuffer.as_deref_mut()
    {
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, hdc, rect, color);
    }
    if let Some(pen) = selected_pen_model(kernel, hdc) {
        let rect = normalize_rect(rect);
        let points = [
            Point {
                x: rect.left,
                y: rect.top,
            },
            Point {
                x: rect.right.saturating_sub(1),
                y: rect.top,
            },
            Point {
                x: rect.right.saturating_sub(1),
                y: rect.bottom.saturating_sub(1),
            },
            Point {
                x: rect.left,
                y: rect.bottom.saturating_sub(1),
            },
            Point {
                x: rect.left,
                y: rect.top,
            },
        ];
        if !draw_polyline_to_bitmap_for_hdc(kernel, memory, hdc, &points, pen)
            && let Some(framebuffer) = framebuffer.as_deref_mut()
        {
            draw_polyline_for_hdc(kernel, framebuffer, hdc, &points, pen);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn gradient_fill_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    // GradientFill(hdc, pVertex, nVertex, pMesh, nMesh, ulMode)
    let hdc = raw_arg(args, 0);
    let vertex_ptr = raw_arg(args, 1);
    let n_vertex = raw_arg(args, 2) as usize;
    let mesh_ptr = raw_arg(args, 3);
    let n_mesh = raw_arg(args, 4) as usize;
    let mode = raw_arg(args, 5);

    const GRADIENT_FILL_RECT_H: u32 = 0x00;
    const GRADIENT_FILL_RECT_V: u32 = 0x01;

    if hdc == 0 || vertex_ptr == 0 || mesh_ptr == 0 || n_vertex == 0 || n_mesh == 0 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }

    // TRIVERTEX: x(4), y(4), Red(2), Green(2), Blue(2), Alpha(2) = 16 bytes each
    const TRIVERTEX_SIZE: u32 = 16;
    // GRADIENT_RECT: UpperLeft(4), LowerRight(4) = 8 bytes each
    const GRADIENT_RECT_SIZE: u32 = 8;

    if mode != GRADIENT_FILL_RECT_H && mode != GRADIENT_FILL_RECT_V {
        // Triangles: no-op for now.
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }

    // Read all vertex data.
    struct TriVertex { x: i32, y: i32, r: u16, g: u16, b: u16 }
    let mut vertices = Vec::with_capacity(n_vertex);
    for i in 0..n_vertex {
        let base = vertex_ptr + i as u32 * TRIVERTEX_SIZE;
        let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, base, TRIVERTEX_SIZE) else {
            return false;
        };
        let x = i32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]);
        let y = i32::from_le_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]);
        let r = u16::from_le_bytes([bytes[8], bytes[9]]);
        let g = u16::from_le_bytes([bytes[10], bytes[11]]);
        let b = u16::from_le_bytes([bytes[12], bytes[13]]);
        vertices.push(TriVertex { x, y, r, g, b });
    }

    // Process each GRADIENT_RECT mesh entry.
    for i in 0..n_mesh {
        let base = mesh_ptr + i as u32 * GRADIENT_RECT_SIZE;
        let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, base, GRADIENT_RECT_SIZE) else {
            return false;
        };
        let ul = u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]) as usize;
        let lr = u32::from_le_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]) as usize;
        let (Some(tl), Some(br)) = (vertices.get(ul), vertices.get(lr)) else {
            kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        };

        let rect = normalize_rect(Rect { left: tl.x, top: tl.y, right: br.x, bottom: br.y });
        if rect.right <= rect.left || rect.bottom <= rect.top {
            continue;
        }

        // COLOR16 values are in the range 0x0000–0xFF00; extract 8-bit components.
        let r0 = (tl.r >> 8) as u8;
        let g0 = (tl.g >> 8) as u8;
        let b0 = (tl.b >> 8) as u8;
        let r1 = (br.r >> 8) as u8;
        let g1 = (br.g >> 8) as u8;
        let b1 = (br.b >> 8) as u8;

        if kernel.resources.is_memory_dc(hdc) {
            if let Some(bitmap) = selected_bitmap_object(kernel, hdc) {
                let clips = hdc_clip_rects(kernel, hdc, rect, bitmap.width, bitmap.height);
                for clip in clips {
                    let span = if mode == GRADIENT_FILL_RECT_H {
                        rect.right - rect.left
                    } else {
                        rect.bottom - rect.top
                    };
                    if span <= 0 { continue; }
                    for y in clip.top..clip.bottom {
                        for x in clip.left..clip.right {
                            let t = if mode == GRADIENT_FILL_RECT_H {
                                (x - rect.left) as f32 / span as f32
                            } else {
                                (y - rect.top) as f32 / span as f32
                            };
                            let t = t.clamp(0.0, 1.0);
                            let r = (r0 as f32 + (r1 as f32 - r0 as f32) * t) as u8;
                            let g = (g0 as f32 + (g1 as f32 - g0 as f32) * t) as u8;
                            let b = (b0 as f32 + (b1 as f32 - b0 as f32) * t) as u8;
                            let _ = write_bitmap_pixel_rgb(memory, &bitmap, x, y, [r, g, b]);
                        }
                    }
                }
            }
        } else if let Some(framebuffer) = framebuffer.as_deref_mut() {
            let Some((client_origin, clips)) =
                hdc_framebuffer_client_clip_rects(kernel, hdc, rect) else {
                continue;
            };
            let info = framebuffer.info();
            let bytes_per_pixel = info.format.bytes_per_pixel();
            let span = if mode == GRADIENT_FILL_RECT_H {
                rect.right - rect.left
            } else {
                rect.bottom - rect.top
            };
            if span <= 0 { continue; }
            for clip in &clips {
                let screen_clip = clip.offset(client_origin.x, client_origin.y);
                let screen_rect = rect.offset(client_origin.x, client_origin.y);
                let y_lo = screen_rect.top.max(screen_clip.top).max(0) as usize;
                let y_hi = screen_rect.bottom.min(screen_clip.bottom).min(info.height as i32) as usize;
                let x_lo = screen_rect.left.max(screen_clip.left).max(0) as usize;
                let x_hi = screen_rect.right.min(screen_clip.right).min(info.width as i32) as usize;
                if y_hi <= y_lo || x_hi <= x_lo { continue; }
                let pixels = framebuffer.pixels_mut();
                for y in y_lo..y_hi {
                    for x in x_lo..x_hi {
                        let t = if mode == GRADIENT_FILL_RECT_H {
                            (x as i32 - screen_rect.left) as f32 / span as f32
                        } else {
                            (y as i32 - screen_rect.top) as f32 / span as f32
                        };
                        let t = t.clamp(0.0, 1.0);
                        let r = (r0 as f32 + (r1 as f32 - r0 as f32) * t) as u8;
                        let g = (g0 as f32 + (g1 as f32 - g0 as f32) * t) as u8;
                        let b = (b0 as f32 + (b1 as f32 - b0 as f32) * t) as u8;
                        let pixel = pixel_bytes_for_rgb(info.format, [r, g, b]);
                        let off = y * info.stride + x * bytes_per_pixel;
                        pixels[off..off + bytes_per_pixel].copy_from_slice(&pixel[..bytes_per_pixel]);
                    }
                }
                framebuffer.mark_dirty(FramebufferRect::new(
                    x_lo as u32, y_lo as u32,
                    (x_hi - x_lo) as u32, (y_hi - y_lo) as u32,
                ));
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn ellipse_fill_spans(rect: Rect) -> Vec<(i32, i32, i32)> {
    // Scan-line fill for ellipse inscribed in rect.
    // Returns (y, x_start_inclusive, x_end_exclusive) spans.
    let width = rect.right - rect.left;
    let height = rect.bottom - rect.top;
    if width <= 0 || height <= 0 {
        return Vec::new();
    }
    let cx = (rect.left + rect.right) as f64 / 2.0;
    let cy = (rect.top + rect.bottom) as f64 / 2.0;
    let a = width as f64 / 2.0;
    let b = height as f64 / 2.0;
    let mut spans = Vec::new();
    for y in rect.top..rect.bottom {
        let dy = (y as f64 + 0.5) - cy;
        let ratio = dy / b;
        if ratio.abs() >= 1.0 {
            continue;
        }
        let x_half = a * (1.0 - ratio * ratio).sqrt();
        let x_start = (cx - x_half).ceil() as i32;
        let x_end = (cx + x_half).ceil() as i32;
        if x_end > x_start {
            spans.push((y, x_start, x_end));
        }
    }
    spans
}

fn draw_ellipse_outline_bitmap<M: CoredllGuestMemory>(
    memory: &mut M,
    bitmap: &crate::ce::resource::BitmapObject,
    rect: Rect,
    clip: Rect,
    pen: PenModel,
) {
    // Midpoint ellipse algorithm tracing the 1-pixel-wide boundary,
    // width-extended by pen.width.
    let width = rect.right - rect.left;
    let height = rect.bottom - rect.top;
    if width <= 0 || height <= 0 {
        return;
    }
    let cx = (rect.left + rect.right - 1) as f64 / 2.0;
    let cy = (rect.top + rect.bottom - 1) as f64 / 2.0;
    let a = width as f64 / 2.0;
    let b = height as f64 / 2.0;
    let rgb = colorref_rgb(pen.colorref);
    let pw = pen.width.max(1);
    let low = (pw - 1) / 2;
    let high = pw / 2;

    // Parametric scan: for each y, compute the boundary x positions.
    // Top and bottom border rows.
    let mut last_x_half = -1.0f64;
    for y in rect.top..rect.bottom {
        let dy = (y as f64 + 0.5) - cy - 0.5;
        let ratio = dy / b;
        if ratio.abs() > 1.0 {
            continue;
        }
        let x_half = a * (1.0 - ratio * ratio).sqrt();
        let x_left = (cx - x_half).round() as i32;
        let x_right = (cx + x_half).round() as i32;

        // Draw vertical side pixels (boundary pixels on left/right columns).
        let left_changed = (x_left as f64 - (cx - last_x_half).round()).abs() >= 0.5;
        let right_changed = (x_right as f64 - (cx + last_x_half).round()).abs() >= 0.5;
        if last_x_half < 0.0 || left_changed || right_changed || y == rect.bottom - 1 {
            // Left boundary column
            for dy2 in -low..=high {
                for dx2 in -low..=high {
                    let px = x_left + dx2;
                    let py = y + dy2;
                    if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                        let dst = bitmap_pixel_rgb_from_memory(memory, bitmap, px, py).unwrap_or([0, 0, 0]);
                        let _ = write_bitmap_pixel_rgb(memory, bitmap, px, py, apply_rop2_rgb(pen.rop2, rgb, dst));
                    }
                }
            }
            // Right boundary column (only if different from left)
            if x_right != x_left {
                for dy2 in -low..=high {
                    for dx2 in -low..=high {
                        let px = x_right + dx2;
                        let py = y + dy2;
                        if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                            let dst = bitmap_pixel_rgb_from_memory(memory, bitmap, px, py).unwrap_or([0, 0, 0]);
                            let _ = write_bitmap_pixel_rgb(memory, bitmap, px, py, apply_rop2_rgb(pen.rop2, rgb, dst));
                        }
                    }
                }
            }
        }
        last_x_half = x_half;
    }
    // Top and bottom horizontal boundary rows.
    for (y, x_start, x_end) in &[
        (rect.top, (cx - a).ceil() as i32, (cx + a).ceil() as i32),
        (rect.bottom - 1, (cx - a).ceil() as i32, (cx + a).ceil() as i32),
    ] {
        for x in *x_start..*x_end {
            for dy2 in -low..=high {
                for dx2 in -low..=high {
                    let px = x + dx2;
                    let py = y + dy2;
                    if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                        let dst = bitmap_pixel_rgb_from_memory(memory, bitmap, px, py).unwrap_or([0, 0, 0]);
                        let _ = write_bitmap_pixel_rgb(memory, bitmap, px, py, apply_rop2_rgb(pen.rop2, rgb, dst));
                    }
                }
            }
        }
    }
}

fn ellipse_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    if hdc == 0 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let rect = Rect {
        left: raw_i32_arg(args, 1),
        top: raw_i32_arg(args, 2),
        right: raw_i32_arg(args, 3),
        bottom: raw_i32_arg(args, 4),
    };
    let rect = normalize_rect(rect);
    if rect.right <= rect.left || rect.bottom <= rect.top {
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }
    let spans = ellipse_fill_spans(rect);
    if kernel.resources.is_memory_dc(hdc) {
        if let Some(bitmap) = selected_bitmap_object(kernel, hdc) {
            let clips = hdc_clip_rects(
                kernel,
                hdc,
                rect,
                bitmap.width,
                bitmap.height,
            );
            if !clips.is_empty() {
                let paint = selected_brush_paint(kernel, hdc);
                let pen = selected_pen_model(kernel, hdc);
                let brush_origin = kernel
                    .resources
                    .dc_state(hdc)
                    .map(|state| state.brush_origin)
                    .unwrap_or(Point { x: 0, y: 0 });
                let pattern = paint.as_ref().and_then(|p| match p {
                    BrushPaint::Pattern(pat) => {
                        bitmap_pattern_bytes(memory, pat).map(|bytes| (pat.clone(), bytes))
                    }
                    _ => None,
                });
                for clip in &clips {
                    let clip = *clip;
                    // Fill interior spans
                    if let Some(paint) = paint.as_ref() {
                        for &(y, x_start, x_end) in &spans {
                            let x_start = x_start.max(clip.left);
                            let x_end = x_end.min(clip.right);
                            if x_end <= x_start {
                                continue;
                            }
                            for x in x_start..x_end {
                                let rgb = match paint {
                                    BrushPaint::Solid(colorref) => colorref_rgb(*colorref),
                                    BrushPaint::Pattern(_) => {
                                        if let Some((pat, bytes)) = pattern.as_ref() {
                                            pattern_pixel_rgb(pat, bytes, x, y, brush_origin)
                                                .unwrap_or([0, 0, 0])
                                        } else {
                                            continue;
                                        }
                                    }
                                };
                                let _ = write_bitmap_pixel_rgb(memory, &bitmap, x, y, rgb);
                            }
                        }
                    }
                    // Draw outline
                    if let Some(pen) = pen {
                        if pen.style != PS_NULL {
                            draw_ellipse_outline_bitmap(memory, &bitmap, rect, clip, pen);
                        }
                    }
                }
            }
        }
    } else if let Some(framebuffer) = framebuffer.as_deref_mut() {
        let Some((client_origin, clips)) =
            hdc_framebuffer_client_clip_rects(kernel, hdc, rect) else {
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        };
        // Fill: draw each span as a horizontal rect in the framebuffer
        if let Some(BrushPaint::Solid(colorref)) = selected_brush_paint(kernel, hdc) {
            let rgb = colorref_rgb(colorref);
            let pixel = {
                let info = framebuffer.info();
                pixel_bytes_for_rgb(info.format, rgb)
            };
            let info = framebuffer.info();
            let bytes_per_pixel = info.format.bytes_per_pixel();
            for &(y, x_start, x_end) in &spans {
                let screen_y = y + client_origin.y;
                if screen_y < 0 || screen_y >= info.height as i32 {
                    continue;
                }
                for clip in &clips {
                    let screen_clip = clip.offset(client_origin.x, client_origin.y);
                    let x_lo = (x_start + client_origin.x).max(screen_clip.left).max(0) as usize;
                    let x_hi = (x_end + client_origin.x)
                        .min(screen_clip.right)
                        .min(info.width as i32) as usize;
                    if x_hi <= x_lo {
                        continue;
                    }
                    let row_off = screen_y as usize * info.stride;
                    let pixels = framebuffer.pixels_mut();
                    for x in x_lo..x_hi {
                        let off = row_off + x * bytes_per_pixel;
                        pixels[off..off + bytes_per_pixel]
                            .copy_from_slice(&pixel[..bytes_per_pixel]);
                    }
                    framebuffer.mark_dirty(FramebufferRect::new(
                        x_lo as u32,
                        screen_y as u32,
                        (x_hi - x_lo) as u32,
                        1,
                    ));
                }
            }
        }
        // Pen outline: draw via parametric approach on framebuffer
        if let Some(pen) = selected_pen_model(kernel, hdc) {
            if pen.style != PS_NULL {
                let pen_rgb = colorref_rgb(pen.colorref);
                let pw = pen.width.max(1);
                let low = (pw - 1) / 2;
                let high = pw / 2;
                let screen_rect = rect.offset(client_origin.x, client_origin.y);
                let a = (screen_rect.right - screen_rect.left) as f64 / 2.0;
                let b = (screen_rect.bottom - screen_rect.top) as f64 / 2.0;
                let cx = (screen_rect.left + screen_rect.right) as f64 / 2.0;
                let cy = (screen_rect.top + screen_rect.bottom) as f64 / 2.0;
                let info = framebuffer.info();
                let bytes_per_pixel = info.format.bytes_per_pixel();
                let pixel = pixel_bytes_for_rgb(info.format, pen_rgb);
                let mut last_x_left = i32::MAX;
                let mut last_x_right = i32::MIN;
                for sy in screen_rect.top..screen_rect.bottom {
                    let dy = (sy as f64 + 0.5) - cy;
                    let ratio = dy / b;
                    if ratio.abs() > 1.0 {
                        continue;
                    }
                    let x_half = a * (1.0 - ratio * ratio).sqrt();
                    let x_left = (cx - x_half).round() as i32;
                    let x_right = (cx + x_half).round() as i32;
                    let draw = sy == screen_rect.top
                        || sy == screen_rect.bottom - 1
                        || x_left != last_x_left
                        || x_right != last_x_right;
                    if !draw {
                        continue;
                    }
                    last_x_left = x_left;
                    last_x_right = x_right;
                    for &sx in &[x_left, x_right] {
                        for clip in &clips {
                            let screen_clip = clip.offset(client_origin.x, client_origin.y);
                            for dpy in -low..=high {
                                for dpx in -low..=high {
                                    let px = sx + dpx;
                                    let py = sy + dpy;
                                    if px >= screen_clip.left
                                        && px < screen_clip.right
                                        && py >= screen_clip.top
                                        && py < screen_clip.bottom
                                        && px >= 0
                                        && px < info.width as i32
                                        && py >= 0
                                        && py < info.height as i32
                                    {
                                        let off =
                                            py as usize * info.stride + px as usize * bytes_per_pixel;
                                        let pixels = framebuffer.pixels_mut();
                                        let dst = framebuffer_pixel_rgb(
                                            info.format,
                                            &pixels[off..off + bytes_per_pixel],
                                        );
                                        let out_rgb = apply_rop2_rgb(pen.rop2, pen_rgb, dst);
                                        let out = pixel_bytes_for_rgb(info.format, out_rgb);
                                        pixels[off..off + bytes_per_pixel]
                                            .copy_from_slice(&out[..bytes_per_pixel]);
                                        framebuffer.mark_dirty(FramebufferRect::new(
                                            px as u32,
                                            py as u32,
                                            1,
                                            1,
                                        ));
                                    }
                                }
                            }
                        }
                    }
                }
                // Top/bottom horizontal arcs
                for sy in [screen_rect.top, screen_rect.bottom - 1] {
                    let dy = (sy as f64 + 0.5) - cy;
                    let ratio = dy / b;
                    if ratio.abs() > 1.0 {
                        continue;
                    }
                    let x_half = a * (1.0 - ratio * ratio).sqrt();
                    let x_start = (cx - x_half).round() as i32;
                    let x_end = (cx + x_half).round() as i32;
                    for sx in x_start..=x_end {
                        for clip in &clips {
                            let screen_clip = clip.offset(client_origin.x, client_origin.y);
                            for dpy in -low..=high {
                                for dpx in -low..=high {
                                    let px = sx + dpx;
                                    let py = sy + dpy;
                                    if px >= screen_clip.left
                                        && px < screen_clip.right
                                        && py >= screen_clip.top
                                        && py < screen_clip.bottom
                                        && px >= 0
                                        && px < info.width as i32
                                        && py >= 0
                                        && py < info.height as i32
                                    {
                                        let off =
                                            py as usize * info.stride + px as usize * bytes_per_pixel;
                                        let pixels = framebuffer.pixels_mut();
                                        pixels[off..off + bytes_per_pixel]
                                            .copy_from_slice(&pixel[..bytes_per_pixel]);
                                        framebuffer.mark_dirty(FramebufferRect::new(
                                            px as u32,
                                            py as u32,
                                            1,
                                            1,
                                        ));
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn round_rect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    if hdc == 0 {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let rect = normalize_rect(Rect {
        left: raw_i32_arg(args, 1),
        top: raw_i32_arg(args, 2),
        right: raw_i32_arg(args, 3),
        bottom: raw_i32_arg(args, 4),
    });
    let ew = raw_i32_arg(args, 5).max(0).min(rect.right - rect.left);
    let eh = raw_i32_arg(args, 6).max(0).min(rect.bottom - rect.top);

    if rect.right <= rect.left || rect.bottom <= rect.top {
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }

    // Degenerate cases: no rounding → Rectangle; full rounding → Ellipse.
    if ew == 0 || eh == 0 {
        let new_args = [
            hdc,
            rect.left as u32,
            rect.top as u32,
            rect.right as u32,
            rect.bottom as u32,
        ];
        return rectangle_raw(kernel, memory, framebuffer, thread_id, &new_args);
    }

    // Corner ellipse half-dimensions.
    let rx = (ew / 2).max(1);
    let ry = (eh / 2).max(1);

    // Build scan-line spans for the RoundRect interior.
    // The rounded rect consists of:
    //   - A central vertical band (full width, middle rows)
    //   - Top/bottom bands with corner cutouts replaced by ellipse arcs
    let inner_top = rect.top + ry;
    let inner_bottom = rect.bottom - ry;
    let inner_left = rect.left + rx;
    let inner_right = rect.right - rx;

    let mut spans: Vec<(i32, i32, i32)> = Vec::new();

    // Middle rows: full width.
    for y in inner_top..inner_bottom {
        spans.push((y, rect.left, rect.right));
    }

    // Top/bottom corner rows with ellipse edges.
    let cx_left = inner_left as f64;
    let cx_right = inner_right as f64;
    let cy_top = inner_top as f64;
    let cy_bottom = inner_bottom as f64;

    for y in rect.top..inner_top {
        let dy = (y as f64 + 0.5) - cy_top;
        let ratio = dy / ry as f64;
        if ratio.abs() > 1.0 {
            continue;
        }
        let x_half = rx as f64 * (1.0 - ratio * ratio).sqrt();
        let x_start = (cx_left - x_half).ceil() as i32;
        let x_end = (cx_right + x_half).ceil() as i32;
        spans.push((y, x_start, x_end));
    }

    for y in inner_bottom..rect.bottom {
        let dy = (y as f64 + 0.5) - cy_bottom;
        let ratio = dy / ry as f64;
        if ratio.abs() > 1.0 {
            continue;
        }
        let x_half = rx as f64 * (1.0 - ratio * ratio).sqrt();
        let x_start = (cx_left - x_half).ceil() as i32;
        let x_end = (cx_right + x_half).ceil() as i32;
        spans.push((y, x_start, x_end));
    }

    if kernel.resources.is_memory_dc(hdc) {
        if let Some(bitmap) = selected_bitmap_object(kernel, hdc) {
            let clips = hdc_clip_rects(kernel, hdc, rect, bitmap.width, bitmap.height);
            if !clips.is_empty() {
                let paint = selected_brush_paint(kernel, hdc);
                let pen = selected_pen_model(kernel, hdc);
                let brush_origin = kernel
                    .resources
                    .dc_state(hdc)
                    .map(|state| state.brush_origin)
                    .unwrap_or(Point { x: 0, y: 0 });
                let pattern = paint.as_ref().and_then(|p| match p {
                    BrushPaint::Pattern(pat) => {
                        bitmap_pattern_bytes(memory, pat).map(|bytes| (pat.clone(), bytes))
                    }
                    _ => None,
                });
                for clip in &clips {
                    let clip = *clip;
                    if let Some(paint) = paint.as_ref() {
                        for &(y, x_start, x_end) in &spans {
                            let x_start = x_start.max(clip.left);
                            let x_end = x_end.min(clip.right);
                            if x_end <= x_start {
                                continue;
                            }
                            for x in x_start..x_end {
                                let rgb = match paint {
                                    BrushPaint::Solid(colorref) => colorref_rgb(*colorref),
                                    BrushPaint::Pattern(_) => {
                                        if let Some((pat, bytes)) = pattern.as_ref() {
                                            pattern_pixel_rgb(pat, bytes, x, y, brush_origin)
                                                .unwrap_or([0, 0, 0])
                                        } else {
                                            continue;
                                        }
                                    }
                                };
                                let _ = write_bitmap_pixel_rgb(memory, &bitmap, x, y, rgb);
                            }
                        }
                    }
                    // Pen outline: draw boundary of each span row.
                    if let Some(pen) = pen {
                        if pen.style != PS_NULL {
                            let rgb = colorref_rgb(pen.colorref);
                            let pw = pen.width.max(1);
                            let low = (pw - 1) / 2;
                            let high = pw / 2;
                            for &(y, x_start, x_end) in &spans {
                                let prev_x_start = spans.iter().find(|&&(py, _, _)| py == y - 1).map(|&(_, xs, _)| xs).unwrap_or(x_start);
                                let prev_x_end = spans.iter().find(|&&(py, _, _)| py == y - 1).map(|&(_, _, xe)| xe).unwrap_or(x_end);
                                let next_x_start = spans.iter().find(|&&(py, _, _)| py == y + 1).map(|&(_, xs, _)| xs).unwrap_or(x_start);
                                let next_x_end = spans.iter().find(|&&(py, _, _)| py == y + 1).map(|&(_, _, xe)| xe).unwrap_or(x_end);
                                // Left and right boundary pixels
                                for &bx in &[x_start, x_end - 1] {
                                    for dy2 in -low..=high {
                                        for dx2 in -low..=high {
                                            let px = bx + dx2;
                                            let py = y + dy2;
                                            if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                                                let dst = bitmap_pixel_rgb_from_memory(memory, &bitmap, px, py).unwrap_or([0, 0, 0]);
                                                let _ = write_bitmap_pixel_rgb(memory, &bitmap, px, py, apply_rop2_rgb(pen.rop2, rgb, dst));
                                            }
                                        }
                                    }
                                }
                                // Top/bottom boundary rows
                                let is_top = y == rect.top || x_start != prev_x_start || x_end != prev_x_end;
                                let is_bottom = y == rect.bottom - 1 || x_start != next_x_start || x_end != next_x_end;
                                if is_top || is_bottom {
                                    for bx in x_start..x_end {
                                        for dy2 in -low..=high {
                                            for dx2 in -low..=high {
                                                let px = bx + dx2;
                                                let py = y + dy2;
                                                if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                                                    let dst = bitmap_pixel_rgb_from_memory(memory, &bitmap, px, py).unwrap_or([0, 0, 0]);
                                                    let _ = write_bitmap_pixel_rgb(memory, &bitmap, px, py, apply_rop2_rgb(pen.rop2, rgb, dst));
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    } else if let Some(framebuffer) = framebuffer.as_deref_mut() {
        let Some((client_origin, clips)) =
            hdc_framebuffer_client_clip_rects(kernel, hdc, rect) else {
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        };
        if let Some(BrushPaint::Solid(colorref)) = selected_brush_paint(kernel, hdc) {
            let rgb = colorref_rgb(colorref);
            let info = framebuffer.info();
            let bytes_per_pixel = info.format.bytes_per_pixel();
            let pixel = pixel_bytes_for_rgb(info.format, rgb);
            for &(y, x_start, x_end) in &spans {
                let screen_y = y + client_origin.y;
                if screen_y < 0 || screen_y >= info.height as i32 {
                    continue;
                }
                for clip in &clips {
                    let screen_clip = clip.offset(client_origin.x, client_origin.y);
                    let x_lo = (x_start + client_origin.x).max(screen_clip.left).max(0) as usize;
                    let x_hi = (x_end + client_origin.x)
                        .min(screen_clip.right)
                        .min(info.width as i32) as usize;
                    if x_hi <= x_lo {
                        continue;
                    }
                    let row_off = screen_y as usize * info.stride;
                    let pixels = framebuffer.pixels_mut();
                    for x in x_lo..x_hi {
                        let off = row_off + x * bytes_per_pixel;
                        pixels[off..off + bytes_per_pixel]
                            .copy_from_slice(&pixel[..bytes_per_pixel]);
                    }
                    framebuffer.mark_dirty(FramebufferRect::new(
                        x_lo as u32,
                        screen_y as u32,
                        (x_hi - x_lo) as u32,
                        1,
                    ));
                }
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn draw_polyline_for_hdc(
    kernel: &CeKernel,
    framebuffer: &mut dyn Framebuffer,
    hdc: u32,
    points: &[Point],
    pen: PenModel,
) {
    let Some((client_origin, clips)) = hdc_framebuffer_client_clip_rects(
        kernel,
        hdc,
        Rect {
            left: i32::MIN / 2,
            top: i32::MIN / 2,
            right: i32::MAX / 2,
            bottom: i32::MAX / 2,
        },
    ) else {
        return;
    };
    let screen_points: Vec<Point> = points
        .iter()
        .map(|point| Point {
            x: point.x + client_origin.x,
            y: point.y + client_origin.y,
        })
        .collect();
    for clip in clips {
        let clip = clip.offset(client_origin.x, client_origin.y);
        let mut style_state = 0usize;
        for segment in screen_points.windows(2) {
            draw_framebuffer_line(
                framebuffer,
                segment[0],
                segment[1],
                clip,
                pen,
                &mut style_state,
            );
        }
    }
}

fn draw_framebuffer_line(
    framebuffer: &mut dyn Framebuffer,
    start: Point,
    end: Point,
    clip: Rect,
    pen: PenModel,
    style_state: &mut usize,
) {
    let info = framebuffer.info();
    let pen_rgb = colorref_rgb(pen.colorref);
    let bytes_per_pixel = info.format.bytes_per_pixel();
    let width = pen.width.max(1);
    let low = (width - 1) / 2;
    let high = width / 2;
    let mut x0 = start.x;
    let mut y0 = start.y;
    let x1 = end.x;
    let y1 = end.y;
    let dx = (x1 - x0).abs();
    let sx = if x0 < x1 { 1 } else { -1 };
    let dy = -(y1 - y0).abs();
    let sy = if y0 < y1 { 1 } else { -1 };
    let mut err = dx + dy;
    let mut dirty: Option<Rect> = None;

    loop {
        if pen_style_draws_pixel(pen.style, *style_state) {
            for py in y0 - low..=y0 + high {
                for px in x0 - low..=x0 + high {
                    if px >= clip.left
                        && px < clip.right
                        && py >= clip.top
                        && py < clip.bottom
                        && px >= 0
                        && py >= 0
                        && px < info.width as i32
                        && py < info.height as i32
                    {
                        let offset = py as usize * info.stride + px as usize * bytes_per_pixel;
                        let dst_rgb = framebuffer_pixel_rgb(
                            info.format,
                            &framebuffer.pixels()[offset..offset + bytes_per_pixel],
                        );
                        let rgb = apply_rop2_rgb(pen.rop2, pen_rgb, dst_rgb);
                        let pixel = pixel_bytes_for_rgb(info.format, rgb);
                        framebuffer.pixels_mut()[offset..offset + bytes_per_pixel]
                            .copy_from_slice(&pixel[..bytes_per_pixel]);
                        let pixel_rect = Rect {
                            left: px,
                            top: py,
                            right: px + 1,
                            bottom: py + 1,
                        };
                        dirty = Some(
                            dirty
                                .map(|rect| union_rect_value(rect, pixel_rect))
                                .unwrap_or(pixel_rect),
                        );
                    }
                }
            }
        }
        *style_state = style_state.wrapping_add(1);
        if x0 == x1 && y0 == y1 {
            break;
        }
        let e2 = 2 * err;
        if e2 >= dy {
            err += dy;
            x0 += sx;
        }
        if e2 <= dx {
            err += dx;
            y0 += sy;
        }
    }

    if let Some(rect) = dirty {
        framebuffer.mark_dirty(FramebufferRect::new(
            rect.left as u32,
            rect.top as u32,
            (rect.right - rect.left) as u32,
            (rect.bottom - rect.top) as u32,
        ));
    }
}

fn draw_bitmap_line<M: CoredllGuestMemory>(
    memory: &mut M,
    bitmap: &crate::ce::resource::BitmapObject,
    start: Point,
    end: Point,
    clip: Rect,
    pen: PenModel,
    style_state: &mut usize,
) {
    let rgb = colorref_rgb(pen.colorref);
    let width = pen.width.max(1);
    let low = (width - 1) / 2;
    let high = width / 2;
    let mut x0 = start.x;
    let mut y0 = start.y;
    let x1 = end.x;
    let y1 = end.y;
    let dx = (x1 - x0).abs();
    let sx = if x0 < x1 { 1 } else { -1 };
    let dy = -(y1 - y0).abs();
    let sy = if y0 < y1 { 1 } else { -1 };
    let mut err = dx + dy;

    loop {
        if pen_style_draws_pixel(pen.style, *style_state) {
            for py in y0 - low..=y0 + high {
                for px in x0 - low..=x0 + high {
                    if px >= clip.left && px < clip.right && py >= clip.top && py < clip.bottom {
                        let dst = bitmap_pixel_rgb_from_memory(memory, bitmap, px, py)
                            .unwrap_or([0, 0, 0]);
                        let _ = write_bitmap_pixel_rgb(
                            memory,
                            bitmap,
                            px,
                            py,
                            apply_rop2_rgb(pen.rop2, rgb, dst),
                        );
                    }
                }
            }
        }
        *style_state = style_state.wrapping_add(1);
        if x0 == x1 && y0 == y1 {
            break;
        }
        let e2 = 2 * err;
        if e2 >= dy {
            err += dy;
            x0 += sx;
        }
        if e2 <= dx {
            err += dx;
            y0 += sy;
        }
    }
}

fn draw_closed_bitmap_polyline<M: CoredllGuestMemory>(
    memory: &mut M,
    bitmap: &crate::ce::resource::BitmapObject,
    points: &[Point],
    clip: Rect,
    pen: PenModel,
) {
    let mut style_state = 0usize;
    for segment in points.windows(2) {
        draw_bitmap_line(
            memory,
            bitmap,
            segment[0],
            segment[1],
            clip,
            pen,
            &mut style_state,
        );
    }
    if let (Some(first), Some(last)) = (points.first().copied(), points.last().copied()) {
        draw_bitmap_line(memory, bitmap, last, first, clip, pen, &mut style_state);
    }
}

fn fill_bitmap_polygon<M: CoredllGuestMemory>(
    memory: &mut M,
    bitmap: &crate::ce::resource::BitmapObject,
    points: &[Point],
    clip: Rect,
    paint: BrushPaint,
    origin: Point,
    fill_mode: i32,
) {
    let pattern = match &paint {
        BrushPaint::Solid(_) => None,
        BrushPaint::Pattern(pattern) => {
            bitmap_pattern_bytes(memory, pattern).map(|bytes| (pattern.clone(), bytes))
        }
    };
    let solid = match &paint {
        BrushPaint::Solid(colorref) => Some(colorref_rgb(*colorref)),
        BrushPaint::Pattern(_) => None,
    };
    if solid.is_none() && pattern.is_none() {
        return;
    }
    for (y, x_start, x_end) in polygon_spans(points, clip, fill_mode) {
        for x in x_start..x_end {
            let rgb = if let Some(rgb) = solid {
                rgb
            } else if let Some((pattern, bytes)) = pattern.as_ref() {
                pattern_pixel_rgb(pattern, bytes, x, y, origin).unwrap_or([0, 0, 0])
            } else {
                continue;
            };
            let _ = write_bitmap_pixel_rgb(memory, bitmap, x, y, rgb);
        }
    }
}

fn fill_framebuffer_polygon_for_hdc(
    kernel: &CeKernel,
    framebuffer: &mut dyn Framebuffer,
    hdc: u32,
    points: &[Point],
    colorref: u32,
    fill_mode: i32,
) {
    let Some((client_origin, clips)) = hdc_framebuffer_client_clip_rects(
        kernel,
        hdc,
        Rect {
            left: i32::MIN / 2,
            top: i32::MIN / 2,
            right: i32::MAX / 2,
            bottom: i32::MAX / 2,
        },
    ) else {
        return;
    };
    let screen_points: Vec<Point> = points
        .iter()
        .map(|point| Point {
            x: point.x + client_origin.x,
            y: point.y + client_origin.y,
        })
        .collect();
    let info = framebuffer.info();
    let pixel = pixel_bytes_for_colorref(info.format, colorref);
    let bytes_per_pixel = info.format.bytes_per_pixel();
    let mut dirty: Option<Rect> = None;
    for clip in clips {
        let clip = clip.offset(client_origin.x, client_origin.y);
        for (y, x_start, x_end) in polygon_spans(&screen_points, clip, fill_mode) {
            if y < 0 || y >= info.height as i32 {
                continue;
            }
            for x in x_start..x_end {
                if x < 0 || x >= info.width as i32 {
                    continue;
                }
                let offset = y as usize * info.stride + x as usize * bytes_per_pixel;
                framebuffer.pixels_mut()[offset..offset + bytes_per_pixel]
                    .copy_from_slice(&pixel[..bytes_per_pixel]);
                let pixel_rect = Rect {
                    left: x,
                    top: y,
                    right: x + 1,
                    bottom: y + 1,
                };
                dirty = Some(
                    dirty
                        .map(|rect| union_rect_value(rect, pixel_rect))
                        .unwrap_or(pixel_rect),
                );
            }
        }
    }
    if let Some(rect) = dirty {
        framebuffer.mark_dirty(FramebufferRect::new(
            rect.left as u32,
            rect.top as u32,
            (rect.right - rect.left) as u32,
            (rect.bottom - rect.top) as u32,
        ));
    }
}

fn polygon_spans(
    points: &[Point],
    clip: Rect,
    fill_mode: i32,
) -> Vec<(i32, i32, i32)> {
    use crate::ce::resource::{POLY_FILL_ALTERNATE, POLY_FILL_WINDING};
    if points.len() < 3 || is_rect_empty_value(clip) {
        return Vec::new();
    }
    let min_y = points
        .iter()
        .map(|point| point.y)
        .min()
        .unwrap_or(clip.top)
        .max(clip.top);
    let max_y = points
        .iter()
        .map(|point| point.y)
        .max()
        .unwrap_or(clip.bottom)
        .min(clip.bottom);
    let mut spans = Vec::new();
    for y in min_y..max_y {
        let scan_y = f64::from(y) + 0.5;
        let mut edges = Vec::new();
        for index in 0..points.len() {
            let a = points[index];
            let b = points[(index + 1) % points.len()];
            if a.y == b.y {
                continue;
            }
            let ay = f64::from(a.y);
            let by = f64::from(b.y);
            if (ay <= scan_y && scan_y < by) || (by <= scan_y && scan_y < ay) {
                let t = (scan_y - ay) / (by - ay);
                let x = f64::from(a.x) + t * f64::from(b.x - a.x);
                let direction = if b.y > a.y { 1i32 } else { -1i32 };
                edges.push((x, direction));
            }
        }
        edges.sort_by(|(a, _), (b, _)| a.total_cmp(b));
        if fill_mode == POLY_FILL_WINDING {
            // Nonzero winding rule: fill between edges where winding transitions through 0.
            let mut index = 0;
            while index < edges.len() {
                let x_left = edges[index].0;
                let mut winding = edges[index].1;
                index += 1;
                while index < edges.len() && winding != 0 {
                    winding += edges[index].1;
                    index += 1;
                }
                if winding != 0 {
                    break;
                }
                let Some((x_right, _)) = edges.get(index.saturating_sub(1)).copied() else {
                    break;
                };
                let x_start = (x_left - 0.5).ceil() as i32;
                let x_end = (x_right - 0.5).ceil() as i32;
                let x_start = x_start.max(clip.left);
                let x_end = x_end.min(clip.right);
                if x_end > x_start {
                    spans.push((y, x_start, x_end));
                }
            }
        } else {
            // ALTERNATE (even-odd) rule: fill between odd/even edge pairs.
            let _ = POLY_FILL_ALTERNATE;
            let mut index = 0;
            while index + 1 < edges.len() {
                let x_left = edges[index].0;
                let x_right = edges[index + 1].0;
                index += 2;
                let x_start = (x_left - 0.5).ceil() as i32;
                let x_end = (x_right - 0.5).ceil() as i32;
                let x_start = x_start.max(clip.left);
                let x_end = x_end.min(clip.right);
                if x_end > x_start {
                    spans.push((y, x_start, x_end));
                }
            }
        }
    }
    spans
}

fn move_to_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let point = Point {
        x: raw_i32_arg(args, 1),
        y: raw_i32_arg(args, 2),
    };
    let out_ptr = raw_arg(args, 3);
    if hdc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(previous) = kernel.resources.move_to(hdc, point) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if out_ptr != 0 && !write_guest_point(kernel, memory, thread_id, out_ptr, previous) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn line_to_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let end = Point {
        x: raw_i32_arg(args, 1),
        y: raw_i32_arg(args, 2),
    };
    if hdc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(start) = kernel.resources.current_pos(hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if let Some(pen) = selected_pen_model(kernel, hdc) {
        let points = [start, end];
        if !draw_polyline_to_bitmap_for_hdc(kernel, memory, hdc, &points, pen)
            && let Some(framebuffer) = framebuffer
        {
            draw_polyline_for_hdc(kernel, framebuffer, hdc, &points, pen);
        }
    }
    let _ = kernel.resources.move_to(hdc, end);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn set_pixel_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    hdc: u32,
    x: i32,
    y: i32,
    color: u32,
) -> u32 {
    if hdc == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0xffff_ffff;
    }
    let rect = crate::ce::gwe::Rect {
        left: x,
        top: y,
        right: x + 1,
        bottom: y + 1,
    };
    let paint = BrushPaint::Solid(color);
    if !fill_bitmap_rect_for_hdc(kernel, memory, hdc, rect, paint)
        && let Some(framebuffer) = framebuffer
    {
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, hdc, rect, color);
    }
    kernel.threads.set_last_error(thread_id, 0);
    color
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TextMetricsModel {
    height: i32,
    ascent: i32,
    descent: i32,
    ave_width: i32,
    max_width: i32,
    weight: i32,
    italic: bool,
    underline: bool,
    strikeout: bool,
    pitch_and_family: u8,
    charset: u8,
    face_name: String,
}

impl TextMetricsModel {
    fn from_font(font: Option<&FontObject>) -> Self {
        let raw_height = font.map(|font| font.height).unwrap_or(0);
        let height = if raw_height == 0 {
            16
        } else {
            raw_height.saturating_abs().max(1)
        };
        let ave_width = font
            .and_then(|font| (font.width > 0).then_some(font.width))
            .unwrap_or_else(|| ((height + 1) / 2).max(1));
        let descent = (height / 4).max(1).min(height);
        let ascent = height.saturating_sub(descent).max(1);
        let face_name = font
            .map(|font| font.face_name.as_str())
            .filter(|name| !name.is_empty())
            .unwrap_or("Tahoma")
            .to_string();

        Self {
            height,
            ascent,
            descent,
            ave_width,
            max_width: ave_width.saturating_mul(2).max(ave_width),
            weight: font.map(|font| font.weight).unwrap_or(400),
            italic: font.map(|font| font.italic).unwrap_or(false),
            underline: font.map(|font| font.underline).unwrap_or(false),
            strikeout: font.map(|font| font.strikeout).unwrap_or(false),
            pitch_and_family: font.map(|font| font.pitch_and_family).unwrap_or(0),
            charset: font.map(|font| font.charset).unwrap_or(1),
            face_name,
        }
    }
}

fn selected_text_metrics(kernel: &CeKernel, hdc: u32) -> Option<TextMetricsModel> {
    let state = kernel.resources.dc_state(hdc)?;
    Some(TextMetricsModel::from_font(
        kernel.resources.font(state.selected_font),
    ))
}

fn read_text_extent_units<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    text_ptr: u32,
    count: i32,
) -> Option<usize> {
    if count < 0 {
        return read_guest_wide_arg(memory, text_ptr).map(|text| text.encode_utf16().count());
    }
    if count == 0 {
        return Some(0);
    }
    if text_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    for index in 0..count as u32 {
        if memory
            .read_u16(text_ptr.wrapping_add(index.saturating_mul(2)))
            .is_err()
        {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return None;
        }
    }
    Some(count as usize)
}

fn write_size<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    size_ptr: u32,
    cx: i32,
    cy: i32,
) -> bool {
    write_guest_i32(kernel, memory, thread_id, size_ptr, cx)
        && write_guest_i32(kernel, memory, thread_id, size_ptr.wrapping_add(4), cy)
}

fn write_textmetric_w<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    out_ptr: u32,
    metrics: &TextMetricsModel,
) -> bool {
    const TEXTMETRICW_SIZE: usize = 60;
    let mut bytes = [0u8; TEXTMETRICW_SIZE];
    let mut write_i32 = |offset: usize, value: i32| {
        bytes[offset..offset + 4].copy_from_slice(&value.to_le_bytes());
    };
    write_i32(0, metrics.height);
    write_i32(4, metrics.ascent);
    write_i32(8, metrics.descent);
    write_i32(12, 0);
    write_i32(16, 0);
    write_i32(20, metrics.ave_width);
    write_i32(24, metrics.max_width);
    write_i32(28, metrics.weight);
    write_i32(32, 0);
    write_i32(36, 96);
    write_i32(40, 96);
    bytes[44..46].copy_from_slice(&(0x20u16).to_le_bytes());
    bytes[46..48].copy_from_slice(&(0xffffu16).to_le_bytes());
    bytes[48..50].copy_from_slice(&('?' as u16).to_le_bytes());
    bytes[50..52].copy_from_slice(&(' ' as u16).to_le_bytes());
    bytes[52] = u8::from(metrics.italic);
    bytes[53] = u8::from(metrics.underline);
    bytes[54] = u8::from(metrics.strikeout);
    bytes[55] = metrics.pitch_and_family;
    bytes[56] = metrics.charset;
    write_guest_bytes(kernel, memory, thread_id, out_ptr, &bytes)
}

fn draw_text_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hdc: u32,
    text_ptr: u32,
    count: i32,
    rect_ptr: u32,
) -> u32 {
    if hdc == 0 || text_ptr == 0 || rect_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if read_guest_rect(kernel, memory, thread_id, rect_ptr).is_none() {
        return 0;
    }
    let text_len = if count < 0 {
        read_guest_wide_arg(memory, text_ptr).map(|text| text.encode_utf16().count())
    } else {
        Some(count as usize)
    };
    let Some(text_len) = text_len else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    text_len.max(1).min(i32::MAX as usize) as u32
}

fn get_text_extent_ex_point_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let text_ptr = raw_arg(args, 1);
    let count = raw_i32_arg(args, 2);
    let max_extent = raw_i32_arg(args, 3);
    let fit_ptr = raw_arg(args, 4);
    let dx_ptr = raw_arg(args, 5);
    let size_ptr = raw_arg(args, 6);
    if size_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(count) = read_text_extent_units(kernel, memory, thread_id, text_ptr, count) else {
        return false;
    };
    let char_width = metrics.ave_width.max(1);
    let total_width = char_width.saturating_mul(count.min(i32::MAX as usize) as i32);
    if fit_ptr != 0 {
        let fit = if max_extent > 0 {
            (max_extent / char_width).clamp(0, count.min(i32::MAX as usize) as i32) as u32
        } else {
            count.min(u32::MAX as usize) as u32
        };
        if !write_guest_u32(kernel, memory, thread_id, fit_ptr, fit) {
            return false;
        }
    }
    if dx_ptr != 0 {
        for index in 0..count.min(i32::MAX as usize) {
            let advance = char_width.saturating_mul(index as i32 + 1);
            if !write_guest_i32(
                kernel,
                memory,
                thread_id,
                dx_ptr.wrapping_add((index as u32).saturating_mul(4)),
                advance,
            ) {
                return false;
            }
        }
    }
    if !write_size(
        kernel,
        memory,
        thread_id,
        size_ptr,
        total_width,
        metrics.height,
    ) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_text_metrics_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    out_ptr: u32,
) -> bool {
    if out_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if !write_textmetric_w(kernel, memory, thread_id, out_ptr, &metrics) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_char_width32_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let first = raw_arg(args, 1);
    let last = raw_arg(args, 2);
    let out_ptr = raw_arg(args, 3);
    if out_ptr == 0 || last < first {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let count = (last - first + 1) as usize;
    for i in 0..count {
        let width = metrics.ave_width as u32;
        if !write_guest_u32(
            kernel,
            memory,
            thread_id,
            out_ptr + i as u32 * 4,
            width,
        ) {
            return false;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

// GetCharABCWidths / GetCharABCWidthsI — fills ABC structs (abcA: i32, abcB: u32, abcC: i32).
// CE has no per-glyph metric data; approximate with average width as abcB, zero for A and C.
fn get_char_abcwidths_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let first = raw_arg(args, 1);
    let last = raw_arg(args, 2);
    let out_ptr = raw_arg(args, 3);
    if out_ptr == 0 || last < first {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let count = (last - first + 1) as usize;
    for i in 0..count {
        let base = out_ptr + i as u32 * 12; // ABC struct = 12 bytes
        if !write_guest_u32(kernel, memory, thread_id, base, 0)          // abcA = 0
            || !write_guest_u32(kernel, memory, thread_id, base + 4, metrics.ave_width as u32) // abcB
            || !write_guest_u32(kernel, memory, thread_id, base + 8, 0)  // abcC = 0
        {
            return false;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_text_face_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    capacity_chars: i32,
    out_ptr: u32,
) -> u32 {
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let face_len = metrics.face_name.encode_utf16().count() as u32;
    if out_ptr != 0 && capacity_chars > 0 {
        if !write_guest_wide_fixed(
            kernel,
            memory,
            thread_id,
            out_ptr,
            &metrics.face_name,
            capacity_chars as usize,
        ) {
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return face_len.min(capacity_chars.saturating_sub(1) as u32);
    }
    kernel.threads.set_last_error(thread_id, 0);
    face_len
}

fn ext_text_out_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let options = raw_arg(args, 3);
    let rect_ptr = raw_arg(args, 4);
    let text_ptr = raw_arg(args, 5);
    let count = raw_arg(args, 6);
    if hdc == 0 || (count != 0 && text_ptr == 0) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let rect = if rect_ptr != 0 {
        let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
            return false;
        };
        Some(rect)
    } else {
        None
    };
    if options & ETO_OPAQUE != 0
        && let Some(rect) = rect
    {
        let color = kernel
            .resources
            .dc_state(hdc)
            .map(|state| state.bk_color)
            .unwrap_or(rgb(0xff, 0xff, 0xff));
        if !fill_bitmap_rect_for_hdc(kernel, memory, hdc, rect, BrushPaint::Solid(color))
            && let Some(framebuffer) = framebuffer
        {
            fill_framebuffer_rect_for_hdc(kernel, framebuffer, hdc, rect, color);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn create_rect_rgn_raw(kernel: &mut CeKernel, left: i32, top: i32, right: i32, bottom: i32) -> u32 {
    kernel.resources.create_region(normalize_rect(Rect {
        left,
        top,
        right,
        bottom,
    }))
}

fn create_rect_rgn_indirect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    rect_ptr: u32,
) -> u32 {
    let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
        return 0;
    };
    kernel.resources.create_region(normalize_rect(rect))
}

fn set_rect_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    region: u32,
    left: i32,
    top: i32,
    right: i32,
    bottom: i32,
) -> bool {
    if !kernel.resources.set_region(
        region,
        normalize_rect(Rect {
            left,
            top,
            right,
            bottom,
        }),
    ) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn combine_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    dest: u32,
    src1: u32,
    src2: u32,
    mode: u32,
) -> u32 {
    if mode == RGN_OR && dest == src1 {
        let Some(rhs_rect) = kernel
            .resources
            .region(src2)
            .and_then(|region| (region.rects.len() == 1).then_some(region.rects[0]))
        else {
            if kernel.resources.region(src1).is_none() || kernel.resources.region(src2).is_none() {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            }
            return combine_rgn_raw_slow(kernel, thread_id, dest, src1, src2, mode);
        };
        if !kernel.resources.union_region_with_rect(dest, rhs_rect) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return kernel
            .resources
            .region(dest)
            .map(region_status_object)
            .unwrap_or(ERROR_REGION);
    }
    combine_rgn_raw_slow(kernel, thread_id, dest, src1, src2, mode)
}

fn combine_rgn_raw_slow(
    kernel: &mut CeKernel,
    thread_id: u32,
    dest: u32,
    src1: u32,
    src2: u32,
    mode: u32,
) -> u32 {
    let Some(lhs) = kernel
        .resources
        .region(src1)
        .map(|region| region.rects.clone())
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let rhs = if mode == RGN_COPY {
        Vec::new()
    } else {
        let Some(rhs) = kernel
            .resources
            .region(src2)
            .map(|region| region.rects.clone())
        else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        rhs
    };
    let combined = match mode {
        RGN_AND => intersect_region_rects(&lhs, &rhs),
        RGN_OR => union_region_rects(&lhs, &rhs),
        RGN_XOR => xor_region_rects(&lhs, &rhs),
        RGN_DIFF => diff_region_rects(&lhs, &rhs),
        RGN_COPY => lhs,
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
            return ERROR_REGION;
        }
    };
    if !kernel.resources.set_region_rects(dest, combined) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(dest)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn get_rgn_box_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    region: u32,
    rect_ptr: u32,
) -> u32 {
    let Some(rect) = kernel.resources.region(region).map(|region| region.rect) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    };
    if rect_ptr != 0 && !write_guest_rect(kernel, memory, thread_id, rect_ptr, rect) {
        return ERROR_REGION;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(region)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn select_clip_rgn_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, region: u32) -> u32 {
    if hdc == 0 || (region != 0 && kernel.resources.region(region).is_none()) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    kernel
        .resources
        .select_clip_region(hdc, (region != 0).then_some(region));
    kernel.threads.set_last_error(thread_id, 0);
    if region == 0 {
        SIMPLEREGION
    } else {
        region_status_object(kernel.resources.region(region).unwrap())
    }
}

fn get_clip_box_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    rect_ptr: u32,
) -> u32 {
    let rect = if let Some(region) = kernel
        .resources
        .clip_region(hdc)
        .and_then(|region| kernel.resources.region(region))
    {
        region.rect
    } else {
        hdc_to_hwnd(hdc)
            .and_then(|hwnd| kernel.gwe.get_client_rect(hwnd))
            .unwrap_or_else(|| Rect::from_origin_size(0, 0, 800, 480))
    };
    if rect_ptr != 0 && !write_guest_rect(kernel, memory, thread_id, rect_ptr, rect) {
        return 0;
    }
    region_status(rect)
}

// GetRegionData(hrgn, dwCount, lpRgnData) — serialise region into RGNDATA buffer.
// RGNDATAHEADER (32 bytes): dwSize(4)+iType(4)+nCount(4)+nRgnSize(4)+rcBound(16)
// followed by nCount RECT structs (each 16 bytes).
fn get_region_data_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hrgn = raw_arg(args, 0);
    let buf_size = raw_arg(args, 1);
    let buf_ptr = raw_arg(args, 2);
    let Some(rgn) = kernel.resources.region(hrgn) else {
        kernel.threads.set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let rects = rgn.rects.clone();
    let bound = rgn.rect;
    let n = rects.len() as u32;
    let rgn_size = n * 16;
    let total = 32 + rgn_size; // RGNDATAHEADER(32) + rects
    if buf_ptr == 0 || buf_size < total {
        kernel.threads.set_last_error(thread_id, 0);
        return total;
    }
    // Write RGNDATAHEADER.
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr, 32);          // dwSize
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 4, 1);       // iType = RDH_RECTANGLES
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 8, n);       // nCount
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 12, rgn_size); // nRgnSize
    // rcBound
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 16, bound.left);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 20, bound.top);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 24, bound.right);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 28, bound.bottom);
    // Write each RECT.
    for (i, r) in rects.iter().enumerate() {
        let base = buf_ptr + 32 + i as u32 * 16;
        let _ = write_guest_i32(kernel, memory, thread_id, base, r.left);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 4, r.top);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 8, r.right);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 12, r.bottom);
    }
    kernel.threads.set_last_error(thread_id, 0);
    total
}

fn pt_in_region_raw(kernel: &CeKernel, region: u32, x: i32, y: i32) -> bool {
    kernel
        .resources
        .region(region)
        .is_some_and(|region| region.rects.iter().any(|rect| point_in_rect(*rect, x, y)))
}

fn rect_in_region_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    region: u32,
    rect_ptr: u32,
) -> bool {
    let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
        return false;
    };
    kernel.resources.region(region).is_some_and(|region| {
        region
            .rects
            .iter()
            .any(|region_rect| rects_intersect(*region_rect, rect))
    })
}

fn set_window_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    region: u32,
    redraw: bool,
) -> u32 {
    let rects = if region == 0 {
        None
    } else {
        let Some(region) = kernel.resources.region(region) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        Some(region.rects.clone())
    };
    if !kernel.gwe.set_window_region_rects(hwnd, rects) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    if redraw && !kernel.gwe.invalidate_window(hwnd, None, true) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    1
}

fn get_window_rgn_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, region: u32) -> u32 {
    if region == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    let Some(rects) = kernel
        .gwe
        .window_region_rects(hwnd)
        .map(|rects| rects.to_vec())
    else {
        if kernel.gwe.is_window(hwnd) {
            kernel.threads.set_last_error(thread_id, 0);
            return NULLREGION;
        }
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return ERROR_REGION;
    };
    if !kernel.resources.set_region_rects(region, rects) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(region)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn paint_hdc_for_hwnd(hwnd: u32) -> u32 {
    0x0200_0000 | (hwnd & 0x00ff_ffff)
}

fn hdc_to_hwnd(hdc: u32) -> Option<u32> {
    (hdc & 0xff00_0000 == 0x0200_0000).then_some(hdc & 0x00ff_ffff)
}

fn is_valid_hdc(kernel: &CeKernel, hdc: u32) -> bool {
    if kernel.resources.is_memory_dc(hdc) {
        return true;
    }
    let Some(hwnd) = hdc_to_hwnd(hdc) else {
        return false;
    };
    hwnd == kernel.gwe.get_desktop_window() || kernel.gwe.is_window(hwnd)
}

fn normalize_rect(rect: Rect) -> Rect {
    Rect {
        left: rect.left.min(rect.right),
        top: rect.top.min(rect.bottom),
        right: rect.left.max(rect.right),
        bottom: rect.top.max(rect.bottom),
    }
}

fn union_rect_value(lhs: Rect, rhs: Rect) -> Rect {
    match (is_rect_empty_value(lhs), is_rect_empty_value(rhs)) {
        (true, true) => Rect::default(),
        (true, false) => rhs,
        (false, true) => lhs,
        (false, false) => Rect {
            left: lhs.left.min(rhs.left),
            top: lhs.top.min(rhs.top),
            right: lhs.right.max(rhs.right),
            bottom: lhs.bottom.max(rhs.bottom),
        },
    }
}

fn intersect_rect_value(lhs: Rect, rhs: Rect) -> Option<Rect> {
    let rect = Rect {
        left: lhs.left.max(rhs.left),
        top: lhs.top.max(rhs.top),
        right: lhs.right.min(rhs.right),
        bottom: lhs.bottom.min(rhs.bottom),
    };
    (!is_rect_empty_value(rect)).then_some(rect)
}

fn intersect_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut rects = Vec::new();
    for lhs_rect in lhs {
        for rhs_rect in rhs {
            if let Some(rect) = intersect_rect_value(*lhs_rect, *rhs_rect) {
                rects.push(rect);
            }
        }
    }
    rects
}

fn union_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    lhs.iter()
        .chain(rhs.iter())
        .copied()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect()
}

fn diff_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut remaining: Vec<Rect> = lhs
        .iter()
        .copied()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect();
    for rhs_rect in rhs {
        let mut next = Vec::new();
        for rect in remaining {
            next.extend(subtract_rect(rect, *rhs_rect));
        }
        remaining = next;
        if remaining.is_empty() {
            break;
        }
    }
    remaining
}

fn xor_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut rects = diff_region_rects(lhs, rhs);
    rects.extend(diff_region_rects(rhs, lhs));
    rects
}

fn subtract_rect(rect: Rect, cut: Rect) -> Vec<Rect> {
    let Some(overlap) = intersect_rect_value(rect, cut) else {
        return vec![rect];
    };
    let candidates = [
        Rect {
            left: rect.left,
            top: rect.top,
            right: rect.right,
            bottom: overlap.top,
        },
        Rect {
            left: rect.left,
            top: overlap.bottom,
            right: rect.right,
            bottom: rect.bottom,
        },
        Rect {
            left: rect.left,
            top: overlap.top,
            right: overlap.left,
            bottom: overlap.bottom,
        },
        Rect {
            left: overlap.right,
            top: overlap.top,
            right: rect.right,
            bottom: overlap.bottom,
        },
    ];
    candidates
        .into_iter()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect()
}

fn region_status(rect: Rect) -> u32 {
    if is_rect_empty_value(rect) {
        NULLREGION
    } else {
        SIMPLEREGION
    }
}

fn region_status_object(region: &RegionObject) -> u32 {
    match region.rects.len() {
        0 => NULLREGION,
        1 => SIMPLEREGION,
        _ => COMPLEXREGION,
    }
}

fn point_in_rect(rect: Rect, x: i32, y: i32) -> bool {
    x >= rect.left && x < rect.right && y >= rect.top && y < rect.bottom
}

fn rects_intersect(lhs: Rect, rhs: Rect) -> bool {
    !is_rect_empty_value(lhs)
        && !is_rect_empty_value(rhs)
        && lhs.left < rhs.right
        && rhs.left < lhs.right
        && lhs.top < rhs.bottom
        && rhs.top < lhs.bottom
}

fn write_paint_struct<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    hdc: u32,
    update: crate::ce::gwe::PaintUpdate,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, addr, hdc)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            u32::from(update.erase),
        )
        && write_guest_rect(kernel, memory, thread_id, addr.wrapping_add(8), update.rect)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(24), 0)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(28), 0)
        && (0..32).all(|offset| {
            write_guest_u8(kernel, memory, thread_id, addr.wrapping_add(32 + offset), 0)
        })
}

fn get_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let msg_ptr = raw_arg(args, 0);
    let hwnd = (raw_arg(args, 1) != 0).then_some(raw_arg(args, 1));
    let min_msg = raw_arg(args, 2);
    let max_msg = raw_arg(args, 3);
    let Some(message) = kernel.get_message_w_filtered(thread_id, hwnd, min_msg, max_msg) else {
        return false;
    };
    if !write_guest_message(kernel, memory, thread_id, msg_ptr, &message) {
        return false;
    }
    message.msg != crate::ce::gwe::WM_QUIT
}

fn peek_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let msg_ptr = raw_arg(args, 0);
    let hwnd = (raw_arg(args, 1) != 0).then_some(raw_arg(args, 1));
    let min_msg = raw_arg(args, 2);
    let max_msg = raw_arg(args, 3);
    let flags = PeekFlags::from_bits_truncate(raw_arg(args, 4));
    let Some(message) = kernel.peek_message_w_filtered(thread_id, hwnd, min_msg, max_msg, flags)
    else {
        return false;
    };
    write_guest_message(kernel, memory, thread_id, msg_ptr, &message)
}

fn dispatch_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    msg_ptr: u32,
) -> u32 {
    let Some(message) = read_guest_message(kernel, memory, thread_id, msg_ptr) else {
        return 0;
    };
    let (class_name, wndproc) = kernel
        .gwe
        .window(message.hwnd)
        .map(|window| (window.class_name.clone(), window.wndproc))
        .unwrap_or_default();
    tracing::debug!(
        target: "ce.gwe",
        thread_id,
        msg_ptr = format_args!("0x{msg_ptr:08x}"),
        hwnd = format_args!("0x{:08x}", message.hwnd),
        msg = format_args!("0x{:08x}", message.msg),
        wparam = format_args!("0x{:08x}", message.wparam),
        lparam = format_args!("0x{:08x}", message.lparam),
        class = class_name.as_str(),
        wndproc = format_args!("0x{wndproc:08x}"),
        "DispatchMessageW"
    );
    let send_id = kernel.gwe.active_sent_message_id(thread_id);
    let result = kernel.dispatch_message_w_for_thread(thread_id, message);
    if let Some(send_id) = send_id {
        write_completed_send_message_timeout_result(kernel, memory, thread_id, send_id);
    }
    result
}

fn destroy_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd: u32,
) -> bool {
    let destroyed = kernel.destroy_window(hwnd);
    if destroyed {
        write_completed_send_message_timeout_results(kernel, memory, thread_id);
    }
    destroyed
}

fn write_completed_send_message_timeout_results<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
) -> bool {
    let writes = kernel.gwe.completed_sent_message_result_writes();
    let mut ok = true;
    for (_, result_ptr, result) in writes {
        ok &= write_guest_u32(kernel, memory, thread_id, result_ptr, result);
    }
    ok
}

fn write_completed_send_message_timeout_result<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    send_id: u64,
) -> bool {
    let Some((result_ptr, result)) = kernel.gwe.sent_message(send_id).and_then(|sent| {
        sent.result_ptr
            .zip(sent.result)
            .filter(|_| sent.flags & crate::ce::gwe::SMF_RESULT_READY != 0)
    }) else {
        return true;
    };
    write_guest_u32(kernel, memory, thread_id, result_ptr, result)
}

fn send_message_timeout_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hwnd = raw_arg(args, 0);
    let msg = raw_arg(args, 1);
    let wparam = raw_arg(args, 2);
    let lparam = raw_arg(args, 3);
    let flags = raw_arg(args, 4);
    let timeout_ms = raw_arg(args, 5);
    let result_ptr = raw_arg(args, 6);
    if flags & !SMTO_SUPPORTED_CE_FLAGS != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_FLAGS_LOCAL);
        return 0;
    }
    let Some(target_thread) = kernel
        .gwe
        .window(hwnd)
        .filter(|window| !window.destroyed)
        .map(|window| window.thread_id)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    if target_thread != thread_id {
        const CE_HUNG_THRESHOLD_MS: u32 = 5000;
        if flags & SMTO_ABORTIFHUNG != 0
            && kernel.gwe.is_thread_hung(
                target_thread,
                kernel.timers.tick_count(),
                CE_HUNG_THRESHOLD_MS,
            )
        {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_TIMEOUT_LOCAL);
            return 0;
        }
        let Some(send_id) = kernel.begin_cross_thread_send_message_w(
            thread_id,
            hwnd,
            msg,
            wparam,
            lparam,
            Some(timeout_ms),
        ) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return 0;
        };
        kernel.gwe.set_sent_message_result_ptr(send_id, result_ptr);
        kernel.gwe.set_sent_message_timeout_flags(send_id, flags);
        if timeout_ms == 0 {
            let expired = kernel.expire_timed_out_send_messages();
            if expired.contains(&send_id) {
                let _ = kernel.take_completed_send_message_result(send_id);
            }
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let Some(result) = kernel.send_message_w(hwnd, msg, wparam, lparam) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    if result_ptr != 0 && !write_guest_u32(kernel, memory, thread_id, result_ptr, result) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    result
}

fn translate_message_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    msg_ptr: u32,
) -> bool {
    let Some(message) = read_guest_message(kernel, memory, thread_id, msg_ptr) else {
        return false;
    };
    if !matches!(
        message.msg,
        crate::ce::gwe::WM_KEYDOWN | crate::ce::gwe::WM_SYSKEYDOWN
    ) || message.hwnd == 0
    {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    // VK_HANGUL (0x15): toggle IME open status, commit any pending composition,
    // and post IMN_SETOPENSTATUS.
    if message.wparam == crate::ce::gwe::VK_HANGUL
        && message.msg == crate::ce::gwe::WM_KEYDOWN
    {
        if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
            // Commit any active composition before toggling.
            if kernel.gwe.hangul_composition_active(himc) {
                if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                    deliver_hangul_ime_actions(kernel, thread_id, hwnd, message.lparam, &actions);
                }
            }
            let currently_open = kernel.gwe.ime_context(himc).is_some_and(|c| c.open);
            kernel.gwe.set_ime_open_status(himc, !currently_open);
            let hwnd = kernel.gwe.ime_context(himc).and_then(|c| c.hwnd).unwrap_or(0);
            if hwnd != 0 {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_NOTIFY,
                    crate::ce::gwe::IMN_SETOPENSTATUS,
                    0,
                );
            }
        }
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }

    // Korean IME composition path: WM_KEYDOWN when the Korean keyboard layout
    // (0x0412) is active and the window's IME context is open.
    if message.msg == crate::ce::gwe::WM_KEYDOWN
        && kernel.gwe.keyboard_layout() == 0x0412
        && kernel.gwe.is_ime_open_for_window(message.hwnd)
    {
        let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
        let vk = message.wparam;

        // VK_BACK (0x08): undo the last Jamo in the composition.
        if vk == 0x08 {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if kernel.gwe.hangul_composition_active(himc) {
                    if let Some((hwnd, actions)) = kernel.gwe.backspace_hangul_ime(himc) {
                        deliver_hangul_ime_actions(
                            kernel,
                            thread_id,
                            hwnd,
                            message.lparam,
                            &actions,
                        );
                    }
                    kernel.threads.set_last_error(thread_id, 0);
                    return true;
                }
            }
            // No active composition — fall through to post WM_CHAR(BS) normally.
        }

        // Commit-and-pass-through keys: Tab, Return, Escape.
        if matches!(vk, 0x09 | 0x0d | 0x1b) {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if kernel.gwe.hangul_composition_active(himc) {
                    if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                        deliver_hangul_ime_actions(
                            kernel,
                            thread_id,
                            hwnd,
                            message.lparam,
                            &actions,
                        );
                    }
                }
            }
            // Fall through: still post WM_CHAR for the key.
        }

        // Try to map the VK to a Hangul Jamo.
        if let Some(jamo) = crate::ce::hangul::vk_to_hangul_jamo(vk, shift) {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if let Some((hwnd, actions)) =
                    kernel.gwe.process_hangul_ime_jamo(himc, jamo)
                {
                    deliver_hangul_ime_actions(kernel, thread_id, hwnd, message.lparam, &actions);
                }
            }
            kernel.threads.set_last_error(thread_id, 0);
            return true; // key consumed by IME
        }

        // Non-Jamo key while IME is open: commit any pending composition, then
        // fall through to normal WM_CHAR translation for non-Hangul characters.
        if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
            if kernel.gwe.hangul_composition_active(himc) {
                if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                    deliver_hangul_ime_actions(
                        kernel,
                        thread_id,
                        hwnd,
                        message.lparam,
                        &actions,
                    );
                }
            }
        }
        // Fall through to normal character translation below.
    }

    // Western European layout dead-key state machine.
    // Active for layouts 0x040C (French), 0x0407 (German), 0x040A/0x0C0A (Spanish).
    let layout = kernel.gwe.keyboard_layout();
    let layout_lang = layout & 0xFFFF;
    let is_western_layout = matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A);

    if is_western_layout && message.msg == crate::ce::gwe::WM_KEYDOWN {
        let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
        let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
        let (ch, is_dead) = translate_vk_for_western_layout(layout, message.wparam, shift, caps);

        if let Some(pending_dead) = kernel.gwe.take_dead_key() {
            if ch != 0 {
                // Attempt to compose dead + base. If current key is a dead key itself,
                // first emit the pending dead char literally, then record the new dead key.
                if is_dead {
                    // Pending dead + new dead key: emit pending dead as literal WM_CHAR,
                    // then store the new dead key.
                    let _ = kernel.post_message_w_for_thread(
                        thread_id,
                        message.hwnd,
                        crate::ce::gwe::WM_CHAR,
                        pending_dead,
                        message.lparam,
                    );
                    kernel.gwe.set_dead_key(ch);
                    let _ = kernel.post_message_w_for_thread(
                        thread_id,
                        message.hwnd,
                        crate::ce::gwe::WM_DEADCHAR,
                        ch,
                        message.lparam,
                    );
                } else if let Some(composed) = compose_dead_key(pending_dead, ch) {
                    // Composed form: emit single WM_CHAR with the combined character.
                    let _ = kernel.post_message_w_for_thread(
                        thread_id,
                        message.hwnd,
                        crate::ce::gwe::WM_CHAR,
                        composed,
                        message.lparam,
                    );
                } else {
                    // No composed form: emit dead char literally, then the base char.
                    let _ = kernel.post_message_w_for_thread(
                        thread_id,
                        message.hwnd,
                        crate::ce::gwe::WM_CHAR,
                        pending_dead,
                        message.lparam,
                    );
                    let _ = kernel.post_message_w_for_thread(
                        thread_id,
                        message.hwnd,
                        crate::ce::gwe::WM_CHAR,
                        ch,
                        message.lparam,
                    );
                }
                kernel.threads.set_last_error(thread_id, 0);
                return true;
            }
            // ch == 0 (non-character key): restore the pending dead key untouched.
            kernel.gwe.set_dead_key(pending_dead);
        } else if is_dead && ch != 0 {
            // No pending dead key, current key is a dead key: store it and post WM_DEADCHAR.
            kernel.gwe.set_dead_key(ch);
            let _ = kernel.post_message_w_for_thread(
                thread_id,
                message.hwnd,
                crate::ce::gwe::WM_DEADCHAR,
                ch,
                message.lparam,
            );
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        } else if ch != 0 {
            // Normal character in a Western layout — emit it and we're done.
            let _ = kernel.post_message_w_for_thread(
                thread_id,
                message.hwnd,
                crate::ce::gwe::WM_CHAR,
                ch,
                message.lparam,
            );
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        }
        // ch == 0 from western table: fall through to standard US translation.
    }

    let char_code = translate_virtual_key_to_char(kernel, message.wparam);
    if char_code == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    let translated_msg = if message.msg == crate::ce::gwe::WM_SYSKEYDOWN {
        crate::ce::gwe::WM_SYSCHAR
    } else {
        crate::ce::gwe::WM_CHAR
    };
    let posted = kernel.post_message_w_for_thread(
        thread_id,
        message.hwnd,
        translated_msg,
        char_code,
        message.lparam,
    );
    kernel.threads.set_last_error(thread_id, 0);
    posted
}

/// Post WM_IME_* messages corresponding to a slice of Hangul IME actions.
fn deliver_hangul_ime_actions(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    key_lparam: u32,
    actions: &[crate::ce::hangul::HangulImeAction],
) {
    use crate::ce::hangul::HangulImeAction;
    for action in actions {
        match *action {
            HangulImeAction::StartComposition => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_STARTCOMPOSITION,
                    0,
                    0,
                );
            }
            HangulImeAction::UpdateComposition(ch) => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_COMPOSITION,
                    u32::from(ch),
                    crate::ce::gwe::GCS_COMPSTR,
                );
            }
            HangulImeAction::CommitChar(ch) => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_CHAR,
                    u32::from(ch),
                    key_lparam,
                );
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_ENDCOMPOSITION,
                    0,
                    0,
                );
            }
            HangulImeAction::EndCompositionOnly => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_ENDCOMPOSITION,
                    0,
                    0,
                );
            }
        }
    }
}

fn keybd_vkey_to_unicode_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let vk = raw_arg(args, 0) & 0xff;
    // arg 1: scan code (unused for translation)
    let key_state_ptr = raw_arg(args, 2); // 256-byte key state array
    let buf_ptr = raw_arg(args, 3);
    let buf_size = raw_arg(args, 4) as usize; // in WCHARs
    let flags_ptr = raw_arg(args, 5);

    if buf_ptr == 0 || buf_size == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0_u32.wrapping_neg();
    }

    // Read key state from the provided pKeyState buffer if available,
    // otherwise fall back to the emulator's current key state.
    let (shift, control, caps) = if key_state_ptr != 0 {
        let shift = read_guest_bytes(kernel, memory, thread_id, key_state_ptr + crate::ce::gwe::VK_SHIFT, 1)
            .and_then(|b| b.into_iter().next())
            .map(|b| b & 0x80 != 0)
            .unwrap_or(false);
        let ctrl = read_guest_bytes(kernel, memory, thread_id, key_state_ptr + crate::ce::gwe::VK_CONTROL, 1)
            .and_then(|b| b.into_iter().next())
            .map(|b| b & 0x80 != 0)
            .unwrap_or(false);
        let caps = read_guest_bytes(kernel, memory, thread_id, key_state_ptr + crate::ce::gwe::VK_CAPITAL, 1)
            .and_then(|b| b.into_iter().next())
            .map(|b| b & 0x01 != 0)
            .unwrap_or(false);
        (shift, ctrl, caps)
    } else {
        (
            kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0,
            kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000_0000 != 0,
            kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0,
        )
    };

    // For Western European layouts, use the layout-specific table so OEM keys
    // produce the correct characters (e.g. VK_OEM_4 → '^' on AZERTY, '[' on US).
    let layout = kernel.gwe.keyboard_layout();
    let layout_lang = layout & 0xFFFF;
    let is_western_layout = matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A);

    let (char_code, is_dead) = if control {
        (translate_control_key(vk), false)
    } else if is_western_layout {
        let (ch, dead) = translate_vk_for_western_layout(layout, vk, shift, caps);
        if ch != 0 {
            (ch, dead)
        } else {
            // Fall back to US table for any VK not covered by the western table.
            (translate_virtual_key_to_char_with_state(vk, shift, caps), false)
        }
    } else {
        (translate_virtual_key_to_char_with_state(vk, shift, caps), false)
    };

    if char_code == 0 {
        // Key produces no character.
        if flags_ptr != 0 {
            let _ = write_guest_u32(kernel, memory, thread_id, flags_ptr, 0);
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }

    // Write the Unicode character (WCHAR) to the output buffer.
    // Dead-key chars are returned as a single WCHAR; callers that need to
    // distinguish can inspect the flags word (non-zero → dead key).
    let wchar = char_code as u16;
    if !write_guest_u16(kernel, memory, thread_id, buf_ptr, wchar) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INSUFFICIENT_BUFFER);
        return 0_u32.wrapping_neg();
    }
    if flags_ptr != 0 {
        // Bit 0 set → dead key character (CE keyboard PDD convention).
        let flags_val: u32 = if is_dead { 1 } else { 0 };
        let _ = write_guest_u32(kernel, memory, thread_id, flags_ptr, flags_val);
    }
    kernel.threads.set_last_error(thread_id, 0);
    1 // one character written
}

fn translate_virtual_key_to_char_with_state(vkey: u32, shift: bool, caps: bool) -> u32 {
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x30..=0x39 => translate_digit_key(vkey, shift),
        0x41..=0x5a => {
            if shift ^ caps {
                vkey
            } else {
                vkey + 0x20
            }
        }
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'),
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0x6c | 0x70..=0x87 => 0,
        0x20 => 0x20,
        0xba => translate_pair_key(b';', b':', shift),
        0xbb => translate_pair_key(b'=', b'+', shift),
        0xbc => translate_pair_key(b',', b'<', shift),
        0xbd => translate_pair_key(b'-', b'_', shift),
        0xbe => translate_pair_key(b'.', b'>', shift),
        0xbf => translate_pair_key(b'/', b'?', shift),
        0xc0 => translate_pair_key(b'`', b'~', shift),
        0xdb => translate_pair_key(b'[', b'{', shift),
        0xdc => translate_pair_key(b'\\', b'|', shift),
        0xdd => translate_pair_key(b']', b'}', shift),
        0xde => translate_pair_key(b'\'', b'"', shift),
        0xe2 => translate_pair_key(b'\\', b'|', shift),
        _ => 0,
    }
}

fn map_virtual_key_w_raw(code: u32, map_type: u32) -> u32 {
    const MAPVK_VK_TO_VSC: u32 = 0;
    const MAPVK_VSC_TO_VK: u32 = 1;
    const MAPVK_VK_TO_CHAR: u32 = 2;
    const MAPVK_VSC_TO_VK_EX: u32 = 3;
    match map_type {
        MAPVK_VK_TO_CHAR => vkey_to_unshifted_char(code),
        MAPVK_VK_TO_VSC => vkey_to_scan_code(code),
        MAPVK_VSC_TO_VK | MAPVK_VSC_TO_VK_EX => scan_code_to_vkey(code, map_type == MAPVK_VSC_TO_VK_EX),
        _ => 0,
    }
}

fn vkey_to_unshifted_char(vkey: u32) -> u32 {
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x20 => 0x20,
        0x30..=0x39 => vkey,                        // digits '0'..'9'
        0x41..=0x5a => vkey | 0x20,                 // lowercase letters 'a'..'z'
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'), // numpad 0-9
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0xba => u32::from(b';'),
        0xbb => u32::from(b'='),
        0xbc => u32::from(b','),
        0xbd => u32::from(b'-'),
        0xbe => u32::from(b'.'),
        0xbf => u32::from(b'/'),
        0xc0 => u32::from(b'`'),
        0xdb => u32::from(b'['),
        0xdc => u32::from(b'\\'),
        0xdd => u32::from(b']'),
        0xde => u32::from(b'\''),
        0xe2 => u32::from(b'\\'),
        _ => 0,
    }
}

fn vkey_to_scan_code(vkey: u32) -> u32 {
    match vkey {
        0x08 => 0x0e, // Backspace
        0x09 => 0x0f, // Tab
        0x0d => 0x1c, // Return
        0x1b => 0x01, // Escape
        0x20 => 0x39, // Space
        0x21 => 0x49, // Page Up (extended)
        0x22 => 0x51, // Page Down (extended)
        0x23 => 0x4f, // End (extended)
        0x24 => 0x47, // Home (extended)
        0x25 => 0x4b, // Left (extended)
        0x26 => 0x48, // Up (extended)
        0x27 => 0x4d, // Right (extended)
        0x28 => 0x50, // Down (extended)
        0x2d => 0x52, // Insert (extended)
        0x2e => 0x53, // Delete (extended)
        0x30 => 0x0b, // '0'
        0x31 => 0x02, // '1'
        0x32 => 0x03, // '2'
        0x33 => 0x04, // '3'
        0x34 => 0x05, // '4'
        0x35 => 0x06, // '5'
        0x36 => 0x07, // '6'
        0x37 => 0x08, // '7'
        0x38 => 0x09, // '8'
        0x39 => 0x0a, // '9'
        0x41 => 0x1e, // A
        0x42 => 0x30, // B
        0x43 => 0x2e, // C
        0x44 => 0x20, // D
        0x45 => 0x12, // E
        0x46 => 0x21, // F
        0x47 => 0x22, // G
        0x48 => 0x23, // H
        0x49 => 0x17, // I
        0x4a => 0x24, // J
        0x4b => 0x25, // K
        0x4c => 0x26, // L
        0x4d => 0x32, // M
        0x4e => 0x31, // N
        0x4f => 0x18, // O
        0x50 => 0x19, // P
        0x51 => 0x10, // Q
        0x52 => 0x13, // R
        0x53 => 0x1f, // S
        0x54 => 0x14, // T
        0x55 => 0x16, // U
        0x56 => 0x2f, // V
        0x57 => 0x11, // W
        0x58 => 0x2d, // X
        0x59 => 0x15, // Y
        0x5a => 0x2c, // Z
        0x60 => 0x52, // Numpad 0
        0x61 => 0x4f, // Numpad 1
        0x62 => 0x50, // Numpad 2
        0x63 => 0x51, // Numpad 3
        0x64 => 0x4b, // Numpad 4
        0x65 => 0x4c, // Numpad 5
        0x66 => 0x4d, // Numpad 6
        0x67 => 0x47, // Numpad 7
        0x68 => 0x48, // Numpad 8
        0x69 => 0x49, // Numpad 9
        0x6a => 0x37, // Numpad *
        0x6b => 0x4e, // Numpad +
        0x6d => 0x4a, // Numpad -
        0x6e => 0x53, // Numpad .
        0x70 => 0x3b, // F1
        0x71 => 0x3c, // F2
        0x72 => 0x3d, // F3
        0x73 => 0x3e, // F4
        0x74 => 0x3f, // F5
        0x75 => 0x40, // F6
        0x76 => 0x41, // F7
        0x77 => 0x42, // F8
        0x78 => 0x43, // F9
        0x79 => 0x44, // F10
        0x7a => 0x57, // F11
        0x7b => 0x58, // F12
        0x90 => 0x45, // NumLock
        0x91 => 0x46, // ScrollLock
        0xa0 => 0x2a, // LShift
        0xa1 => 0x36, // RShift
        0xa2 => 0x1d, // LControl
        0xa3 => 0x1d, // RControl (same scan as LControl without extended)
        0xa4 => 0x38, // LAlt
        0xa5 => 0x38, // RAlt (same scan as LAlt without extended)
        0xba => 0x27, // ;
        0xbb => 0x0d, // =
        0xbc => 0x33, // ,
        0xbd => 0x0c, // -
        0xbe => 0x34, // .
        0xbf => 0x35, // /
        0xc0 => 0x29, // `
        0xdb => 0x1a, // [
        0xdc => 0x2b, // backslash
        0xdd => 0x1b, // ]
        0xde => 0x28, // '
        _ => 0,
    }
}

fn scan_code_to_vkey(scan: u32, extended: bool) -> u32 {
    // Standard PC AT scan code set 1 to VK mapping.
    // Extended prefix (0xe0) distinguishes some keys when extended=true.
    match (scan & 0x7f, extended) {
        (0x01, _) => 0x1b, // Escape
        (0x02, _) => 0x31, // '1'
        (0x03, _) => 0x32, // '2'
        (0x04, _) => 0x33, // '3'
        (0x05, _) => 0x34, // '4'
        (0x06, _) => 0x35, // '5'
        (0x07, _) => 0x36, // '6'
        (0x08, _) => 0x37, // '7'
        (0x09, _) => 0x38, // '8'
        (0x0a, _) => 0x39, // '9'
        (0x0b, _) => 0x30, // '0'
        (0x0c, _) => 0xbd, // -
        (0x0d, _) => 0xbb, // =
        (0x0e, _) => 0x08, // Backspace
        (0x0f, _) => 0x09, // Tab
        (0x10, _) => 0x51, // Q
        (0x11, _) => 0x57, // W
        (0x12, _) => 0x45, // E
        (0x13, _) => 0x52, // R
        (0x14, _) => 0x54, // T
        (0x15, _) => 0x59, // Y
        (0x16, _) => 0x55, // U
        (0x17, _) => 0x49, // I
        (0x18, _) => 0x4f, // O
        (0x19, _) => 0x50, // P
        (0x1a, _) => 0xdb, // [
        (0x1b, _) => 0xdd, // ]
        (0x1c, false) => 0x0d, // Return
        (0x1c, true) => 0x0d,  // Numpad Enter (same VK)
        (0x1d, false) => 0xa2, // LControl
        (0x1d, true) => 0xa3,  // RControl
        (0x1e, _) => 0x41, // A
        (0x1f, _) => 0x53, // S
        (0x20, _) => 0x44, // D
        (0x21, _) => 0x46, // F
        (0x22, _) => 0x47, // G
        (0x23, _) => 0x48, // H
        (0x24, _) => 0x4a, // J
        (0x25, _) => 0x4b, // K
        (0x26, _) => 0x4c, // L
        (0x27, _) => 0xba, // ;
        (0x28, _) => 0xde, // '
        (0x29, _) => 0xc0, // `
        (0x2a, _) => 0xa0, // LShift
        (0x2b, _) => 0xdc, // backslash
        (0x2c, _) => 0x5a, // Z
        (0x2d, _) => 0x58, // X
        (0x2e, _) => 0x43, // C
        (0x2f, _) => 0x56, // V
        (0x30, _) => 0x42, // B
        (0x31, _) => 0x4e, // N
        (0x32, _) => 0x4d, // M
        (0x33, _) => 0xbc, // ,
        (0x34, _) => 0xbe, // .
        (0x35, false) => 0xbf, // /
        (0x35, true) => 0x6f,  // Numpad /
        (0x36, _) => 0xa1, // RShift
        (0x37, _) => 0x6a, // Numpad *
        (0x38, false) => 0xa4, // LAlt
        (0x38, true) => 0xa5,  // RAlt
        (0x39, _) => 0x20, // Space
        (0x3b, _) => 0x70, // F1
        (0x3c, _) => 0x71, // F2
        (0x3d, _) => 0x72, // F3
        (0x3e, _) => 0x73, // F4
        (0x3f, _) => 0x74, // F5
        (0x40, _) => 0x75, // F6
        (0x41, _) => 0x76, // F7
        (0x42, _) => 0x77, // F8
        (0x43, _) => 0x78, // F9
        (0x44, _) => 0x79, // F10
        (0x45, _) => 0x90, // NumLock
        (0x46, _) => 0x91, // ScrollLock
        (0x47, false) => 0x67, // Numpad 7
        (0x47, true) => 0x24,  // Home
        (0x48, false) => 0x68, // Numpad 8
        (0x48, true) => 0x26,  // Up
        (0x49, false) => 0x69, // Numpad 9
        (0x49, true) => 0x21,  // PageUp
        (0x4a, _) => 0x6d, // Numpad -
        (0x4b, false) => 0x64, // Numpad 4
        (0x4b, true) => 0x25,  // Left
        (0x4c, _) => 0x65, // Numpad 5
        (0x4d, false) => 0x66, // Numpad 6
        (0x4d, true) => 0x27,  // Right
        (0x4e, _) => 0x6b, // Numpad +
        (0x4f, false) => 0x61, // Numpad 1
        (0x4f, true) => 0x23,  // End
        (0x50, false) => 0x62, // Numpad 2
        (0x50, true) => 0x28,  // Down
        (0x51, false) => 0x63, // Numpad 3
        (0x51, true) => 0x22,  // PageDown
        (0x52, false) => 0x60, // Numpad 0
        (0x52, true) => 0x2d,  // Insert
        (0x53, false) => 0x6e, // Numpad .
        (0x53, true) => 0x2e,  // Delete
        (0x57, _) => 0x7a, // F11
        (0x58, _) => 0x7b, // F12
        _ => 0,
    }
}

fn translate_virtual_key_to_char(kernel: &CeKernel, vkey: u32) -> u32 {
    let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
    let control = kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000_0000 != 0;
    let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
    if control {
        return translate_control_key(vkey);
    }
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x30..=0x39 => translate_digit_key(vkey, shift),
        0x41..=0x5a => {
            if shift ^ caps {
                vkey
            } else {
                vkey + 0x20
            }
        }
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'),
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0x6c => 0,         // VK_SEPARATOR: produces no character
        0x70..=0x87 => 0, // VK_F1..VK_F24: function keys produce no character
        0x20 => 0x20,
        0xba => translate_pair_key(b';', b':', shift),
        0xbb => translate_pair_key(b'=', b'+', shift),
        0xbc => translate_pair_key(b',', b'<', shift),
        0xbd => translate_pair_key(b'-', b'_', shift),
        0xbe => translate_pair_key(b'.', b'>', shift),
        0xbf => translate_pair_key(b'/', b'?', shift),
        0xc0 => translate_pair_key(b'`', b'~', shift),
        0xdb => translate_pair_key(b'[', b'{', shift),
        0xdc => translate_pair_key(b'\\', b'|', shift),
        0xdd => translate_pair_key(b']', b'}', shift),
        0xde => translate_pair_key(b'\'', b'"', shift),
        // VK_OEM_102 / VK_EXTEND_BSLASH (0xE2): ISO extra key, same `\`/`|` mapping
        // as VK_OEM_5 on both US (il_0409.cpp) and Korean (il_0412.cpp) layouts.
        0xe2 => translate_pair_key(b'\\', b'|', shift),
        _ => 0,
    }
}

fn translate_control_key(vkey: u32) -> u32 {
    match vkey {
        0x41..=0x5a => vkey - 0x40,
        0x61..=0x7a => vkey - 0x60,
        0xdb => 0x1b,
        0xdc => 0x1c,
        0xdd => 0x1d,
        0xde => 0x1e,
        0xbd => 0x1f,
        0xe2 => 0x1c,
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        _ => 0,
    }
}

fn translate_pair_key(base: u8, shifted: u8, shift: bool) -> u32 {
    if shift {
        u32::from(shifted)
    } else {
        u32::from(base)
    }
}

fn translate_digit_key(vkey: u32, shift: bool) -> u32 {
    if !shift {
        return vkey;
    }
    match vkey {
        0x30 => b')' as u32,
        0x31 => b'!' as u32,
        0x32 => b'@' as u32,
        0x33 => b'#' as u32,
        0x34 => b'$' as u32,
        0x35 => b'%' as u32,
        0x36 => b'^' as u32,
        0x37 => b'&' as u32,
        0x38 => b'*' as u32,
        0x39 => b'(' as u32,
        _ => 0,
    }
}

/// Translate a VK code for a Western European keyboard layout.
/// Returns `(char_code, is_dead)`. `char_code == 0` means no character.
/// `is_dead == true` means the char is a dead-key diacritic.
/// Used for layouts 0x040C (French AZERTY), 0x0407 (German QWERTZ),
/// 0x040A / 0x0C0A (Spanish).
fn translate_vk_for_western_layout(
    layout: u32,
    vkey: u32,
    shift: bool,
    caps: bool,
) -> (u32, bool) {
    let lang = layout & 0xFFFF;
    match lang {
        // French AZERTY (040C)
        0x040C => translate_vk_azerty(vkey, shift, caps),
        // German QWERTZ (0407)
        0x0407 => translate_vk_qwertz(vkey, shift, caps),
        // Spanish (040A, 0C0A)
        0x040A | 0x0C0A => translate_vk_spanish(vkey, shift, caps),
        _ => (0, false),
    }
}

fn translate_vk_azerty(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // French AZERTY layout VK→char table (VK codes are physical QWERTY positions).
    // Dead keys: VK_OEM_4 (0xDB) unshifted → dead circumflex '^',
    //            VK_OEM_4 (0xDB) shifted   → dead diaeresis '¨'.
    // Reference: standard Windows AZERTY (kbdfr.dll) layout.
    let letter = |lower: u8, upper: u8| -> (u32, bool) {
        let ch = if shift ^ caps { upper } else { lower };
        (u32::from(ch), false)
    };
    match vkey {
        // Letter row remapping (AZERTY vs QWERTY)
        0x41 => letter(b'q', b'Q'), // A key → q/Q
        0x5a => letter(b'w', b'W'), // Z key → w/W
        0x57 => letter(b'z', b'Z'), // W key → z/Z
        0x51 => letter(b'a', b'A'), // Q key → a/A
        // Remaining letters same physical position as QWERTY
        // Excludes: A=0x41, Q=0x51, W=0x57, Z=0x5A (remapped above),
        //           M=0x4D (at AZERTY ',' position, handled below).
        0x42..=0x4c | 0x4e..=0x50 | 0x52..=0x56 | 0x58..=0x59 => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        0x4d => (if shift { 0x3f } else { 0x2c }, false), // M key → ,/?
        // Digit row: unshifted produce special chars; shifted produce digit
        0x31 => (if shift { 0x31 } else { 0x26 }, false), // 1 / &
        0x32 => (if shift { 0x32 } else { 0x00e9 }, false), // 2 / é
        0x33 => (if shift { 0x33 } else { 0x22 }, false), // 3 / "
        0x34 => (if shift { 0x34 } else { 0x27 }, false), // 4 / '
        0x35 => (if shift { 0x35 } else { 0x28 }, false), // 5 / (
        0x36 => (if shift { 0x36 } else { 0x2d }, false), // 6 / -
        0x37 => (if shift { 0x37 } else { 0x00e8 }, false), // 7 / è
        0x38 => (if shift { 0x38 } else { 0x5f }, false), // 8 / _
        0x39 => (if shift { 0x39 } else { 0x00e7 }, false), // 9 / ç
        0x30 => (if shift { 0x30 } else { 0x00e0 }, false), // 0 / à
        // OEM keys
        0xbd => (if shift { 0x00b0 } else { 0x29 }, false), // ° / )
        0xbb => (if shift { 0x2b } else { 0x3d }, false), // + / =
        0xdb => {
            // VK_OEM_4: dead circumflex (unshifted) / dead diaeresis (shifted)
            if shift {
                (0x00a8, true) // dead diaeresis ¨
            } else {
                (0x5e, true) // dead circumflex ^
            }
        }
        0xdd => (if shift { 0x00a3 } else { 0x24 }, false), // £ / $
        0xba => letter(b'm', b'M'), // VK_OEM_1 (;) → m/M on AZERTY
        0xde => (if shift { 0x25 } else { 0x00f9 }, false), // % / ù
        0xdc => (if shift { 0x00b5 } else { 0x2a }, false), // µ / *
        0xe2 => (if shift { 0x3e } else { 0x3c }, false), // > / <
        0xbc => (if shift { 0x2e } else { 0x3b }, false), // . / ;
        0xbe => (if shift { 0x2f } else { 0x3a }, false), // / / :
        0xbf => (if shift { 0x00a7 } else { 0x21 }, false), // § / !
        0xc0 => (if shift { 0x7e } else { 0x60 }, false), // ~ / `
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

fn translate_vk_qwertz(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // German QWERTZ layout.
    // Dead keys:
    //   VK_OEM_3 (0xC0, backtick position) unshifted → dead circumflex '^'
    //   VK_OEM_PLUS (0xBB, = position)    unshifted → dead acute '´'
    //   VK_OEM_PLUS (0xBB)                shifted   → dead grave '`'
    // Reference: standard Windows QWERTZ (kbdgr.dll) layout.
    let letter = |lower: u8, upper: u8| -> (u32, bool) {
        let ch = if shift ^ caps { upper } else { lower };
        (u32::from(ch), false)
    };
    match vkey {
        // Y↔Z swap
        0x59 => letter(b'z', b'Z'),
        0x5a => letter(b'y', b'Y'),
        // Other letters (A..X) — same as QWERTY (Y=0x59 and Z=0x5A are swapped above)
        0x41..=0x58 => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        // Digit row
        0x31 => (if shift { 0x21 } else { 0x31 }, false), // ! / 1
        0x32 => (if shift { 0x22 } else { 0x32 }, false), // " / 2
        0x33 => (if shift { 0x00a7 } else { 0x33 }, false), // § / 3
        0x34 => (if shift { 0x24 } else { 0x34 }, false), // $ / 4
        0x35 => (if shift { 0x25 } else { 0x35 }, false), // % / 5
        0x36 => (if shift { 0x26 } else { 0x36 }, false), // & / 6
        0x37 => (if shift { 0x2f } else { 0x37 }, false), // / / 7
        0x38 => (if shift { 0x28 } else { 0x38 }, false), // ( / 8
        0x39 => (if shift { 0x29 } else { 0x39 }, false), // ) / 9
        0x30 => (if shift { 0x3d } else { 0x30 }, false), // = / 0
        // OEM keys
        0xbd => (if shift { 0x3f } else { 0x00df }, false), // ß / ?
        0xbb => {
            // VK_OEM_PLUS: dead acute (unshifted) / dead grave (shifted)
            if shift {
                (0x60, true) // dead grave `
            } else {
                (0x00b4, true) // dead acute ´
            }
        }
        0xdb => (if shift { 0x00dc } else { 0x00fc }, false), // ü/Ü
        0xdd => (if shift { 0x2a } else { 0x2b }, false), // * / +
        0xba => (if shift { 0x00d6 } else { 0x00f6 }, false), // ö/Ö
        0xde => (if shift { 0x00c4 } else { 0x00e4 }, false), // ä/Ä
        0xdc => (if shift { 0x27 } else { 0x23 }, false), // ' / #
        0xc0 => (0x5e, true), // dead circumflex ^
        0xe2 => (if shift { 0x3e } else { 0x3c }, false), // > / <
        0xbc => (if shift { 0x3b } else { 0x2c }, false), // ; / ,
        0xbe => (if shift { 0x3a } else { 0x2e }, false), // : / .
        0xbf => (if shift { 0x5f } else { 0x2d }, false), // _ / -
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

fn translate_vk_spanish(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // Spanish (Spain) keyboard layout.
    // Dead keys:
    //   VK_OEM_4 (0xDB) unshifted → dead grave '`'
    //   VK_OEM_4 (0xDB) shifted   → dead circumflex '^'
    //   VK_OEM_PLUS (0xBB, = position) unshifted → dead acute '´'
    // Reference: standard Windows Spanish layout (kbdsp.dll).
    let _ = caps; // Spanish letters follow caps-lock the same as QWERTY
    match vkey {
        // Letters same as US
        0x41..=0x5a => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        // Digit row: shifted produces Spanish special characters
        0x30 => (if shift { 0x3d } else { 0x30 }, false), // = / 0
        0x31 => (if shift { 0x21 } else { 0x31 }, false), // ! / 1
        0x32 => (if shift { 0x22 } else { 0x32 }, false), // " / 2
        0x33 => (if shift { 0x00b7 } else { 0x33 }, false), // · / 3
        0x34 => (if shift { 0x24 } else { 0x34 }, false), // $ / 4
        0x35 => (if shift { 0x25 } else { 0x35 }, false), // % / 5
        0x36 => (if shift { 0x26 } else { 0x36 }, false), // & / 6
        0x37 => (if shift { 0x2f } else { 0x37 }, false), // / / 7
        0x38 => (if shift { 0x28 } else { 0x38 }, false), // ( / 8
        0x39 => (if shift { 0x29 } else { 0x39 }, false), // ) / 9
        // OEM keys
        0xbd => (if shift { 0x3f } else { 0x27 }, false), // ? / '
        0xbb => (0x00b4, true), // dead acute ´ (both shift states)
        0xdb => {
            if shift {
                (0x5e, true) // dead circumflex ^
            } else {
                (0x60, true) // dead grave `
            }
        }
        0xdd => (if shift { 0x2a } else { 0x2b }, false), // * / +
        0xba => (if shift { 0x3a } else { 0x3b }, false), // : / ;
        0xde => (if shift { 0x22 } else { 0x00ba }, false), // " / º
        0xdc => (if shift { 0x00aa } else { 0x00ba }, false),
        0xc0 => (if shift { 0x00d1 } else { 0x00f1 }, false), // Ñ / ñ
        0xe2 => (if shift { 0x3e } else { 0x3c }, false), // > / <
        0xbc => (if shift { 0x3b } else { 0x2c }, false), // ; / ,
        0xbe => (if shift { 0x3a } else { 0x2e }, false), // : / .
        0xbf => (if shift { 0x5f } else { 0x2d }, false), // _ / -
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

/// Look up the composed character for a dead-key + base-character pair.
/// Returns `Some(composed)` if a Unicode precomposed form exists,
/// `None` if there is no composed form (caller should emit dead+base separately).
fn compose_dead_key(dead: u32, base: u32) -> Option<u32> {
    // Standard Unicode precomposed forms for the five common diacritics.
    match dead {
        // Dead circumflex ^ (0x5E)
        0x5e => match base {
            0x61 => Some(0x00e2), // a → â
            0x65 => Some(0x00ea), // e → ê
            0x69 => Some(0x00ee), // i → î
            0x6f => Some(0x00f4), // o → ô
            0x75 => Some(0x00fb), // u → û
            0x41 => Some(0x00c2), // A → Â
            0x45 => Some(0x00ca), // E → Ê
            0x49 => Some(0x00ce), // I → Î
            0x4f => Some(0x00d4), // O → Ô
            0x55 => Some(0x00db), // U → Û
            0x20 => Some(0x005e), // space → literal ^
            _ => None,
        },
        // Dead grave ` (0x60)
        0x60 => match base {
            0x61 => Some(0x00e0), // a → à
            0x65 => Some(0x00e8), // e → è
            0x69 => Some(0x00ec), // i → ì
            0x6f => Some(0x00f2), // o → ò
            0x75 => Some(0x00f9), // u → ù
            0x41 => Some(0x00c0), // A → À
            0x45 => Some(0x00c8), // E → È
            0x49 => Some(0x00cc), // I → Ì
            0x4f => Some(0x00d2), // O → Ò
            0x55 => Some(0x00d9), // U → Ù
            0x20 => Some(0x0060), // space → literal `
            _ => None,
        },
        // Dead acute ´ (U+00B4)
        0x00b4 => match base {
            0x61 => Some(0x00e1), // a → á
            0x65 => Some(0x00e9), // e → é
            0x69 => Some(0x00ed), // i → í
            0x6f => Some(0x00f3), // o → ó
            0x75 => Some(0x00fa), // u → ú
            0x79 => Some(0x00fd), // y → ý
            0x41 => Some(0x00c1), // A → Á
            0x45 => Some(0x00c9), // E → É
            0x49 => Some(0x00cd), // I → Í
            0x4f => Some(0x00d3), // O → Ó
            0x55 => Some(0x00da), // U → Ú
            0x59 => Some(0x00dd), // Y → Ý
            0x20 => Some(0x00b4), // space → literal ´
            _ => None,
        },
        // Dead tilde ~ (0x7E)
        0x7e => match base {
            0x61 => Some(0x00e3), // a → ã
            0x6f => Some(0x00f5), // o → õ
            0x6e => Some(0x00f1), // n → ñ
            0x41 => Some(0x00c3), // A → Ã
            0x4f => Some(0x00d5), // O → Õ
            0x4e => Some(0x00d1), // N → Ñ
            0x20 => Some(0x007e), // space → literal ~
            _ => None,
        },
        // Dead diaeresis ¨ (U+00A8)
        0x00a8 => match base {
            0x61 => Some(0x00e4), // a → ä
            0x65 => Some(0x00eb), // e → ë
            0x69 => Some(0x00ef), // i → ï
            0x6f => Some(0x00f6), // o → ö
            0x75 => Some(0x00fc), // u → ü
            0x79 => Some(0x00ff), // y → ÿ
            0x41 => Some(0x00c4), // A → Ä
            0x45 => Some(0x00cb), // E → Ë
            0x49 => Some(0x00cf), // I → Ï
            0x4f => Some(0x00d6), // O → Ö
            0x55 => Some(0x00dc), // U → Ü
            0x20 => Some(0x00a8), // space → literal ¨
            _ => None,
        },
        _ => None,
    }
}

fn post_keybd_message_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    let virtual_key = raw_arg(args, 1);
    let key_state_flags = raw_arg(args, 2);
    let requested_characters = raw_arg(args, 3);
    let (character_ptr, character_capacity) = if args.len() >= 8 {
        (raw_arg(args, 6), raw_arg(args, 7))
    } else {
        (raw_arg(args, 5), requested_characters)
    };
    let character_count = requested_characters.min(character_capacity) as usize;
    let characters = match read_keyboard_character_buffer(
        kernel,
        memory,
        thread_id,
        character_ptr,
        character_count,
    ) {
        Some(characters) => characters,
        None => return false,
    };
    let key_down = key_state_flags & crate::ce::gwe::KEY_STATE_DOWN_FLAG != 0;
    let lparam = keyboard_message_lparam(
        0,
        key_state_flags & crate::ce::gwe::KEY_STATE_PREV_DOWN_FLAG != 0,
        !key_down,
        false,
    );
    let posted = kernel.post_keybd_message_for_thread(
        thread_id,
        (hwnd != 0).then_some(hwnd),
        virtual_key,
        key_down,
        lparam,
        &characters,
    );
    kernel.threads.set_last_error(
        thread_id,
        if posted {
            0
        } else {
            ERROR_INVALID_WINDOW_HANDLE
        },
    );
    posted
}

fn keybd_event_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) {
    let virtual_key = raw_arg(args, 0) & 0xff;
    let scan_code = raw_arg(args, 1) & 0xff;
    let flags = raw_arg(args, 2);
    let key_up = flags & KEYEVENTF_KEYUP != 0;
    let lparam = keyboard_message_lparam(
        scan_code,
        key_up,
        key_up,
        flags & KEYEVENTF_EXTENDEDKEY != 0,
    );
    let _ =
        kernel.post_keybd_message_for_thread(thread_id, None, virtual_key, !key_up, lparam, &[]);
    kernel.threads.set_last_error(thread_id, 0);
}

fn read_keyboard_character_buffer<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    character_ptr: u32,
    character_count: usize,
) -> Option<Vec<u32>> {
    if character_count == 0 {
        return Some(Vec::new());
    }
    if character_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let mut characters = Vec::with_capacity(character_count);
    for index in 0..character_count {
        let addr = character_ptr.wrapping_add((index as u32) * 4);
        characters.push(read_guest_u32(kernel, memory, thread_id, addr)?);
    }
    Some(characters)
}

fn keyboard_message_lparam(
    scan_code: u32,
    previous_down: bool,
    key_up: bool,
    extended: bool,
) -> u32 {
    let mut lparam = 1 | ((scan_code & 0xff) << 16);
    if extended {
        lparam |= KF_EXTENDED_LPARAM;
    }
    if previous_down {
        lparam |= KF_REPEAT_LPARAM;
    }
    if key_up {
        lparam |= KF_UP_LPARAM;
    }
    lparam
}

const CS_LOCK_COUNT: u32 = 0;
const CS_OWNER_THREAD: u32 = 4;
const CS_HANDLE: u32 = 8;
const CS_NEED_TRAP: u32 = 12;
const CS_CONTENTIONS: u32 = 16;
const CS_SIZE_WORDS: u32 = 5;

fn initialize_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return;
    }
    for offset in [
        CS_LOCK_COUNT,
        CS_OWNER_THREAD,
        CS_HANDLE,
        CS_NEED_TRAP,
        CS_CONTENTIONS,
    ] {
        if !write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(offset), 0) {
            return;
        }
    }
    let handle = kernel
        .handles
        .insert(KernelObject::CriticalSection(CriticalSectionObject {
            guest_ptr: addr,
        }));
    write_guest_u32(
        kernel,
        memory,
        thread_id,
        addr.wrapping_add(CS_HANDLE),
        handle,
    );
}

fn delete_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    if let Some(handle) = read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(CS_HANDLE)) {
        let _ = kernel.close_handle(handle);
    }
    for word in 0..CS_SIZE_WORDS {
        write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(word * 4), 0);
    }
}

fn enter_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    try_only: bool,
) -> bool {
    let owner_addr = addr.wrapping_add(CS_OWNER_THREAD);
    let lock_addr = addr.wrapping_add(CS_LOCK_COUNT);
    let contentions_addr = addr.wrapping_add(CS_CONTENTIONS);
    let Some(owner) = read_guest_u32(kernel, memory, thread_id, owner_addr) else {
        return false;
    };

    if owner == thread_id {
        let Some(lock_count) = read_guest_u32(kernel, memory, thread_id, lock_addr) else {
            return false;
        };
        return write_guest_u32(
            kernel,
            memory,
            thread_id,
            lock_addr,
            lock_count.wrapping_add(1),
        );
    }

    if owner == 0 {
        return write_guest_u32(kernel, memory, thread_id, owner_addr, thread_id)
            && write_guest_u32(kernel, memory, thread_id, lock_addr, 1);
    }

    if !try_only {
        interlocked_update(
            kernel,
            memory,
            thread_id,
            contentions_addr,
            |value| value.wrapping_add(1),
            InterlockedReturn::NewValue,
        );
    }
    false
}

fn leave_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    let owner_addr = addr.wrapping_add(CS_OWNER_THREAD);
    let lock_addr = addr.wrapping_add(CS_LOCK_COUNT);
    let Some(owner) = read_guest_u32(kernel, memory, thread_id, owner_addr) else {
        return;
    };
    if owner != thread_id {
        return;
    }
    let Some(lock_count) = read_guest_u32(kernel, memory, thread_id, lock_addr) else {
        return;
    };
    if lock_count > 1 {
        write_guest_u32(
            kernel,
            memory,
            thread_id,
            lock_addr,
            lock_count.wrapping_sub(1),
        );
    } else {
        write_guest_u32(kernel, memory, thread_id, owner_addr, thread_id | 1);
        interlocked_compare_store(kernel, memory, thread_id, owner_addr, 0, thread_id | 1);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum InterlockedReturn {
    OldValue,
    NewValue,
}

fn interlocked_update<M, F>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    update: F,
    return_mode: InterlockedReturn,
) -> u32
where
    M: CoredllGuestMemory,
    F: FnOnce(u32) -> u32,
{
    let Some(old_value) = read_guest_u32(kernel, memory, thread_id, addr) else {
        return 0;
    };
    let new_value = update(old_value);
    if !write_guest_u32(kernel, memory, thread_id, addr, new_value) {
        return 0;
    }
    match return_mode {
        InterlockedReturn::OldValue => old_value,
        InterlockedReturn::NewValue => new_value,
    }
}

fn interlocked_compare_store<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    exchange: u32,
    comparand: u32,
) -> u32 {
    let Some(old_value) = read_guest_u32(kernel, memory, thread_id, addr) else {
        return 0;
    };
    if old_value == comparand {
        write_guest_u32(kernel, memory, thread_id, addr, exchange);
    }
    old_value
}

pub(crate) fn read_guest_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
    len: u32,
) -> Option<Vec<u8>> {
    let mut bytes = vec![0; len as usize];
    if memory.read_bytes(addr, &mut bytes).is_err() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    Some(bytes)
}

fn read_guest_narrow_preview<M: CoredllGuestMemory>(
    memory: &M,
    ptr: u32,
    max_len: usize,
) -> Option<String> {
    if ptr == 0 {
        return None;
    }
    let mut preview = String::new();
    for offset in 0..max_len {
        let byte = memory.read_u8(ptr.wrapping_add(offset as u32)).ok()?;
        if byte == 0 {
            break;
        }
        match byte {
            b'\r' => preview.push_str("\\r"),
            b'\n' => preview.push_str("\\n"),
            b'\t' => preview.push_str("\\t"),
            0x20..=0x7e => preview.push(byte as char),
            _ => preview.push_str(&format!("\\x{byte:02x}")),
        }
    }
    Some(preview)
}

pub(crate) fn write_guest_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    bytes: &[u8],
) -> bool {
    if memory.write_bytes(addr, bytes).is_err() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    true
}

fn write_optional_count<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u32,
) -> bool {
    addr == 0 || write_guest_u32(kernel, memory, thread_id, addr, value)
}

fn write_optional_u32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u32,
) -> bool {
    write_optional_count(kernel, memory, thread_id, addr, value)
}

fn write_optional_u64<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u64,
) -> bool {
    addr == 0
        || (write_guest_u32(kernel, memory, thread_id, addr, value as u32)
            && write_guest_u32(
                kernel,
                memory,
                thread_id,
                addr.wrapping_add(4),
                (value >> 32) as u32,
            ))
}

fn read_guest_u32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<u32> {
    match memory.read_u32(addr) {
        Ok(value) => Some(value),
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            None
        }
    }
}

